-- Poems batch 91
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('2efa3fd8-2cc2-4cff-a6bd-a053f78b7d83','山居雜詩九十首  其六','曹勛','宋','宋诗','song-poetry','','[]','伏日更酷暑，當午劇炎烈。',48,'全唐诗/poet.song.110000.json','["伏日更酷暑，當午劇炎烈。", "火雲凝不動，勢欲終歲熱。", "天公蘇赤子，雨隨震霆發。", "一掃回清凉，庭筠助騷屑。"]'),
('61cc3333-bd58-476c-9b4c-79e17d24970e','山居雜詩九十首  其七','曹勛','宋','宋诗','song-poetry','','[]','除地台山麓，稍葺五畝宅。',48,'全唐诗/poet.song.110000.json','["除地台山麓，稍葺五畝宅。", "松竹互偃亞，雲山若阡陌。", "子舍念我老，文餘躬幹役。", "欣欣歸來樂，樂豈一朝夕。"]'),
('ea27cc27-9220-4198-be39-17420caa76b2','山居雜詩九十首  其八','曹勛','宋','宋诗','song-poetry','','[]','牆裏種桃杏，新春亦已花。',48,'全唐诗/poet.song.110000.json','["牆裏種桃杏，新春亦已花。", "牆外繞扶疏，綠蔭皆桑麻。", "今年風雨時，日見田稻嘉。", "長缾瀉黄湯，且餉田畯茶。"]'),
('f0ee2ff0-b304-4089-b869-58b6cd497fc6','山居雜詩九十首  其九','曹勛','宋','宋诗','song-poetry','','[]','清曉看田去，乘露衣襟凉。',48,'全唐诗/poet.song.110000.json','["清曉看田去，乘露衣襟凉。", "已有耘夫出，揖我喜非常。", "爲言苗正好，喜顔笑亦長。", "雖有吏在門，視苗端可償。"]'),
('61512ae0-e442-47a7-bb49-60ebf2d86315','山居雜詩九十首  其一○','曹勛','宋','宋诗','song-poetry','','[]','松根有至藥，琥珀與茯苓。',48,'全唐诗/poet.song.110000.json','["松根有至藥，琥珀與茯苓。", "琥珀未易致，茯苓選宜精。", "製與鞠塵細，色如截肪并。", "一一伴朝粥，地黄安可京。"]'),
('2691e4dd-0a13-4c36-8fa7-3e67427bc43e','山居雜詩九十首  其一一','曹勛','宋','宋诗','song-poetry','','[]','松色蔭人居，松力治人病。',48,'全唐诗/poet.song.110000.json','["松色蔭人居，松力治人病。", "丹砂含其滋，復可延性命。", "幽居繞蒼髯，不畏夏日盛。", "風來聽笙竽，便有華胥興。"]'),
('1db9d2ed-cd0a-4aa2-8990-8209524e29fb','山居雜詩九十首  其一二','曹勛','宋','宋诗','song-poetry','','[]','卜居得幽勝，景物無升沉。',48,'全唐诗/poet.song.110000.json','["卜居得幽勝，景物無升沉。", "峯巒環郛郭，松竹排園林。", "時時破寂寥，翛翛頼鳴禽。", "於焉自有得，天籟皆餘音。"]'),
('7b6e0727-815f-4ce6-ab82-9808a4b72cee','山居雜詩九十首  其一三','曹勛','宋','宋诗','song-poetry','','[]','朅去天台居，邑有萬戶酒。',48,'全唐诗/poet.song.110000.json','["朅去天台居，邑有萬戶酒。", "一出嘗十家，已覺醉屢肘。", "留連多好事，方圓煩飣鬬。", "約趁黄昏歸，不知月挂柳。"]'),
('4d102b8c-1e7e-4f7c-b6ff-c8a5cc6889f4','山居雜詩九十首  其一四','曹勛','宋','宋诗','song-poetry','','[]','年來心目昏，稍息文字業。',48,'全唐诗/poet.song.110000.json','["年來心目昏，稍息文字業。", "曉擁台山雲，時讀修禊帖。", "稚子來捋鬚，幼孫每持鑷。", "晚來微雨休，幽徑無不涉。"]'),
('498d69c8-5eec-4003-99f2-c7bad458a5b2','山居雜詩九十首  其一五','曹勛','宋','宋诗','song-poetry','','[]','三伏暑可畏，貧富方共之。',48,'全唐诗/poet.song.110000.json','["三伏暑可畏，貧富方共之。", "雨忽兼飄風，凉與清氣隨。", "一餉滌炎暍，萬里失蒸炊。", "大哉天地德，好生常所施。"]'),
('4c12dd97-727e-448f-a294-479f993c025a','山居雜詩九十首  其一六','曹勛','宋','宋诗','song-poetry','','[]','七月正流火，晚飯凈剎中。',48,'全唐诗/poet.song.110000.json','["七月正流火，晚飯凈剎中。", "稍脫蒸鬰苦，頓覺心境空。", "放意覽翠岫，徐行迎好風。", "得來喜不徹，此賜皆天公。"]'),
('5c897ff8-25df-4cd7-bfae-8a222ae66bff','山居雜詩九十首  其一七','曹勛','宋','宋诗','song-poetry','','[]','棄官了無事，飯餘心境空。',48,'全唐诗/poet.song.110000.json','["棄官了無事，飯餘心境空。", "清琴或數弄，濁酒時一中。", "人生苦不閑，得閑須從容。", "閉門適吾樂，三籟皆同功。"]'),
('9fdc64f5-18ef-4a3d-bce0-89dd632889f7','山居雜詩九十首  其一八','曹勛','宋','宋诗','song-poetry','','[]','今年已斷梅，七月雨益大。',48,'全唐诗/poet.song.110000.json','["今年已斷梅，七月雨益大。", "苗雖不厭雨，灌恐有餘溉。", "禾梗正柔嫩，水滿舞澎湃。", "其間田高低，于焉有畏愛。"]'),
('27322831-32ad-4fbe-9370-5e55e7bc3e41','山居雜詩九十首  其一九','曹勛','宋','宋诗','song-poetry','','[]','北風忽捲熱，山頂雲已馳。',48,'全唐诗/poet.song.110000.json','["北風忽捲熱，山頂雲已馳。", "日影未容歛，雨脚俄驟垂。", "一向得凉吹，四山橫脩眉。", "暄寒本兩陸，莫能測密移。"]'),
('f935c3b4-8441-4fdd-882a-2bddf85db9e2','山居雜詩九十首  其二○','曹勛','宋','宋诗','song-poetry','','[]','今歲立秋早，便覺驅探湯。',48,'全唐诗/poet.song.110000.json','["今歲立秋早，便覺驅探湯。", "雖有正午熱，已覺中夜凉。", "麻豆率房角，早禾亦上場。", "吾心喜可知，紀實藏詩章。"]'),
('af1fc652-85e2-49b0-95d8-e6003c62438d','山居雜詩九十首  其二一','曹勛','宋','宋诗','song-poetry','','[]','晚家台山下，雲水同一鄉。',48,'全唐诗/poet.song.110000.json','["晚家台山下，雲水同一鄉。", "人事講鄰曲，雞黍期相當。", "秋風起木杪，凉氣吹衣裳。", "東家喜見招，社甕開新嘗。"]'),
('ad44e8d4-6f65-4696-a472-8b70a6538b27','山居雜詩九十首  其二二','曹勛','宋','宋诗','song-poetry','','[]','道人談長生，禪子論寂滅。',48,'全唐诗/poet.song.110000.json','["道人談長生，禪子論寂滅。", "二子互出奇，生滅孰判別。", "吾儕守黄卷，生理知猶劣。", "惟當一以貫，無問亦無說。"]'),
('bd2a7e6a-da8f-496a-b9ad-9b81a38aff18','山居雜詩九十首  其二三','曹勛','宋','宋诗','song-poetry','','[]','前巖有蘭若，委徑宜細履。',48,'全唐诗/poet.song.110000.json','["前巖有蘭若，委徑宜細履。", "未能望窣堵，屢復涉清泚。", "路紆疲脚力，僧老識茶味。", "策杖趁栖鴉，斜陽在林際。"]'),
('371797b4-b6c9-4715-b8eb-151512efe8a8','山居雜詩九十首  其二四','曹勛','宋','宋诗','song-poetry','','[]','客惠雙井芽，千里冒寒暍。',48,'全唐诗/poet.song.110000.json','["客惠雙井芽，千里冒寒暍。", "品格自高勝，香味兩奇絕。", "小小猷溪磨，團團掌中月。", "揮肘喜旋之，紛泊看落雪。"]'),
('f23bd2ce-21de-4e7e-97a0-0df503bbeeff','山居雜詩九十首  其二五','曹勛','宋','宋诗','song-poetry','','[]','東岡老道友，招我閲子孫。',48,'全唐诗/poet.song.110000.json','["東岡老道友，招我閲子孫。", "大兒教以孝，小兒撫以溫。", "舉觴意未暢，已復月挂昏。", "興言還吾廬，更待它日論。"]'),
('71bb31ad-5b1f-4191-8218-310e4f7ffa63','山居雜詩九十首  其二六','曹勛','宋','宋诗','song-poetry','','[]','真隠古招提，長林如磔蝟。',48,'全唐诗/poet.song.110000.json','["真隠古招提，長林如磔蝟。", "雖有羣山峰，所欠一支水。", "草木乏秀潤，巖竇燥肌理。", "安能借僧錫，卓處泉湧沸。"]'),
('f0f4532d-10e2-4134-9902-067b6a91cebb','山居雜詩九十首  其二七','曹勛','宋','宋诗','song-poetry','','[]','士不遠千里，訪我村落中。',48,'全唐诗/poet.song.110000.json','["士不遠千里，訪我村落中。", "話舊語益密，論交顔不紅。", "酒炙乏供給，近製相延容。", "白飯與青芻，且餉馿與僮。"]'),
('a4d5a14c-a014-41c9-af4c-2f71e758b5e7','山居雜詩九十首  其二八','曹勛','宋','宋诗','song-poetry','','[]','栽竹勿傍牆，種蕉莫近砌。',48,'全唐诗/poet.song.110000.json','["栽竹勿傍牆，種蕉莫近砌。", "頃之根蔓延，寖乃壞階戺。", "扶疏宛成趣，茂密相映蔽。", "操刀時遣獠，洗削去蓊翳。"]'),
('4bb78300-a9be-4f3f-b40c-4273746fc212','山居雜詩九十首  其二九','曹勛','宋','宋诗','song-poetry','','[]','朝來天無風，秋暘劇炎銳。',48,'全唐诗/poet.song.110000.json','["朝來天無風，秋暘劇炎銳。", "當年屏翳動，松竹發清吹。", "風豈憐我老，飄蕭翔異氣。", "泠然濯煩襟，蘇息殆天意。"]'),
('8bcb416e-e421-4ce6-9e8f-65dd2442eff2','山居雜詩九十首  其三○','曹勛','宋','宋诗','song-poetry','','[]','平生文字飲，真積力已久。',48,'全唐诗/poet.song.110000.json','["平生文字飲，真積力已久。", "溫故忽若醉，卯飲不待酒。", "昏然亟步武，快哉繞衡陋。", "水闊夕陽紅，雨餘羣山秀。"]'),
('0039a01e-093b-4cb4-a787-e29a88a384e0','山居雜詩九十首  其三一','曹勛','宋','宋诗','song-poetry','','[]','閑時謁墳山，小築真隠麓。',48,'全唐诗/poet.song.110000.json','["閑時謁墳山，小築真隠麓。", "怪來少清景，頗似闕脩竹。", "荷鋤斸雲烟，移種扶疏綠。", "亭亭纔數根，一掃羣樸樕。"]'),
('65c588b6-d11b-4fc7-be19-5819ce0567aa','山居雜詩九十首  其三二','曹勛','宋','宋诗','song-poetry','','[]','閩浙風土異，九日未見菊。',48,'全唐诗/poet.song.110000.json','["閩浙風土異，九日未見菊。", "豐枝閟秀色，細蓓凄已綠。", "當樽折野蘂，氣味亦棖觸。", "詎知三徑中，采采不一足。"]'),
('cc672dd5-c95c-4e84-84c2-7981c673bfc7','山居雜詩九十首  其三三','曹勛','宋','宋诗','song-poetry','','[]','人惠九臯禽，應節每對舞。',48,'全唐诗/poet.song.110000.json','["人惠九臯禽，應節每對舞。", "縶彼雲漢心，成我閑靜趣。", "六翮不忍剪，深徑任翔翥。", "一舉遨天風，應到逍遥處。"]'),
('4f5bbc0a-3874-4d25-ba2e-29d604bc750a','山居雜詩九十首  其三四','曹勛','宋','宋诗','song-poetry','','[]','流泉墮石壁，清韻傳幽林。',48,'全唐诗/poet.song.110000.json','["流泉墮石壁，清韻傳幽林。", "詎知水石韻，可契琴筑音。", "支筇聽之久，凉風吹衣襟。", "更待月下來，同我清夜吟。"]'),
('4f9fa116-98c1-42ff-88d9-d286620cb9b8','山居雜詩九十首  其三五','曹勛','宋','宋诗','song-poetry','','[]','畫工作江梅，粉繪良自誇。',48,'全唐诗/poet.song.110000.json','["畫工作江梅，粉繪良自誇。", "吾儕暈澹墨，一枝纔數花。", "風情意自足，橫斜不可加。", "須知自古來，畫家須詩家。"]'),
('a1ba477b-f706-425a-aa04-665c20f1f4f7','山居雜詩九十首  其三六','曹勛','宋','宋诗','song-poetry','','[]','露蜂綴林薄，土蜂翔戶內。',48,'全唐诗/poet.song.110000.json','["露蜂綴林薄，土蜂翔戶內。", "飛繞旬日閒，穿穴皆其類。", "衆聲互起息，鬨然自闤闠。", "螫幼成腫毒，居閑視其未。"]'),
('68231e45-718b-4f8e-9459-b89edbaa0e6d','山居雜詩九十首  其三七','曹勛','宋','宋诗','song-poetry','','[]','憶君遠亦去，泉響塹每度。',48,'全唐诗/poet.song.110000.json','["憶君遠亦去，泉響塹每度。", "一笑成真樂，此樂固難屢。", "村閑桑柘秋，川闊牛羊暮。", "歸顧紫領巾，媿我方學圃。"]'),
('3322c3d1-ac72-473c-a6b8-c859844a31a6','山居雜詩九十首  其三八','曹勛','宋','宋诗','song-poetry','','["\u592a\u6e56"]','英石多斧鑿，司石殊怯脆。',48,'全唐诗/poet.song.110000.json','["英石多斧鑿，司石殊怯脆。", "拳然太湖出，始有巖壑意。", "彈窩數峰綠，欲與仇池對。", "永念靈壁巧，嵌空勞夢寐。"]'),
('41058580-d95b-4bc2-bf88-bcf93f380177','山居雜詩九十首  其三九','曹勛','宋','宋诗','song-poetry','','[]','休官伏畎畝，農事未歷覽。',48,'全唐诗/poet.song.110000.json','["休官伏畎畝，農事未歷覽。", "年豐則知喜，歲歉頗不鑒。", "螟蜮則曰蠖，不實乃名冇。", "生民惰與勤，天災未嘗濫。"]'),
('2b161bbf-43b0-4807-b8b0-8a1f831e3431','山居雜詩九十首  其四○','曹勛','宋','宋诗','song-poetry','','[]','偶讀禪門禮，老賾存清規。',48,'全唐诗/poet.song.110000.json','["偶讀禪門禮，老賾存清規。", "魚鼓鐘磬間，細行兼威儀。", "能居三板頭，可當一住持。", "破衲受用薄，後來有不知。"]'),
('1cddd00c-3f91-4127-b44d-c5f2bc359432','山居雜詩九十首  其四一','曹勛','宋','宋诗','song-poetry','','[]','瑞香本廬阜，瑞昌最爲冠。',48,'全唐诗/poet.song.110000.json','["瑞香本廬阜，瑞昌最爲冠。", "以此得瑞名，昧者强臆斷。", "種法避寒暑，錦籠不足纂。", "欲披紫雲裘，時分建溪椀。"]'),
('2afb564a-8ee0-43f5-ad4f-439e954e61b0','山居雜詩九十首  其四二','曹勛','宋','宋诗','song-poetry','','[]','天地有大德，好生洽民心。',48,'全唐诗/poet.song.110000.json','["天地有大德，好生洽民心。", "炎雲漲毒暑，此風散重陰。", "欲驅冞旬熱，忽作三日霖。", "人物荷造化，喜歸田畝深。"]'),
('9c987d96-a535-4146-ace5-291bbc65071e','山居雜詩九十首  其四三','曹勛','宋','宋诗','song-poetry','','[]','頃職古器事，三代考纖悉。',48,'全唐诗/poet.song.110000.json','["頃職古器事，三代考纖悉。", "閎異必夏商，形模且朴質。", "其間盛款識，鼓文儼周室。", "固知文武隆，牧敦當第一。"]'),
('de3e1230-6c3c-40d1-9ffd-430335616ecc','山居雜詩九十首  其四四','曹勛','宋','宋诗','song-poetry','','[]','蒲桃天下冠，太原與全邠。',48,'全唐诗/poet.song.110000.json','["蒲桃天下冠，太原與全邠。", "邠故近西凉，種植紛士民。", "豈但馬乳堆，殆若荔子春。", "爲膏爲酒醴，香味有此珍。"]'),
('079d720f-1b0d-4292-b8e7-5ebe5c736381','山居雜詩九十首  其四五','曹勛','宋','宋诗','song-poetry','','[]','調羹商相業，粉額漢宮粧。',48,'全唐诗/poet.song.110000.json','["調羹商相業，粉額漢宮粧。", "寄遠與却月，六朝用彌彰。", "犯寒清而潔，騷經何獨忘。", "撫卷懷靈均，靈均亦沉湘。"]'),
('1a162857-9f5b-4fbd-ad89-f4da1fb7159c','山居雜詩九十首  其四六','曹勛','宋','宋诗','song-poetry','','[]','蓋屋不在華，所欲庇風雨。',48,'全唐诗/poet.song.110000.json','["蓋屋不在華，所欲庇風雨。", "種花品無繁，四時看開處。", "指喻多非約，日涉乃成趣。", "吾年能幾日，景物亦漫與。"]'),
('cb47fbac-0864-4a69-9593-1f4a4ffd9a3c','山居雜詩九十首  其四七','曹勛','宋','宋诗','song-poetry','','[]','海棠盛西蜀，豪壓春風塗。',48,'全唐诗/poet.song.110000.json','["海棠盛西蜀，豪壓春風塗。", "三月浣花溪，游人鄙金珠。", "少陵時居瀼，詩史切太虛。", "獨不被品藻，此理端何如。"]'),
('994cfc4e-695b-42dc-aced-f431c2c55061','山居雜詩九十首  其四八','曹勛','宋','宋诗','song-poetry','','[]','道德五千言，屢讀殊隠奧。',48,'全唐诗/poet.song.110000.json','["道德五千言，屢讀殊隠奧。", "頗能分句法，已自到微妙。", "治國與脩身，篇篇言上道。", "講解七十家，識者自知要。"]'),
('42747534-5182-42e4-8b73-9506b802f057','山居雜詩九十首  其四九','曹勛','宋','宋诗','song-poetry','','[]','僧相同剃除，其門則異竇。',48,'全唐诗/poet.song.110000.json','["僧相同剃除，其門則異竇。", "律儀尚講論，枯禪則烏有。", "悟去此大魁，窮說則學究。", "與語判此科，是非免紛糅。"]'),
('ad26d69b-a79b-4ff9-b83f-a05f8878347c','山居雜詩九十首  其五○','曹勛','宋','宋诗','song-poetry','','[]','閑居養僮僕，衣食必鮮美。',48,'全唐诗/poet.song.110000.json','["閑居養僮僕，衣食必鮮美。", "小則愛睡眠，大者趨博戲。", "不然言疾病，莫能承付委。", "長須與赤脚，昔人誠有理。"]'),
('8ec7849a-39e0-4bb9-9c70-dc475f783ccb','山居雜詩九十首  其五一','曹勛','宋','宋诗','song-poetry','','[]','莫怪游春頻，只被老逼身。',48,'全唐诗/poet.song.110000.json','["莫怪游春頻，只被老逼身。", "念此樂天語，誠哉辭甚真。", "遵行我不倦，治具汝勿嗔。", "持炬接迎我，村醉欹冠巾。"]'),
('5f1cd4d9-e5ca-4eff-b5b5-f0876b36edd7','山居雜詩九十首  其五二','曹勛','宋','宋诗','song-poetry','','[]','三春羣卉盛，在花茂與殘。',48,'全唐诗/poet.song.110000.json','["三春羣卉盛，在花茂與殘。", "好花正穠麗，不作十日看。", "蓓嫩便須賞，開時惟可歎。", "繼自喜新綠，吾心常並觀。"]'),
('2502357d-bc92-46b0-a718-7af52c292687','山居雜詩九十首  其五三','曹勛','宋','宋诗','song-poetry','','[]','熅室宿火銷，縕袍良獨暖。',48,'全唐诗/poet.song.110000.json','["熅室宿火銷，縕袍良獨暖。", "病身怯夜永，老懷苦晝短。", "棲鳥驚簷頭，朝日上窗眼。", "未問粥面花，地黄酒須滿。"]'),
('ba4ffd07-3615-402e-b935-18504ad7bcb5','山居雜詩九十首  其五四','曹勛','宋','宋诗','song-poetry','','[]','侵晨盥櫛起，爽氣隨凉飈。',48,'全唐诗/poet.song.110000.json','["侵晨盥櫛起，爽氣隨凉飈。", "曳杖踏露草，不覺路已遥。", "水清出沙嘴，烟白橫山腰。", "致爽列羣岫，不待西山招。"]'),
('c9964e40-c73b-42f3-9649-862cc5c6c5b8','山居雜詩九十首  其五五','曹勛','宋','宋诗','song-poetry','','[]','從昔漫浪心，家居意不適。',48,'全唐诗/poet.song.110000.json','["從昔漫浪心，家居意不適。", "晨朝香火餘，飯了辦游歷。", "或訪僧掇齋，或隠者對奕。", "歸來任侵燈，龍吟噴霜笛。"]'),
('17f95f73-841c-47a7-930d-24e764cdd446','山居雜詩九十首  其五六','曹勛','宋','宋诗','song-poetry','','[]','前村有經社，香火訊屢通。',48,'全唐诗/poet.song.110000.json','["前村有經社，香火訊屢通。", "携朋閑步往，老人顔有童。", "一杯苦澀茗，滿塘蒲稗風。", "笑顧紙上佛，何時供渠儂。"]'),
('d1219fe9-cf61-4e9e-8e08-9c157fab11f0','山居雜詩九十首  其五七','曹勛','宋','宋诗','song-poetry','','[]','平生不能棋，遇棋亦輙喜。',48,'全唐诗/poet.song.110000.json','["平生不能棋，遇棋亦輙喜。", "從來號萬戶，知生不救死。", "多見國手說，得先乃妙理。", "更有末後著，此著知者幾。"]'),
('22185899-806e-4c59-b046-85ec937661fa','山居雜詩九十首  其五八','曹勛','宋','宋诗','song-poetry','','[]','不持月三長，不奉八關戒。',48,'全唐诗/poet.song.110000.json','["不持月三長，不奉八關戒。", "久素則生疾，多肉亦思菜。", "齒决今莫遂，啜汁老所快。", "終當屏去葷，居山得自在。"]'),
('ef2ec3c9-5a63-44ba-a58c-23702c36f792','山居雜詩九十首  其五九','曹勛','宋','宋诗','song-poetry','','[]','江海吹天風，飛舞散千壠。',48,'全唐诗/poet.song.110000.json','["江海吹天風，飛舞散千壠。", "橫斜任所適，光麗世非種。", "險穢已平治，屋背欲洶湧。", "年豐此兆之，有秋高可拱。"]'),
('aac8263f-3089-46e8-9f5b-daa98d7ae438','山居雜詩九十首  其六○','曹勛','宋','宋诗','song-poetry','','[]','旬日扣玉京，所見如夙昔。',48,'全唐诗/poet.song.110000.json','["旬日扣玉京，所見如夙昔。", "紅雲隠碧洞，清溪映白石。", "臨流坐且久，浩氣洞胸臆。", "溪深竟難涉，踟躕撫蒼壁。"]'),
('d38da5a6-6dc9-4cae-a027-2b480917f3bc','山居雜詩九十首  其六一','曹勛','宋','宋诗','song-poetry','','[]','古鐵如鈎戟，歲久鋼斷綻。',48,'全唐诗/poet.song.110000.json','["古鐵如鈎戟，歲久鋼斷綻。", "久爲土氣蝕，皆成豌豆𤂳。", "銖兩每不多，積之可精煉。", "爲劍或爲刀，花賓劣于滇。"]'),
('1051849a-e83c-4f27-92f8-450c78ce9558','山居雜詩九十首  其六二','曹勛','宋','宋诗','song-poetry','','[]','平昔喜鼇舉，未易自摧墮。',48,'全唐诗/poet.song.110000.json','["平昔喜鼇舉，未易自摧墮。", "功名邂逅來，求則成大過。", "壯年不艱苦，老即困寒餓。", "消長理或然，要知非力可。"]'),
('c49a7eb2-73a1-4ff1-b485-ffd18680fa6e','山居雜詩九十首  其六三','曹勛','宋','宋诗','song-poetry','','[]','造化致有生，旋亦致凋瘁。',48,'全唐诗/poet.song.110000.json','["造化致有生，旋亦致凋瘁。", "草木方薿薿，枝葉忽靡靡。", "初發白雨滌，接以赤日熾。", "末爲飈風吹，從是即委翳。"]'),
('beaffd48-5c93-4a49-ab96-f0afc67718ee','山居雜詩九十首  其六四','曹勛','宋','宋诗','song-poetry','','[]','早年困胡虜，驚痛失方寸。',48,'全唐诗/poet.song.110000.json','["早年困胡虜，驚痛失方寸。", "居常雖勉勉，臨事輙悶悶。", "作字每誤墨，裁詩或失韻。", "老來疾益侵，薾然誰可論。"]'),
('3594ce16-821e-4296-b88f-d041c0820e3b','山居雜詩九十首  其六五','曹勛','宋','宋诗','song-poetry','','[]','半夜秋風高，便覺殘暑退。',48,'全唐诗/poet.song.110000.json','["半夜秋風高，便覺殘暑退。", "一凉精神醒，終夕枕簟媿。", "我老念病役，生病爲形贅。", "永懷忘形友，寒暑孰能累。"]'),
('b25a2044-f937-44a9-83bc-a4d4cbdd2a96','山居雜詩九十首  其六六','曹勛','宋','宋诗','song-poetry','','[]','雞冠與鳳仙，早種近階砌。',48,'全唐诗/poet.song.110000.json','["雞冠與鳳仙，早種近階砌。", "夏秋無花時，類能作幽致。", "雞色惟青紫，鳳蘂雜紅翠。", "來年不待種，罅隙自苗裔。"]'),
('ed99d408-b86c-4584-a171-00d883c64c4a','山居雜詩九十首  其六七','曹勛','宋','宋诗','song-poetry','','[]','台山邑萬戶，戶以酒爲天。',48,'全唐诗/poet.song.110000.json','["台山邑萬戶，戶以酒爲天。", "不憚甑生塵，所願酒如泉。", "多疾自麴糵，致夭非天年。", "因思禁酒法，積粟民沛然。"]'),
('e862ee8a-ae1f-4d8d-8180-c6a5bb44f619','山居雜詩九十首  其六八','曹勛','宋','宋诗','song-poetry','','[]','萬花烘天容，粉色騰雲氣。',48,'全唐诗/poet.song.110000.json','["萬花烘天容，粉色騰雲氣。", "花雲覆臺榭，疑若天亦醉。", "杯盤多歡賞，供帳亦明麗。", "游人侵宵歸，風雨恐踵至。"]'),
('c074afaf-6ea8-4935-8ddc-7b24d092eb26','山居雜詩九十首  其六九','曹勛','宋','宋诗','song-poetry','','[]','赤城玉京天，冠簡奉香火。',48,'全唐诗/poet.song.110000.json','["赤城玉京天，冠簡奉香火。", "一旦僧有之，道容易佛坐。", "忽爲道復得，瞿曇加巾裹。", "屢改神不聞，二家自人我。"]'),
('22b721a3-680a-4b90-8cda-d2aa71d37e3d','山居雜詩九十首  其七○','曹勛','宋','宋诗','song-poetry','','[]','先生義皇上，與物同逶迤。',48,'全唐诗/poet.song.110000.json','["先生義皇上，與物同逶迤。", "道伴雜然至，閑情示之希。", "蒲團茶味足，明窗情話遲。", "一室多入靜，相見亦何時。"]'),
('8ff43d41-6e43-4c46-b95e-8072c4a992eb','山居雜詩九十首  其七一','曹勛','宋','宋诗','song-poetry','','[]','蒔松須殘臘，栽花宜早春。',48,'全唐诗/poet.song.110000.json','["蒔松須殘臘，栽花宜早春。", "移竹日隨月，種麻月及辰。", "旺方八卦定，農詩七月陳。", "物性無不然，農業宜斤斤。"]'),
('40ac69b8-5bac-49b6-bd7a-6c12f170eb09','山居雜詩九十首  其七二','曹勛','宋','宋诗','song-poetry','','[]','山間氣候晚，初冬菊英回。',48,'全唐诗/poet.song.110000.json','["山間氣候晚，初冬菊英回。", "定俟開爐集，始送泛菊杯。", "漸列衆色異，不殊東籬栽。", "冷雨與寒烟，深惜易塵埃。"]'),
('05021490-fec8-4793-98a1-60869005dcb8','山居雜詩九十首  其七三','曹勛','宋','宋诗','song-poetry','','[]','台山穴三獸，樵者不得薪。',48,'全唐诗/poet.song.110000.json','["台山穴三獸，樵者不得薪。", "忽是食人虎，便有射虎人。", "善惡必對待，禍福常相鄰。", "冞月寢三皮，居山聊一欣。"]'),
('2b189ee1-ab05-4985-9102-bcaef526d1ae','山居雜詩九十首  其七四','曹勛','宋','宋诗','song-poetry','','[]','春雨要如膏，發生物已拆。',48,'全唐诗/poet.song.110000.json','["春雨要如膏，發生物已拆。", "霢霂則易耨，浸漬乃損麥。", "連旬不見日，過社麻亦阨。", "再拜祈開晴，民食庶可得。"]'),
('26074ee3-ba1a-4ba6-ae20-9e57299f22a5','山居雜詩九十首  其七五','曹勛','宋','宋诗','song-poetry','','[]','蓬蓽久不居，乍歸欣故情。',48,'全唐诗/poet.song.110000.json','["蓬蓽久不居，乍歸欣故情。", "落葉聚蛛網，殘莎閙蛩聲。", "迹與朝市遠，夢隨風月清。", "從此眠食間，蕭散安餘生。"]'),
('5a869df9-f770-4425-9640-228b4d326bdd','山居雜詩九十首  其七六','曹勛','宋','宋诗','song-poetry','','[]','八月河漢近，凉蟾輝太清。',48,'全唐诗/poet.song.110000.json','["八月河漢近，凉蟾輝太清。", "窗戶紗已薄，草木風有聲。", "所喜暑云退，不憚歲徂征。", "招客對晚色，酒與月同傾。"]'),
('7c11681d-7450-49ae-82c3-727f437aca54','山居雜詩九十首  其七七','曹勛','宋','宋诗','song-poetry','','[]','村落闢幽居，深靜頗得趣。',48,'全唐诗/poet.song.110000.json','["村落闢幽居，深靜頗得趣。", "白雲棲簷棟，嵐光照窗戶。", "往還得隠逸，談笑皆舊故。", "不畏歸路遥，家家響機杼。"]'),
('b9aa1a17-41e0-460e-b3af-3ae30a95797d','山居雜詩九十首  其七八','曹勛','宋','宋诗','song-poetry','','[]','手種亭下松，偃蓋出雲外。',48,'全唐诗/poet.song.110000.json','["手種亭下松，偃蓋出雲外。", "攀條喜脩幹，爲我發清吹。", "曉庭風瑟縮，夜月金鎖碎。", "種久方來歸，對之顔有愧。"]'),
('8a4ad1d0-0bf3-4008-bfa7-bc44da35e9d0','山居雜詩九十首  其七九','曹勛','宋','宋诗','song-poetry','','[]','寓居溪陰剎，未暇理歸棹。',48,'全唐诗/poet.song.110000.json','["寓居溪陰剎，未暇理歸棹。", "遮眼闕文史，借書得探討。", "卷舒白虎通，涵泳青龍鈔。", "賢哉絕世書，欣然慰幽抱。"]'),
('3955ad92-1cf5-47da-a64d-7f040e59e44d','山居雜詩九十首  其八○','曹勛','宋','宋诗','song-poetry','','[]','吾年已七十，眠早起不宴。',48,'全唐诗/poet.song.110000.json','["吾年已七十，眠早起不宴。", "倦甚就宵枕，卧久思永旦。", "雖無文字勞，漸絕人事歎。", "收其放心爾，戒得尤所贊。"]'),
('74bf017d-1d11-4637-aa13-8463f2f125fd','山居雜詩九十首  其八一','曹勛','宋','宋诗','song-poetry','','[]','得閑一何樂，佳處先徜徉。',48,'全唐诗/poet.song.110000.json','["得閑一何樂，佳處先徜徉。", "每扣隠逸士，屢過清靜坊。", "地僻干戈遠，年豐禾稻香。", "訪我亦何所，南澗與東岡。"]'),
('e134d299-8466-4010-a4e1-709663fca56c','山居雜詩九十首  其八二','曹勛','宋','宋诗','song-poetry','','[]','架屋集匠氏，斲石最可恤。',48,'全唐诗/poet.song.110000.json','["架屋集匠氏，斲石最可恤。", "相石千仞端，壍山方得出。", "疲形困輦置，巧磓較絲忽。", "所直等衆人，人可不擇術。"]'),
('60e0122a-23cf-4899-bff1-ecaef52323f8','山居雜詩九十首  其八三','曹勛','宋','宋诗','song-poetry','','[]','陳梨甘若飴，雪梨脆而水。',48,'全唐诗/poet.song.110000.json','["陳梨甘若飴，雪梨脆而水。", "二物浙左右，大顆擅甘脆。", "秋熱兼宿酒，啗之手不置。", "雖非鳳濁鵝，惠予亦多矣。"]'),
('77335384-f18b-4302-9e83-3bde72af74a9','山居雜詩九十首  其八四','曹勛','宋','宋诗','song-poetry','','[]','台蕈甘擅名，油葱芼枯腊。',48,'全唐诗/poet.song.110000.json','["台蕈甘擅名，油葱芼枯腊。", "及居台山下，生致出巖隙。", "丁頭形磷磷，雞股香羃羃。", "清對雲水客，葷素得共食。"]'),
('edc69510-9841-4e09-880e-fb598972724c','山居雜詩九十首  其八五','曹勛','宋','宋诗','song-poetry','','[]','休退居遠邑，頓喜人事疏。',48,'全唐诗/poet.song.110000.json','["休退居遠邑，頓喜人事疏。", "飯籮自不足，日記無可書。", "惟對楮先生，復接松大夫。", "溪友留白魚，鼾睡驚長須。"]'),
('6a47be5f-ca5c-4dfe-971a-3e03699885ec','山居雜詩九十首  其八六','曹勛','宋','宋诗','song-poetry','','[]','晨粥山中行，落葉響步武。',48,'全唐诗/poet.song.110000.json','["晨粥山中行，落葉響步武。", "委曲訪隠逸，清談銷百慮。", "老湯瀹苦茗，宿火煨山芋。", "却照夕陽歸，家人不知處。"]'),
('1c8e0be9-a76a-4b0f-8331-14edcd9258ed','山居雜詩九十首  其八七','曹勛','宋','宋诗','song-poetry','','[]','初意得閑適，處處期登臨。',48,'全唐诗/poet.song.110000.json','["初意得閑適，處處期登臨。", "豈謂病見拘，未能攄靈衿。", "小滯廣莫願，恐辜雲水心。", "强半人事爾，無令成侵尋。"]'),
('2175e6b3-f653-4a26-b164-aa3efc29b17a','山居雜詩九十首  其八八','曹勛','宋','宋诗','song-poetry','','[]','臨老看草聖，作字意少快。',48,'全唐诗/poet.song.110000.json','["臨老看草聖，作字意少快。", "居然落筆際，點畫反留礙。", "早意亦易事，懷抱殊不介。", "茲來每把玩，徒復一歎慨。"]'),
('fbcb5f8e-ac09-45e6-a977-278fd4d39312','山居雜詩九十首  其八九','曹勛','宋','宋诗','song-poetry','','[]','歲華念將晚，寒色慘中抱。',48,'全唐诗/poet.song.110000.json','["歲華念將晚，寒色慘中抱。", "昔年困虀鹽，撥灰吟苦調。", "老來適其適，所樂在燕笑。", "招賓共一醉，圍爐不妨小。"]'),
('4a02f3e7-2fef-4867-b319-3a06d5ed1cc1','山居雜詩九十首  其九○','曹勛','宋','宋诗','song-poetry','','[]','北風號枯桑，濃寒堅夜凍。',48,'全唐诗/poet.song.110000.json','["北風號枯桑，濃寒堅夜凍。", "關河鳥過少，雪意曉來重。", "陌上未霑塵，山中已成壠。", "雝雝南去雁，袖手徒目送。"]'),
('0ab54aad-8206-4e27-b930-f76595b521ad','山居雜詩九十首  其一','曹勛','宋','宋诗','song-poetry','','[]','我生不僥福，始終躬純臣。',48,'全唐诗/poet.song.110000.json','["我生不僥福，始終躬純臣。", "雖更齊楚僞，常障西風塵。", "耳順早引年，掛冠踰八春。", "甘與田畯游，遂予胸次真。"]'),
('da741f91-de3a-4f0d-9610-cdcec10ad089','山居雜詩九十首  其二','曹勛','宋','宋诗','song-poetry','','[]','農人作田務，耘者最辛苦。',48,'全唐诗/poet.song.110000.json','["農人作田務，耘者最辛苦。", "肘膝伏泥塗，拔莠連茹取。", "所拔隨已多，悉釀所伏處。", "惟冀禾稻肥，豈問正炎暑。"]'),
('ae6aa1cf-f94d-42cb-8d60-c5d852f5260d','山居雜詩九十首  其三','曹勛','宋','宋诗','song-poetry','','[]','地水與火風，四大各一性。',48,'全唐诗/poet.song.110000.json','["地水與火風，四大各一性。", "和合乃養形，損增則成病。", "圓覺著于品，岐伯峻其證。", "君子知其言，窮理宜至命。"]'),
('0afe1a2c-d915-45dd-b2c8-f8c80a2c8e24','山居雜詩九十首  其四','曹勛','宋','宋诗','song-poetry','','[]','山中四序景，巧供晨夕間。',48,'全唐诗/poet.song.110000.json','["山中四序景，巧供晨夕間。", "茶甌不少輟，詩魔常畏閑。", "生計付風雨，年華寄毛顔。", "支筇正獨立，栖禽相與還。"]'),
('20a32ee2-08a5-4569-81e2-be4e3dd675a8','山居雜詩九十首  其五','曹勛','宋','宋诗','song-poetry','','[]','歸爲田舍翁，不作無復理。',48,'全唐诗/poet.song.110000.json','["歸爲田舍翁，不作無復理。", "耕鑿頃畝地，遠近先視水。", "溝塍欲利達，農具無委靡。", "高田下田事，得馬失馬爾。"]'),
('3daa6960-e9dd-4c19-b2b8-2f5f9520a0b0','山居雜詩九十首  其六','曹勛','宋','宋诗','song-poetry','','[]','小圃藝花竹，春末已繁秀。',48,'全唐诗/poet.song.110000.json','["小圃藝花竹，春末已繁秀。", "土脈得鋤斸，枝葉易秀茂。", "久以告老病，未免閉圭竇。", "相忘無芥蒂，一二約親舊。"]'),
('27d2f8fb-bb0a-4568-8ef7-31a3ebbf3078','山居雜詩九十首  其七','曹勛','宋','宋诗','song-poetry','','[]','古斗喜妙供，溪蓀種勻抽。',48,'全唐诗/poet.song.110000.json','["古斗喜妙供，溪蓀種勻抽。", "蘸水浮翠蝟，絡石駢栗皺。", "薿薿巧凝綠，梢梢眇含秋。", "相對几案間，蕭然無與儔。"]'),
('d38b500f-e147-455e-936b-abc29fa0903d','山居雜詩九十首  其八','曹勛','宋','宋诗','song-poetry','','[]','閑裏心情拙，還知興自嘉。',48,'全唐诗/poet.song.110000.json','["閑裏心情拙，還知興自嘉。", "饑鴉時立檻，野蝶自尋花。", "客至聊從容，僧來不厭茶。", "晚烟時竚立，列岫映餘霞。"]'),
('96e1808b-25e6-43a3-9d4e-89bf8f317696','山居雜詩九十首  其九','曹勛','宋','宋诗','song-poetry','','[]','人生行樂爾，行樂則心閑。',48,'全唐诗/poet.song.110000.json','["人生行樂爾，行樂則心閑。", "心既無所用，和氣滋容顔。", "衛生有此妙，餘事皆可刪。", "若益兼忘理，敢告知識間。"]'),
('5da26cb7-76b4-4a4a-bf9a-b9bb0965c656','山居雜詩九十首  其一○','曹勛','宋','宋诗','song-poetry','','[]','招客圖客歡，不圖能病客。',48,'全唐诗/poet.song.110000.json','["招客圖客歡，不圖能病客。", "既醉失匕筯，吐茵墮巾幘。", "何堪款曲意，貽念風月夕。", "拂旦往問訊，慙恨見顔色。"]'),
('fa781303-5ab8-4051-9250-00a41a6a836a','山居雜詩九十首  其一一','曹勛','宋','宋诗','song-poetry','','[]','春雪翳重霄，寒雨連日夜。',48,'全唐诗/poet.song.110000.json','["春雪翳重霄，寒雨連日夜。", "不輟獸炭熾，甚恐庭花謝。", "疏簾莫禦冷，爐焚屢成灺。", "寒食數日間，春事求諸野。"]'),
('0b787c1f-5270-4649-8b89-c280eaf51958','山居雜詩九十首  其一二','曹勛','宋','宋诗','song-poetry','','[]','吾年踰七十，真欲願春遲。',48,'全唐诗/poet.song.110000.json','["吾年踰七十，真欲願春遲。", "豈謂上元過，適丁多雨時。", "韶華荏苒半，清明旦夕期。", "流鶑與蜂蝶，冷落殊未知。"]'),
('1e9d8017-ba90-40af-ae9a-da4f289bc675','山居雜詩九十首  其一三','曹勛','宋','宋诗','song-poetry','','[]','客寄輦轂下，馳心田畝間。',48,'全唐诗/poet.song.110000.json','["客寄輦轂下，馳心田畝間。", "君恩重山嶽，臣節殊安閑。", "雖幸米鹽足，其如塵土顔。", "終負告歸罪，判然誠獨難。"]'),
('45bb6bbf-00ff-4fbb-a7ed-374939419283','山居雜詩九十首  其一四','曹勛','宋','宋诗','song-poetry','','[]','老去情懷懶，翛然只此翁。',48,'全唐诗/poet.song.110000.json','["老去情懷懶，翛然只此翁。", "閑窗千里月，修竹一簾風。", "事與孤鴻遠，心將止水同。", "故人如問訊，癡坐正觀空。"]'),
('6d9dbc5e-f4af-4396-8d02-eae42696a020','山居雜詩九十首  其一五','曹勛','宋','宋诗','song-poetry','','[]','寂歷秋風晚，閑庭落葉深。',48,'全唐诗/poet.song.110000.json','["寂歷秋風晚，閑庭落葉深。", "天高晴日澹，山浄暮烟沉。", "疾病無時已，年華有底侵。", "兩行南去雁，一片北歸心。"]'),
('972d39d4-b3f9-4643-a55a-f2940c1aaee5','山居雜詩九十首  其一六','曹勛','宋','宋诗','song-poetry','','[]','北歸了無日，先壟掃何時。',48,'全唐诗/poet.song.110000.json','["北歸了無日，先壟掃何時。", "愁與燕鴻遠，心同楚客悲。", "寒蟬咽敗柳，幽鷺來清池。", "誰與話舊事，淚蘚空在衣。"]'),
('328ec76f-0ded-446b-b54e-cd87b2ac858c','山居雜詩九十首  其一七','曹勛','宋','宋诗','song-poetry','','[]','連日山村雨，牛羊都在欄。',48,'全唐诗/poet.song.110000.json','["連日山村雨，牛羊都在欄。", "低田漬積水，卧穗鋪新寒。", "氣逼琴絲潤，香傳巖桂丹。", "天光惜壠畝，應放月團團。"]'),
('99fc02f9-8b44-4a4c-b395-8933fdee66d6','山居雜詩九十首  其一八','曹勛','宋','宋诗','song-poetry','','[]','秋色遂將半，游雲時淡濃。',48,'全唐诗/poet.song.110000.json','["秋色遂將半，游雲時淡濃。", "水光影䆉䅉，秀色增芙蓉。", "斸地種三徑，鈎窗來五峰。", "新晴何以卜，一意聽晨鐘。"]'),
('ddd88644-d6fc-44e1-95c5-a57e1990996f','山居雜詩九十首  其一九','曹勛','宋','宋诗','song-poetry','','[]','冷趁西風便，雲趨南國深。',48,'全唐诗/poet.song.110000.json','["冷趁西風便，雲趨南國深。", "相舂聞野唱，漂絮擊溪砧。", "小立遲殘照，閑愁倦寸心。", "新亭有耆舊，應共惜花陰。"]'),
('13eeb586-2b0e-4fa0-82af-35cf353b2497','山居雜詩九十首  其二○','曹勛','宋','宋诗','song-poetry','','[]','白日忽若暮，北風天正寒。',48,'全唐诗/poet.song.110000.json','["白日忽若暮，北風天正寒。", "濃陰欲釀雪，雲侶商量間。", "羣兒競喜躍，婢子爭仰看。", "命席撥甕碧，取醉期盡歡。"]'),
('0fedc6e7-935e-4d8b-83e2-ee8a8d274441','山居雜詩九十首  其二一','曹勛','宋','宋诗','song-poetry','','[]','凄風入林薄，旵日升山遲。',48,'全唐诗/poet.song.110000.json','["凄風入林薄，旵日升山遲。", "槿花落因雨，菊英開映籬。", "身老每倦客，目昏猶喜詩。", "所欣水雲念，得赴猿鶴期。"]'),
('51a8d08b-c00e-41f5-867e-9ea74e4b3b7b','山居雜詩九十首  其二二','曹勛','宋','宋诗','song-poetry','','[]','晨起冒清露，笋輿出城闉。',48,'全唐诗/poet.song.110000.json','["晨起冒清露，笋輿出城闉。", "原野回舊色，花柳摇新春。", "眷言山林性，常與魚鳥鄰。", "怡然適襟抱，自謂羲皇民。"]'),
('fb4879b6-5054-40f0-a873-c84860c035b0','山居雜詩九十首  其二三','曹勛','宋','宋诗','song-poetry','','[]','我本汝潁士，老隠天台山。',48,'全唐诗/poet.song.110000.json','["我本汝潁士，老隠天台山。", "一瓢顧粗足，三謁無厚顔。", "身與樵牧遠，居眇林壑間。", "不爲物事役，常對風日閑。"]'),
('fc147009-7ad1-49e4-bd67-7bc27879d735','山居雜詩九十首  其二四','曹勛','宋','宋诗','song-poetry','','[]','平生江海性，俗冗不到眼。',48,'全唐诗/poet.song.110000.json','["平生江海性，俗冗不到眼。", "偶然牽祿養，遂復事篇簡。", "所愧道益遠，所喜性習懶。", "末路終此惠，尤得養樗散。"]'),
('bb93d235-99d8-4532-b841-3d5c3d006bdf','山居雜詩九十首  其二五','曹勛','宋','宋诗','song-poetry','','[]','梢梢岸上柳，粼粼岸下波。',48,'全唐诗/poet.song.110000.json','["梢梢岸上柳，粼粼岸下波。", "晴雲羃遠岫，東風扇微和。", "去冬有耕植，連春無干戈。", "田畯知此意，種秫應更多。"]'),
('f84aa461-a604-4bf7-aa2b-561800914823','山居雜詩九十首  其二六','曹勛','宋','宋诗','song-poetry','','[]','高原收菽麥，下田插禾秧。',48,'全唐诗/poet.song.110000.json','["高原收菽麥，下田插禾秧。", "田頭與地尾，一一意所量。", "躬耕辨好怯，擇種均豐荒。", "所以終歲間，食米不及糠。"]'),
('f929deee-24ef-4002-855d-97a271e20bab','山居雜詩九十首  其二七','曹勛','宋','宋诗','song-poetry','','[]','大麥未救饑，小麥漸擢芒。',48,'全唐诗/poet.song.110000.json','["大麥未救饑，小麥漸擢芒。", "此時農夫嘆，政阻接青黄。", "多畏頻雨澤，只欲暄晴光。", "農安吾亦安，朝夕祈蒼蒼。"]'),
('664172a3-fec1-4e16-9bdd-0f4e7a060c86','山居雜詩九十首  其二八','曹勛','宋','宋诗','song-poetry','','[]','堂堂春將去，好花如款留。',48,'全唐诗/poet.song.110000.json','["堂堂春將去，好花如款留。", "荼䕷蔓層雪，芍藥欹重樓。", "金沙插架富，蕙香轉林幽。", "我欲助送之，飛絮漫天愁。"]'),
('37ae9e9a-9749-4ebf-85ed-aa5f83d727ac','山居雜詩九十首  其二九','曹勛','宋','宋诗','song-poetry','','[]','曉來浩露出，細履欣悠然。',48,'全唐诗/poet.song.110000.json','["曉來浩露出，細履欣悠然。", "壠麥漾輕浪，芳草迷平川。", "無邊綠成幄，團飛柳皆綿。", "老翁指謂我，漸熟高低田。"]'),
('1aa32934-eac1-4283-b710-ca3c3b412948','山居雜詩九十首  其三○','曹勛','宋','宋诗','song-poetry','','[]','西山隠道室，山光鎖葱蒨。',48,'全唐诗/poet.song.110000.json','["西山隠道室，山光鎖葱蒨。", "松竹意可揖，芳潤欲入饌。", "扳携一二友，香火共昏旦。", "天台坐忘身，笑領吾所眷。"]'),
('6a472feb-32db-405b-b570-278d43f7ddbe','山居雜詩九十首  其三一','曹勛','宋','宋诗','song-poetry','','[]','日鑄得新茗，色味建水空。',48,'全唐诗/poet.song.110000.json','["日鑄得新茗，色味建水空。", "未論七碗足，先借兩腋風。", "烹在擊拂外，香泛齒頰中。", "若論破睡魔，自可書元功。"]'),
('3fcc915b-5892-4981-8375-377e597deb6f','山居雜詩九十首  其三二','曹勛','宋','宋诗','song-poetry','','[]','行都老故舊，見贈新曆日。',48,'全唐诗/poet.song.110000.json','["行都老故舊，見贈新曆日。", "快哉得過目，蘧然若有失。", "已病嗟再歲，漸老念弱質。", "歎餘落麈尾，非言付摇膝。"]'),
('47b49ff9-024c-462e-8ec9-28817a46f093','山居雜詩九十首  其三三','曹勛','宋','宋诗','song-poetry','','[]','冰壺凍欲裂，霜風凌雪屋。',48,'全唐诗/poet.song.110000.json','["冰壺凍欲裂，霜風凌雪屋。", "牛鬭攪夕眠，缾笙不成曲。", "平生湖海心，弗受車轅促。", "晨興且探梅，不憚肌生粟。"]'),
('3b9ba9db-6d39-481b-aa91-10f78fd8cfb2','山居雜詩九十首  其三四','曹勛','宋','宋诗','song-poetry','','[]','閑中每自得，閑意非陸沉。',48,'全唐诗/poet.song.110000.json','["閑中每自得，閑意非陸沉。", "蟻穴漫說夢，鷗盟誰更尋。", "一年記好處，萬緣隨夙心。", "即以洗其勞，清月升層林。"]'),
('660fbc0f-6372-44b4-a067-955ea06f56dc','山居雜詩九十首  其三五','曹勛','宋','宋诗','song-poetry','','[]','幽居歲屢換，豪舉欲誰作。',48,'全唐诗/poet.song.110000.json','["幽居歲屢換，豪舉欲誰作。", "閑情寡賦詠，舊句漫筆削。", "草茅晦小隠，筍蕨供大嚼。", "不時有佳處，悠然動春酌。"]'),
('72669354-8d62-48cd-add8-aa61b050c63f','山居雜詩九十首  其三六','曹勛','宋','宋诗','song-poetry','','[]','塵境得閑適，塵事從如麻。',48,'全唐诗/poet.song.110000.json','["塵境得閑適，塵事從如麻。", "且發蟹眼湯，一試鷹爪芽。", "蕭蕭衲帔冷，泠泠心境嘉。", "坐久若爲侶，清月上梅花。"]'),
('0371c42a-0cbe-47d3-a5b9-5d6c83eb1b30','山居雜詩九十首  其三七','曹勛','宋','宋诗','song-poetry','','[]','小庵築桐柏，宛在艮山位。',48,'全唐诗/poet.song.110000.json','["小庵築桐柏，宛在艮山位。", "數峯直遠目，一水繞右地。", "門徑連主山，松篁接空翠。", "貴客下北闕，喜話卜鄰計。"]'),
('023c591c-1441-4548-9ca4-d0acf45d82e7','山居雜詩九十首  其三八','曹勛','宋','宋诗','song-poetry','','[]','平生有知舊，相望頓以疏。',48,'全唐诗/poet.song.110000.json','["平生有知舊，相望頓以疏。", "卧念十日雨，誰寄一行書。", "景已來白雁，詩漫如黄初。", "不忘剡溪棹，且策雪中馿。"]'),
('321a86ac-f85a-4884-bfbf-dcc56c85301d','山居雜詩九十首  其三九','曹勛','宋','宋诗','song-poetry','','[]','下邑常寂寞，細履寒溪頭。',48,'全唐诗/poet.song.110000.json','["下邑常寂寞，細履寒溪頭。", "魚鰕腥斷岸，橘柚明晚秋。", "山色儼晴碧，溪光泛澄流。", "相思故人遠，應過回雁洲。"]'),
('c8cef3fb-6c9b-4d94-971e-f62d8cfa5778','山居雜詩九十首  其四○','曹勛','宋','宋诗','song-poetry','','[]','秋色不勝悲，濃霜寒入衣。',48,'全唐诗/poet.song.110000.json','["秋色不勝悲，濃霜寒入衣。", "蔬畦倦小摘，茅簷曝晴暉。", "人去歌酒歇，雁來音信稀。", "好客招不來，楓葉伴愁飛。"]'),
('b5065f1f-7908-47ac-99b0-76089b6f2e27','山居雜詩九十首  其四一','曹勛','宋','宋诗','song-poetry','','[]','雨急怨春晚，花殘獨稔香。',48,'全唐诗/poet.song.110000.json','["雨急怨春晚，花殘獨稔香。", "燕巢方穩密，蝶翅覺凄凉。", "引睡漫支枕，銷閑時炷香。", "新晴故晚照，芳草留斜陽。"]'),
('8fa6700a-5416-4c6d-a85c-cabfaf5ee874','山居雜詩九十首  其四二','曹勛','宋','宋诗','song-poetry','','[]','駸駸隨日老，寧能問分陰。',48,'全唐诗/poet.song.110000.json','["駸駸隨日老，寧能問分陰。", "波流固自遠，雲在初無心。", "鳥聲驚幽思，風徐快沖襟。", "馬卿苦病多，中懷天莫忱。"]'),
('1a54b94b-3afa-416d-a375-c4b2b5db5962','山居雜詩九十首  其四三','曹勛','宋','宋诗','song-poetry','','[]','小隠世味薄，花飛慘殘春。',48,'全唐诗/poet.song.110000.json','["小隠世味薄，花飛慘殘春。", "明玉剝楚筍，嫩紫庖吳蓴。", "不覺槃筯闕，但喜志意新。", "我惟一廛足，何必問大鈞。"]'),
('28ac3f41-562c-4667-81c6-7241ba94c11d','山居雜詩九十首  其四四','曹勛','宋','宋诗','song-poetry','','[]','僕以義制心，自謂頗忠赤。',48,'全唐诗/poet.song.110000.json','["僕以義制心，自謂頗忠赤。", "保國不保身，用忠豈用力。", "所以四將命，悉能全趙璧。", "未當引年歸，痛定思政剌。"]'),
('199fec1a-6134-4b50-a967-3ae7377d1752','山居雜詩九十首  其四五','曹勛','宋','宋诗','song-poetry','','[]','雲山貯回腸，日月任轉轂。',48,'全唐诗/poet.song.110000.json','["雲山貯回腸，日月任轉轂。", "客居不問鄉，一飽寧較粟。", "家釀報浮蟻，溪鱗買尺玉。", "以充朝莫槃，懷抱無乃足。"]'),
('f1483ab9-2916-4bc6-951a-5e9ae2671b76','山居雜詩九十首  其四六','曹勛','宋','宋诗','song-poetry','','[]','平日爲飽役，方拋世網嬰。',48,'全唐诗/poet.song.110000.json','["平日爲飽役，方拋世網嬰。", "買魚沽市醖，借姓過州城。", "老脫塵中境，心游物外清。", "寒溪行不盡，端爲濯衣纓。"]'),
('b13b2c4b-0d25-4cce-98b9-7649481072cb','山居雜詩九十首  其四七','曹勛','宋','宋诗','song-poetry','','[]','素懷繞列岫，乃家台山麓。',48,'全唐诗/poet.song.110000.json','["素懷繞列岫，乃家台山麓。", "人境兩俱絕，事物濟所欲。", "芳醪澈琖白，茗飲瀹溪綠。", "對客調玉軫，清風入梧竹。"]'),
('ea9e42b2-74a9-4306-a27b-1d3509188532','山居雜詩九十首  其四八','曹勛','宋','宋诗','song-poetry','','[]','春來每竊抃，春去孰可喭。',48,'全唐诗/poet.song.110000.json','["春來每竊抃，春去孰可喭。", "尋勝攬妍姿，對花得清燕。", "樽酒所以樂，摘植得忘倦。", "忽改綠陰陰，蒼苔從滿院。"]'),
('f6586134-c4db-45fa-af6c-a5f95b999e22','山居雜詩九十首  其四九','曹勛','宋','宋诗','song-poetry','','[]','鑿池固不廣，納納隘所居。',48,'全唐诗/poet.song.110000.json','["鑿池固不廣，納納隘所居。", "苟無水光寒，便覺非吾廬。", "漪漣漾芳渚，澄影浮晴虛。", "樂哉濠梁心，已復游嘉魚。"]'),
('6e308969-2edd-4613-b606-071dd1148f0f','山居雜詩九十首  其五○','曹勛','宋','宋诗','song-poetry','','[]','道人范子珉，隠跡朝市端。',48,'全唐诗/poet.song.110000.json','["道人范子珉，隠跡朝市端。", "筆墨作峯嶺，氣象爭巑岏。", "稍變煙雲態，便覺風雨寒。", "鶴舉忽沖霄，大羅得遐觀。"]'),
('aa39ebe0-b651-4236-8b3b-e56d23d7f3ad','山居雜詩九十首  其五一','曹勛','宋','宋诗','song-poetry','','[]','范仙最所長，畫牛誠絕筆。',48,'全唐诗/poet.song.110000.json','["范仙最所長，畫牛誠絕筆。", "圍模大小定，毛孔不少失。", "膊腕與腹胯，一牛動數日。", "惟我頗得之，卧起盡纖悉。"]'),
('dacf3b79-d70d-4024-adec-956783be8231','山居雜詩九十首  其五二','曹勛','宋','宋诗','song-poetry','','[]','寒毬格雖下，春事亦可尋。',48,'全唐诗/poet.song.110000.json','["寒毬格雖下，春事亦可尋。", "故園少見之，花葉均來禽。", "芳蓓暖苞玉，半腮紅淺深。", "與客屢清賞，只恐風雨侵。"]'),
('4c6af5a5-5097-4130-98f4-fff71ff9e6ec','山居雜詩九十首  其五三','曹勛','宋','宋诗','song-poetry','','[]','隨春動草木，微和入池閣。',48,'全唐诗/poet.song.110000.json','["隨春動草木，微和入池閣。", "羣芳爭妍媸，紅翠媚寥廓。", "一枝姑到眼，萬態便如昨。", "春深風雨來，固已任開落。"]'),
('5d6b5ca2-14bf-4641-8e68-4a87e01b7ec7','山居雜詩九十首  其五四','曹勛','宋','宋诗','song-poetry','','[]','閑居必家釀，不以空乏廢。',48,'全唐诗/poet.song.110000.json','["閑居必家釀，不以空乏廢。", "小槽壓春碧，渾含揖和氣。", "三杯禦客寒，一巵款僕意。", "寧論有賢聖，且復供村醉。"]'),
('61f155b8-e6d9-42ac-b42c-86f62a7647b0','山居雜詩九十首  其五五','曹勛','宋','宋诗','song-poetry','','[]','小圃養春色，乘時不可緩。',48,'全唐诗/poet.song.110000.json','["小圃養春色，乘時不可緩。", "翌鋤常于于，成趣須旦旦。", "花摘去年種，喜供一時翫。", "舉杯付歌兒，野服更蕭散。"]'),
('dae5d245-b2f3-4540-91a2-0f5d79e27359','山居雜詩九十首  其五六','曹勛','宋','宋诗','song-poetry','','[]','隨分作欄檻，松竹带花柳。',48,'全唐诗/poet.song.110000.json','["隨分作欄檻，松竹带花柳。", "四時面面看，百種日日有。", "玩目必羣卉，洗心付芳酒。", "吾儕不改常，居閒簡可久。"]'),
('3e9c5cd9-bfab-4004-80d1-b84a2ca94b29','山居雜詩九十首  其五七','曹勛','宋','宋诗','song-poetry','','[]','老來參同事，勤志不敢失。',48,'全唐诗/poet.song.110000.json','["老來參同事，勤志不敢失。", "人言爐偃月，吾意爐藏日。", "朝陽升西山，異液甘若蜜。", "一體奠所居，旦旦享清逸。"]'),
('1c2f843c-3e13-46c9-8305-9c2928b71a70','山居雜詩九十首  其五八','曹勛','宋','宋诗','song-poetry','','[]','和靖骨已槁，後來欲無說。',48,'全唐诗/poet.song.110000.json','["和靖骨已槁，後來欲無說。", "細雨斷魂句，妙處益清絕。", "朅來客異縣，籬落冷風月。", "吟哦一字難，愧此枝下雪。"]'),
('b6dfa778-85d5-46d2-8d49-e07829c85dfe','山居雜詩九十首  其五九','曹勛','宋','宋诗','song-poetry','','[]','台山無牡丹，單葉已最貴。',48,'全唐诗/poet.song.110000.json','["台山無牡丹，單葉已最貴。", "斗檻數花爾，便欲發光氣。", "珍重莫肯折，如天藏地祕。", "西都每興懷，此賞殆夢寐。"]'),
('76b7c1e5-d1a3-4560-ae83-c666b7020d3a','山居雜詩九十首  其六○','曹勛','宋','宋诗','song-poetry','','[]','春深多夜雨，倦卧得飽聽。',48,'全唐诗/poet.song.110000.json','["春深多夜雨，倦卧得飽聽。", "穿林乍依微，滴簷已紛競。", "衾寒似落莫，人寂眷閑靜。", "怡然遂高眠，枕上頗適性。"]'),
('647adc64-d11d-41e5-a0b2-725e8d1ffff8','山居雜詩九十首  其六一','曹勛','宋','宋诗','song-poetry','','[]','澤國經炎夏，常厭日晷永。',48,'全唐诗/poet.song.110000.json','["澤國經炎夏，常厭日晷永。", "既乏枕簟凉，亦欠冰雪冷。", "北窗但倦卧，閑人遠造請。", "時濯醒心泉，柳下汲深井。"]'),
('c497ab5b-aaf6-41dc-af9b-433e34765280','山居雜詩九十首  其六二','曹勛','宋','宋诗','song-poetry','','[]','道人有相訪，不求養生訣。',48,'全唐诗/poet.song.110000.json','["道人有相訪，不求養生訣。", "或問琴棋妙，或笑汗漫說。", "何州有隠逸，何山富薇蕨。", "飯了且分携，日課所不屑。"]'),
('d481c787-964c-42a7-9c34-3f385a9714b7','山居雜詩九十首  其六三','曹勛','宋','宋诗','song-poetry','','[]','吾年將八十，歷踐何足數。',48,'全唐诗/poet.song.110000.json','["吾年將八十，歷踐何足數。", "義不惜骸骨，愧無罔君父。", "挂冠復挂冠，求去再求去。", "至願誠遂心，燕笑樂畎畝。"]'),
('4cf9bcef-c907-468a-93cd-296c02caf770','山居雜詩九十首  其六四','曹勛','宋','宋诗','song-poetry','','[]','山高翳落日，殘照欣晚晴。',48,'全唐诗/poet.song.110000.json','["山高翳落日，殘照欣晚晴。", "意適策筇杖，意倦眠桃笙。", "雲水喜益近，語話能忘情。", "書來故人意，相憶應遄征。"]'),
('0f136f53-5747-4ec2-9da6-4858b1167f61','山居雜詩九十首  其六五','曹勛','宋','宋诗','song-poetry','','[]','松隠靜無事，松竹惟參差。',48,'全唐诗/poet.song.110000.json','["松隠靜無事，松竹惟參差。", "避熱卧其間，綠蔭回凉吹。", "水雲不相遠，起坐常自怡。", "此心益浩然，西風生桂枝。"]'),
('bf837eac-8233-4309-97fc-bce7ceec4318','山居雜詩九十首  其六六','曹勛','宋','宋诗','song-poetry','','[]','城居得高勝，欄檻俯闤闠。',48,'全唐诗/poet.song.110000.json','["城居得高勝，欄檻俯闤闠。", "歛跡紅塵中，游目雉堞外。", "湖光浸晴碧，若與雲外會。", "漁舟何處來，幾點忽隠晦。"]'),
('f985e3bb-9e40-4ff7-9225-e6586c143ffb','山居雜詩九十首  其六七','曹勛','宋','宋诗','song-poetry','','[]','葉落復葉落，衝飈黯寥廓。',48,'全唐诗/poet.song.110000.json','["葉落復葉落，衝飈黯寥廓。", "重疊響瑟縮，翩翻下紛泊。", "倦客行脩塗，幽人倚高閣。", "歸來故山休，冰霜欲蕭索。"]'),
('12abc41f-db75-4bfe-8c3f-1172430f8a92','山居雜詩九十首  其六八','曹勛','宋','宋诗','song-poetry','','[]','商飈忽在序，候蟲凄以鳴。',48,'全唐诗/poet.song.110000.json','["商飈忽在序，候蟲凄以鳴。", "歲律念向晚，崦嵫逼于征。", "已歎日月疾，但覺須鬢獰。", "搔首欲何爲，松篁助秋聲。"]'),
('a66ca474-cf8d-4745-99c7-09ebb615ca8d','山居雜詩九十首  其六九','曹勛','宋','宋诗','song-poetry','','[]','秋暑正炎酷，人不得以息。',48,'全唐诗/poet.song.110000.json','["秋暑正炎酷，人不得以息。", "向晚注大雨，劇暑遂掃跡。", "蕭然物氣平，暫止火御職。", "上天常好生，一凉誠大德。"]'),
('63f546cf-23ca-448c-91ee-ea8befad0bbe','山居雜詩九十首  其七○','曹勛','宋','宋诗','song-poetry','','[]','人生不如意，十固常八九。',48,'全唐诗/poet.song.110000.json','["人生不如意，十固常八九。", "吾輩窮物理，挺特惟所守。", "東風暖入律，客意濃勝酒。", "游鞍縱所如，寧能困圭竇。"]'),
('33e6afc7-024a-421a-8c52-66c40917f0d8','山居雜詩九十首  其七一','曹勛','宋','宋诗','song-poetry','','[]','雲山環所臨，烟景日日異。',48,'全唐诗/poet.song.110000.json','["雲山環所臨，烟景日日異。", "山作故人接，雲爲久處計。", "酒酣一聲笛，梅風四山起。", "清香賸披拂，參橫伴村醉。"]'),
('cf3d3cb7-8f88-452b-83d5-8154e0e0f985','山居雜詩九十首  其七二','曹勛','宋','宋诗','song-poetry','','[]','我生苟無禍，放懷在詩酒。',48,'全唐诗/poet.song.110000.json','["我生苟無禍，放懷在詩酒。", "詩酒得自在，功名亦何有。", "正欲醉墜車，豈問柳生肘。", "寫我平生適，笑寄方外友。"]'),
('95a48a86-6e7f-463a-b58f-ff623dc59eb0','山居雜詩九十首  其七三','曹勛','宋','宋诗','song-poetry','','[]','墐戶喜冬序，秋容換霜風。',48,'全唐诗/poet.song.110000.json','["墐戶喜冬序，秋容換霜風。", "可歎景物移，只在笑談中。", "菊茂遠先見，蓼疏寒更紅。", "老懷欣自愜，漸享愛日功。"]'),
('e72d2001-14e4-485a-b6c1-601205ac460c','山居雜詩九十首  其七四','曹勛','宋','宋诗','song-poetry','','[]','四大一和合，所以兆我命。',48,'全唐诗/poet.song.110000.json','["四大一和合，所以兆我命。", "及其有損增，遂復制我病。", "五年過縱心，四大失正定。", "新歲轉盼來，疾應改新證。"]'),
('ea932655-fc86-4384-a62d-d643c5735622','山居雜詩九十首  其七五','曹勛','宋','宋诗','song-poetry','','[]','新年供家廟，老稚晨夕忙。',48,'全唐诗/poet.song.110000.json','["新年供家廟，老稚晨夕忙。", "塊坐溫暖處，但聞油醤香。", "不問物物闕，有食時時嘗。", "諸孫甚解事，翁乃無饑腸。"]'),
('2d7cb906-812a-418f-8c45-bd4d67923c95','山居雜詩九十首  其七六','曹勛','宋','宋诗','song-poetry','','[]','林泉久自得，窗戶向深幽。',48,'全唐诗/poet.song.110000.json','["林泉久自得，窗戶向深幽。", "不復嫌村酒，何能有客愁。", "夕陽烘遠水，飛絮挾輕鷗。", "杖屨歸從晚，柴門月一鈎。"]'),
('100a8894-1a39-44b3-a909-bbd9d092ce6b','山居雜詩九十首  其七七','曹勛','宋','宋诗','song-poetry','','[]','中春艷桃李，東風惠以繁。',48,'全唐诗/poet.song.110000.json','["中春艷桃李，東風惠以繁。", "胡爲連日雪，花葉飄闌干。", "氣非驕陽候，宛若殘臘寒。", "玄冥僭融和，玉川知其端。"]'),
('54b973ef-10da-4b16-b68a-a00689bf1a3a','山居雜詩九十首  其七八','曹勛','宋','宋诗','song-poetry','','["\u897f\u6e56"]','新春遨西湖，結伴每有侶。',48,'全唐诗/poet.song.110000.json','["新春遨西湖，結伴每有侶。", "豈意氣差忒，旬中自寒暑。", "欣欣一日晴，愀愀三日雨。", "謂言愛酒伴，有酒誰能湑。"]'),
('93aa24ca-79bc-4e96-9834-57bb0f27ef42','山居雜詩九十首  其七九','曹勛','宋','宋诗','song-poetry','','[]','門前露草嫩，極目遨青龍。',48,'全唐诗/poet.song.110000.json','["門前露草嫩，極目遨青龍。", "策杖不知遠，看山兼別峰。", "曉厨尋晚筍，客供摘新菘。", "舌下清肥足，何勞細肋供。"]'),
('6fadcef1-500c-4bff-98b4-cf689fbd07ec','山居雜詩九十首  其八○','曹勛','宋','宋诗','song-poetry','','[]','我有舊知識，生來晦蹤跡。',48,'全唐诗/poet.song.110000.json','["我有舊知識，生來晦蹤跡。", "邂逅不可見，早夜何能覓。", "忽然積習處，相逢吐胸臆。", "臨了一句子，會心極得力。"]'),
('63311bb7-ebd7-45f5-957a-5e2162691854','山居雜詩九十首  其八一','曹勛','宋','宋诗','song-poetry','','[]','斗水小漣漪，拳石獻巖竇。',48,'全唐诗/poet.song.110000.json','["斗水小漣漪，拳石獻巖竇。", "蒼蒼三峰足，挺挺數葉秀。", "棐几得巨壑，幽色清永晝。", "以我兼忘心，嵩華亦何有。"]'),
('7366cbd7-d243-4a61-8fe2-eb25546191a5','山居雜詩九十首  其八二','曹勛','宋','宋诗','song-poetry','','[]','秋雨濕庭戶，陋舍集閑客。',48,'全唐诗/poet.song.110000.json','["秋雨濕庭戶，陋舍集閑客。", "重以樽酒空，可爲饑腸厄。", "呼童取盃酌，村酒我先識。", "一杯復一杯，滿坐生春色。"]'),
('fbc25116-135a-4e9f-a5dd-6fb8c90fd40b','山居雜詩九十首  其八三','曹勛','宋','宋诗','song-poetry','','[]','秋雨不可雷，雷即雨無節。',48,'全唐诗/poet.song.110000.json','["秋雨不可雷，雷即雨無節。", "況當收刈時，只欲天明潔。", "夫何連日雨，卧穗恐芽蘗。", "已失早禾望，晚田幸天輟。"]'),
('6bee245c-1ea0-49b7-a693-740cf31d3de8','山居雜詩九十首  其八四','曹勛','宋','宋诗','song-poetry','','[]','山色侵衣冷，異氣作心賞。',48,'全唐诗/poet.song.110000.json','["山色侵衣冷，異氣作心賞。", "嶺月聞鳳笙，松風吹鶴氅。", "碧池縐澄綠，羣山發清響。", "以此助蕭閑，欣然同擊壤。"]'),
('279d3872-3bbe-4fac-bd47-2cd6e5d1262c','山居雜詩九十首  其八五','曹勛','宋','宋诗','song-poetry','','[]','寂歷斜陽岸，高低猶漲痕。',48,'全唐诗/poet.song.110000.json','["寂歷斜陽岸，高低猶漲痕。", "輕舟隨浪穩，遠水带烟昏。", "野色幾番換，喬林何處村。", "情懷了無事，安得易銷魂。"]'),
('57fd73f1-d20d-4cdc-b594-e725176a5d23','山居雜詩九十首  其八六','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','素願游匡廬，夢寐不可易。',48,'全唐诗/poet.song.110000.json','["素願游匡廬，夢寐不可易。", "棄官竟一往，不以歸意迫。", "屢扣清虛仙，杯酒話疇昔。", "永懷撥雲峰，西麈每相憶。"]'),
('bf5505a4-45de-4ea1-8e81-091664337ed0','山居雜詩九十首  其八七','曹勛','宋','宋诗','song-poetry','','[]','飯了縱閑適，杖屨涉晴晝。',48,'全唐诗/poet.song.110000.json','["飯了縱閑適，杖屨涉晴晝。", "時物破百感，環山獻明秀。", "承宇茂芳桂，追凉風細逗。", "摘果靡憚勞，聊用引稚幼。"]'),
('363b5a70-cc0f-4ce8-86bd-7ac5e2d133b3','山居雜詩九十首  其八八','曹勛','宋','宋诗','song-poetry','','[]','前日花正紅，今旦香已改。',48,'全唐诗/poet.song.110000.json','["前日花正紅，今旦香已改。", "我知色空相，未開固非在。", "韶華每備陳，風雨不相貸。", "任渠萬點飛，豈待愁如海。"]'),
('dbc43a8d-af49-4fdc-9e74-2dc4e9b093c0','山居雜詩九十首  其八九','曹勛','宋','宋诗','song-poetry','','[]','吾家遠城市，四圍縈疊嶂。',48,'全唐诗/poet.song.110000.json','["吾家遠城市，四圍縈疊嶂。", "意尋烟霞游，喜逐樵牧上。", "松間憩兩足，論高等四暢。", "或時戴月歸，山花記心想。"]'),
('402cd745-ed84-4760-a611-1346829c1a85','山居雜詩九十首  其九○','曹勛','宋','宋诗','song-poetry','','[]','雅意老山林，每作山林趣。',48,'全唐诗/poet.song.110000.json','["雅意老山林，每作山林趣。", "引領山林景，賦詠山林句。", "嵐光增日夕，林風度朝暮。", "時時携筇歸，羣山送歸戶。"]'),
('2935ba7d-de5a-4112-8add-9e54b5fa4dff','乾道聖德頌','曹勛','宋','宋诗','song-poetry','','[]','維聖有作，紹隆興運。',240,'全唐诗/poet.song.110000.json','["維聖有作，紹隆興運。", "天經地義，宗堯越舜。", "風俗惇厚，日星清潤。", "冰天桂海，咸祗成訓。", "皇矣藝祖，肇開宗祊。", "用集大命，再造羣生。", "卜世卜年，周室與京。", "德懋聖孫，區宇載寧。", "龍潛出震，握符御極。", "恭儉慈仁，已隆燕翼。", "勵精治具，羣工惟辟。", "斯皇聖德，以受方國。", "躬秉要道，化成斯民。", "問寢侍膳，克勤日新。", "刑于四海，率土興仁。", "至矣聖孝，悅安嚴親。", "猾夏餘種，久失我重。", "稍恢雄略，盡還尊奉。", "復修絳樂，亟續騫貢。", "布昭聖武，式皇鉅宋。", "洪宣景命，爰振皇綱。", "詔令諭旨，粉澤八荒。", "宸奎逸彩，龍鳳騫翔。", "煥乎聖文，彬彬日彰。"]'),
('250005fc-5c3b-487b-9002-091890154335','李次仲誕辰頌','曹勛','宋','宋诗','song-poetry','','[]','柱史列裔，清映霞舉。',80,'全唐诗/poet.song.110000.json','["柱史列裔，清映霞舉。", "環堵所禮，土木所與。", "起死濟民，渾跡塵土。", "好生廣德，密佑人主。", "三千功就，易遷行著。", "東恩及孫，西色仍敘。", "仙不言壽，道不言古。", "願祝羅浮，五雲同侶。"]'),
('372777af-4f4c-46fa-a545-f940deaac6a4','高麗爐一枚寄虎丘結老爲說偈言','曹勛','宋','宋诗','song-poetry','','[]','茲爐之先，鯨波空際。',40,'全唐诗/poet.song.110000.json','["茲爐之先，鯨波空際。", "有國曰韓，以陶以器。", "奉之函丈，寶烟輕細。", "此一瓣香，用嚴報地。"]'),
('6bea8bbe-2b45-423f-bab2-62785a2ac64d','黄節夫問疾以偈答之','曹勛','宋','宋诗','song-poetry','','[]','四大和合成我身，四大損增成我病。',64,'全唐诗/poet.song.110000.json','["四大和合成我身，四大損增成我病。", "我病在枕誰爲起，我艾在身誰爲痛。", "惟此疾痛切身時，畢竟二事誰復代。", "公今累紙示格言，願示免疾痛一句。"]'),
('e8764cec-aa88-4a89-9bb5-2030b495dbcc','戲妙德二偈  其一','曹勛','宋','宋诗','song-poetry','','[]','萬行不修無事也，隨緣放曠任逍遥。',32,'全唐诗/poet.song.110000.json','["萬行不修無事也，隨緣放曠任逍遥。", "昨夜人言風雨急，窗間只道海門潮。"]'),
('b19ae75a-1545-459f-a23e-6a22d99f0b63','戲妙德二偈  其二','曹勛','宋','宋诗','song-poetry','','[]','穩得身心常坦坦，此事從來高著眼。',32,'全唐诗/poet.song.110000.json','["穩得身心常坦坦，此事從來高著眼。", "山河大地徧遊行，只是雨下不借傘。"]'),
('673b689f-13a8-463d-b1cf-110fadfb92b3','國清曹源爲書名已復說偈云','曹勛','宋','宋诗','song-poetry','','[]','非湛非摇，真源常在。',40,'全唐诗/poet.song.110000.json','["非湛非摇，真源常在。", "直指性海，總別無礙。", "星分月現，光涵法界。", "寄語諸方，莫作擬解。"]'),
('c75700a7-69fb-4cc6-aa3e-a35c5f23f2b0','偈送剛僧錄入塔','曹勛','宋','宋诗','song-poetry','','[]','嗚呼剛兄，相識半生。',60,'全唐诗/poet.song.110000.json','["嗚呼剛兄，相識半生。", "慧林勤舊，崇先寓名。", "五旬戒臘，八十壽齡。", "平居慷慨，末後分明。", "超山之麓，示人無生。", "松鶴移巢，月冷風清。"]'),
('58f9da0d-c226-4436-a5be-b54b4141eee5','施磨衲與惠因長老','曹勛','宋','宋诗','song-poetry','','[]','三韓山川悉漢地，其中佛法亦復然。',192,'全唐诗/poet.song.110000.json','["三韓山川悉漢地，其中佛法亦復然。", "王子義天不思議，剪除須髮作佛事。", "東渡參問三乘法，無爲分與最上乘。", "喜抱方袍入浄人，有僧恭敬能攝受。", "寶華粲縟並文綺，金針細衲成帖相。", "衣裓一一如來法，一一針孔藏妙用。", "經歷百千無退轉，佛光律儀不曾失。", "我以至寶易得之，每善護持神通藏。", "是故回施惠因老，願以此衣覆法身。", "天風海濤助潮音，普聞四衆及一切。", "常如此袍無斷滅，惠因法施亦無窮。", "楖栗橫拈師子牀，法法流通並東海。"]'),
('50204344-822e-4dc3-b9ec-cf49ecf5af08','冞公出示崇寧超然相與之詩贊以伽陀','曹勛','宋','宋诗','song-poetry','','[]','崇師金聲，居士玉振。',40,'全唐诗/poet.song.110000.json','["崇師金聲，居士玉振。", "芝蘭道同，萬涂一進。", "妙語領畧，後學標準。", "如是如是，雲駛月運。"]'),
('8471371e-0e6c-429c-bc08-f8ecefa6d4b7','貧漢歸廬阜結庵作伽陀爲別','曹勛','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','辯公出藍之智，楮衲披來游戲。',98,'全唐诗/poet.song.110000.json','["辯公出藍之智，楮衲披來游戲。", "衲底一段光明，可謂湛然無累。", "倒峽傾河雄辯，銀山鐵壁意氣。", "毗盧頂𩕳上行，彌勒眼睛裏睡。", "歸去羌廬山下，一笑雪中風味。", "他時杖屨重來，且道有甚領會。", "爲公撦了楮衣，奉爲普薰一切。"]'),
('f3dcfeee-c7ad-4752-b1e3-e76e09c2c00b','故知院樞密相公葉公挽章二首  其一','曹勛','宋','宋诗','song-poetry','','[]','取第如前俯，論兵度昔賢。',48,'全唐诗/poet.song.110000.json','["取第如前俯，論兵度昔賢。", "擊姦清相位，捧日上虞淵。", "氣節公卿右，勳庸日月邊。", "一生惟許國，史牒諒盈編。"]'),
('32daba52-13da-4179-9022-dbe7d0244453','故知院樞密相公葉公挽章二首  其二','曹勛','宋','宋诗','song-poetry','','[]','帝命洪樞貴，身兼制閫雄。',48,'全唐诗/poet.song.110000.json','["帝命洪樞貴，身兼制閫雄。", "江淮奠諸壘，廟社頼元功。", "憤虜游魂孽，馳神積慮中。", "慶聯蘭玉秀，相業看家風。"]'),
('25191064-9889-47a2-a311-fce3fcac4fae','林徽猷挽章二首  其一','曹勛','宋','宋诗','song-poetry','','[]','昔處朝廷日，堅持諫諍風。',48,'全唐诗/poet.song.110000.json','["昔處朝廷日，堅持諫諍風。", "宰司資大政，帝座識孤忠。", "烏府無前匹，龍驤有舊功。", "中興追錄處，耆德在淵衷。"]'),
('687efcaf-92fd-4a18-8403-3cbd6ecf3065','林徽猷挽章二首  其二','曹勛','宋','宋诗','song-poetry','','[]','出鎮溫陵重，鄰邦頼設施。',48,'全唐诗/poet.song.110000.json','["出鎮溫陵重，鄰邦頼設施。", "未容推厚德，遽復見豐碑。", "落日輝丹旐，凄風入素帷。", "便知餘慶在，絕筆看遺詩。"]'),
('bdfb043e-5f88-4d70-9efd-a941eca95b10','陳太夫人挽章二首  其一','曹勛','宋','宋诗','song-poetry','','[]','淑德兼前懿，年齡甫八旬。',48,'全唐诗/poet.song.110000.json','["淑德兼前懿，年齡甫八旬。", "義方能教子，佛理已詮身。", "卧病才踰月，求醫不浹辰。", "人間膺上壽，松路黯凝塵。"]'),
('bfb69499-af20-474f-99c1-855267390317','陳太夫人挽章二首  其二','曹勛','宋','宋诗','song-poetry','','[]','有子賢仍貴，成家際盛時。',48,'全唐诗/poet.song.110000.json','["有子賢仍貴，成家際盛時。", "清修勤且儉，御下愛而慈。", "忽忽辭榮養，哀哀見孝思。", "几筵將啟紼，慘淡曉雲悲。"]'),
('06f16068-533d-4b8d-8374-0a910207b158','楊和王挽章五首  其一','曹勛','宋','宋诗','song-poetry','','[]','奉鑾翔覇府，血漢聖心留。',48,'全唐诗/poet.song.110000.json','["奉鑾翔覇府，血漢聖心留。", "稍護勾陳衛，旋分慰撫憂。", "威名騰瀚海，姓字竦旄頭。", "和國真封貴，元功記冕旒。"]'),
('3c79c60f-f2ea-45bd-b188-85da6eedfe25','楊和王挽章五首  其二','曹勛','宋','宋诗','song-poetry','','[]','代北生英傑，臨戎發策新。',48,'全唐诗/poet.song.110000.json','["代北生英傑，臨戎發策新。", "兩淮平僣亂，二紀並洪鈞。", "定難詩書將，推忠社稷臣。", "臨分雙下淚，每憶每霑巾。"]'),
('5b851d1c-737f-4bc7-91ef-8a487430cb43','楊和王挽章五首  其三','曹勛','宋','宋诗','song-poetry','','[]','早歲名虓將，陰功晚益昌。',48,'全唐诗/poet.song.110000.json','["早歲名虓將，陰功晚益昌。", "職齊張右相，威並郭汾陽。", "水月宸奎炳，風雲寶墨香。", "兩宮恩賻禮，深見眷忠良。"]'),
('e70c6c26-10d8-4789-b0b8-84ae142ee19c','楊和王挽章五首  其四','曹勛','宋','宋诗','song-poetry','','[]','帝謂關張勇，氣吞豺虎羣。',48,'全唐诗/poet.song.110000.json','["帝謂關張勇，氣吞豺虎羣。", "忠誠昭白日，始卒翊明君。", "滅沒台躔耀，哀榮鳳口墳。", "傳家有賢嗣，淚血入江雲。"]'),
('240c0ddc-076a-4108-94d1-4e26ec91ad39','楊和王挽章五首  其五','曹勛','宋','宋诗','song-poetry','','[]','乍去潭潭府，方多耿耿心。',48,'全唐诗/poet.song.110000.json','["乍去潭潭府，方多耿耿心。", "嘗忘言激切，共歎老侵尋。", "側聽醫方驗，何期訃報臨。", "縗麻望神坐，雲亦慘愁陰。"]'),
('07fcb158-7042-4765-a887-20b83f7c158a','春暮','曹勛','宋','宋诗','song-poetry','','[]','乾坤萬事上眉端，寂歷東風獨倚欄。',64,'全唐诗/poet.song.110000.json','["乾坤萬事上眉端，寂歷東風獨倚欄。", "白髮餘春能幾醉，綠陰細雨不多寒。", "香飄苔逕花誰惜，影落沙鶴泉自看。", "碧眼野僧知我意，素琴携就竹西彈。"]'),
('45ab2f6b-7e42-437e-8fbd-b7e6a30172d8','酬陳居士','曹勛','宋','宋诗','song-poetry','','[]','喚起離愁落木聲，抱饑猶自向書耕。',64,'全唐诗/poet.song.110000.json','["喚起離愁落木聲，抱饑猶自向書耕。", "江湖有夢追前事，天地無根笑此生。", "歲晏斷鴻羈客影，夜深殘火故人情。", "幸來相就分岑寂，閑對梅花酌翠觥。"]'),
('0fff3d8a-9d14-4a99-8690-33d6f4ff9140','浴罷','曹勛','宋','宋诗','song-poetry','','[]','浴罷披襟竹影斜，客中殘暑散空花。',64,'全唐诗/poet.song.110000.json','["浴罷披襟竹影斜，客中殘暑散空花。", "人行窗外雲無脚，月起林間燈映紗。", "舉酒聞鍾知近寺，談詩食李却忘家。", "明朝又浴還來此，何必開樽只煮茶。"]'),
('477a438b-9288-44d4-8885-73a748d88d43','仲春初五日報謁','曹勛','宋','宋诗','song-poetry','','[]','玉磬蒲團出定音，謁酬與世費浮沉。',64,'全唐诗/poet.song.110000.json','["玉磬蒲團出定音，謁酬與世費浮沉。", "徑松參漢周官肅，塢竹藏雲商易深。", "莫色溪山皆有道，春風花草本無心。", "年來年去頭成白，斗酒樓前明月斟。"]'),
('18d80a40-10db-4622-866b-ccc45ab87ef5','多謝','曹勛','宋','宋诗','song-poetry','','[]','多謝東皇著意晴，海棠勻趁笑相迎。',64,'全唐诗/poet.song.110000.json','["多謝東皇著意晴，海棠勻趁笑相迎。", "園林富貴何千萬，花柳功勳已十成。", "曉雨有情於芍藥，春風無處不流鶑。", "扁舟水長一篙許，茶竈筆牀聊意行。"]'),
('32e6ff7e-5790-4de5-bc4e-a796fe1f1ad2','厭厭','曹勛','宋','宋诗','song-poetry','','[]','厭厭夜飲忘更深，客不來辭主有情。',64,'全唐诗/poet.song.110000.json','["厭厭夜飲忘更深，客不來辭主有情。", "僮僕觸屏成蝶夢，姬姜擫笛作蟬聲。", "月如有待行行慢，風不生嗔細細清。", "萍散人生何可料，嬋娟千里共交盟。"]'),
('eba78af5-030d-4481-bfab-5505d49c6b12','辭賈徽州','曹勛','宋','宋诗','song-poetry','','[]','束書歸去饗梅花，底事霏英故故斜。',64,'全唐诗/poet.song.110000.json','["束書歸去饗梅花，底事霏英故故斜。", "約住忙中千里鶴，羨渠如意兩歸鴉。", "家中見雪念爲客，客裏觀梅不似家。", "園樹暫時相鬭白，明朝休向我儂誇。"]'),
('0d615a5e-af9b-4663-b092-fad382144952','三月二首  其一','曹勛','宋','宋诗','song-poetry','','[]','三月春如年少時，了知造化最兒嬉。',64,'全唐诗/poet.song.110000.json','["三月春如年少時，了知造化最兒嬉。", "智行無事柳飛絮，道發自然花滿枝。", "錦繡園林添富貴，神仙院落鬭清奇。", "老夫長似春三月，游戲人間不皺眉。"]'),
('4b41b1ea-f7af-46f6-bd77-af0bfe9fda1a','三月二首  其二','曹勛','宋','宋诗','song-poetry','','[]','游子從來悲故鄉，歸來襟袖芷蘭芳。',64,'全唐诗/poet.song.110000.json','["游子從來悲故鄉，歸來襟袖芷蘭芳。", "夢魂飛去雲濤遠，杖策閑行秋水光。", "可是夢中曾到此，安知身後却餘香。", "紫陽弟子有賢子，卜築新亭真肯堂。"]'),
('fb588eaa-607d-4bad-b959-cae097d62625','翠玉樓晚雨','曹勛','宋','宋诗','song-poetry','','[]','晚樓一曲轉梅花，官事無多報放衙。',64,'全唐诗/poet.song.110000.json','["晚樓一曲轉梅花，官事無多報放衙。", "林木蔽虧烟斷續，江流曲折雨橫斜。", "年華冉冉風前影，歲莫悠悠客裏家。", "一雁近從沙嘴落，更饒片雪入天涯。"]'),
('05863786-d35e-4dde-84b4-854d98e26c0c','中秋雨過月出  其一','曹勛','宋','宋诗','song-poetry','','[]','欲遣清風掃亂雲，先將一雨凈游塵。',64,'全唐诗/poet.song.110000.json','["欲遣清風掃亂雲，先將一雨凈游塵。", "今年大作中秋事，月色何孤我輩人。", "照却八方還剩在，看來千古許清新。", "不眠不惜明朝補，報答孤光醉是真。"]'),
('0797211b-da60-4639-bec9-1837247073c1','中秋雨過月出  其二','曹勛','宋','宋诗','song-poetry','','[]','綠陰芳樹鳥啼春，與客相携發興新。',64,'全唐诗/poet.song.110000.json','["綠陰芳樹鳥啼春，與客相携發興新。", "半落杏花初過雨，微酸梅子已生仁。", "每尋詩去必遷坐，穩跨牛歸不問津。", "筋力尚堪簑笠在，莫欺老子髮如銀。"]'),
('7c911e23-1fae-40c8-9d5b-a79d62fc878d','山中二首  其一','曹勛','宋','宋诗','song-poetry','','[]','山中從事亦賢勞，安得眠雲獨自高。',64,'全唐诗/poet.song.110000.json','["山中從事亦賢勞，安得眠雲獨自高。", "兩席地栽青紫芥，一株樹接碧紅桃。", "春風多可移花性，夜雨無聲入土膏。", "那辦工夫到詩句，溪燈穿屋未編茅。"]'),
('56f2478e-6834-4d33-a90f-64e9f167a70f','山中二首  其二','曹勛','宋','宋诗','song-poetry','','[]','人間久矣倦迎逢，歸路牛羊带夕舂。',64,'全唐诗/poet.song.110000.json','["人間久矣倦迎逢，歸路牛羊带夕舂。", "千點梅沉山店月，一溪煙咽寺樓鐘。", "窮猶羞澀巉巖面，老自平夷磊磈胸。", "曾笑古人多晚謬，草庵雖小幸相容。"]'),
('b5ecf19b-e690-47fb-b7b8-f0329fbea206','立春','曹勛','宋','宋诗','song-poetry','','[]','初信車風入綵幡，自挑雪薺飣春盤。',64,'全唐诗/poet.song.110000.json','["初信車風入綵幡，自挑雪薺飣春盤。", "土牛又送一年老，野鶴不知三逕寒。", "筋力尚堪耕綠野，□毛併欲掛黄冠。", "無人共跨南山犢，更作尋花問柳看。"]'),
('0c2cd57d-f2f4-4ab2-92fb-791912087d2f','泊冷水浦','曹勛','宋','宋诗','song-poetry','','[]','前夕放船湘口步，約到衡州來日午。',64,'全唐诗/poet.song.110000.json','["前夕放船湘口步，約到衡州來日午。", "五程一減作三程，謝渠江漲半篙清。", "今日雨來三四五，又閉疏蓬聽暮雨。", "長年商量泊舟所，雨外青山更青處。"]'),
('e670a956-e2e5-475c-b8b8-fd6c23d8f548','夜雨獨覺','曹勛','宋','宋诗','song-poetry','','[]','枕上還鄉枕上回，更更點點把人催。',64,'全唐诗/poet.song.110000.json','["枕上還鄉枕上回，更更點點把人催。", "雨將苔砌滴到曉，風揀荻簾疏處來。", "每到凋年每多感，不教睡眼不曾開。", "來宵我識華胥路，莫近茶甌近酒杯。"]'),
('a044aa2c-87b1-40ae-b5ad-8043ebe49b5f','夜聞風聲','曹勛','宋','宋诗','song-poetry','','[]','作寒作暑無處避，花落花開儘他意。',64,'全唐诗/poet.song.110000.json','["作寒作暑無處避，花落花開儘他意。", "只有夜聲殊可憎，偏攪愁人五更睡。", "幸自無形那有聲，無端樹子替渠鳴。", "斫盡老槐與枯柳，更看渠儂作麽生。"]'),
('8b415306-3000-4899-a969-3bf8bacf1cdc','三月十日','曹勛','宋','宋诗','song-poetry','','[]','纔看桃李錦成圍，忽使園林綠作堆。',64,'全唐诗/poet.song.110000.json','["纔看桃李錦成圍，忽使園林綠作堆。", "遠草將人雙眼去，飛花引蝶過牆來。", "簿書節裏無多著，懷抱朝來得好開。", "已是七分春去了，何須鳥語苦相催。"]'),
('f45236db-d100-4f47-a5e8-e6ae4d4ce24d','過秀溪長句','曹勛','宋','宋诗','song-poetry','','[]','去年來此上巳日，今年重來未寒食。',64,'全唐诗/poet.song.110000.json','["去年來此上巳日，今年重來未寒食。", "臨溪照影老自羞，慚愧春光尚相識。", "秀溪何許好春容，最是溪深樹密中。", "海棠開盡却成白，桃李欲落翻深紅。"]'),
('7b8134d1-9f60-44a1-b6f9-5f69841c1c75','雪後','曹勛','宋','宋诗','song-poetry','','[]','雪後山齋鶴睡殘，登臨等得蘚泥乾。',64,'全唐诗/poet.song.110000.json','["雪後山齋鶴睡殘，登臨等得蘚泥乾。", "毋多酌酒亦成醉，儘足看梅不道寒。", "籬落十分春意思，人家一色玉闌干。", "小詩未就冰生硯，洗盡人間渴肺肝。"]'),
('67359684-afea-42a8-bc9c-fff9873183be','卜居','曹勛','宋','宋诗','song-poetry','','[]','久欲謀歸力不任，浮雲蹤跡謾巢林。',64,'全唐诗/poet.song.110000.json','["久欲謀歸力不任，浮雲蹤跡謾巢林。", "功名未入屠龍手，貧賤常懷買鶴心。", "月下開門微雨過，樓頭聞笛二更深。", "世間萬事俱陳迹，空倚西風閲古今。"]'),
('3f734a47-15e8-495f-a121-89d3975e095e','繭窩','曹勛','宋','宋诗','song-poetry','','[]','百年三萬六千埸，擬挈乾坤入睡鄉。',64,'全唐诗/poet.song.110000.json','["百年三萬六千埸，擬挈乾坤入睡鄉。", "世事何常雲聚散，古人安在草荒凉。", "不禁杜宇催春老，莫怪吳蠶作繭忙。", "已擅一丘吾事足，人間蟻垤自侯王。"]'),
('ef620cf1-bd78-4e35-9eae-51d380db035c','趙周卿送菜','曹勛','宋','宋诗','song-poetry','','[]','虛老空山學圃翁，荷鋤頭白雪蓬鬆。',64,'全唐诗/poet.song.110000.json','["虛老空山學圃翁，荷鋤頭白雪蓬鬆。", "芥臺如臂何曾夢，菜腦生筋漫自供。", "不料官園蒼玉束，絕勝禁臠紫駝峯。", "更煩詩手剪春雨，剩與一番風露胸。"]'),
('63603283-816e-425e-a284-a6fc77b976d1','今乃和以報之','曹勛','宋','宋诗','song-poetry','','[]','賀子胸中自有山，結庵山底更雲間。',64,'全唐诗/poet.song.110000.json','["賀子胸中自有山，結庵山底更雲間。", "遣才只道今無許，此士如何尚著閑。", "未應萬言直杯水，向來九虎守天關。", "莫嫌久不還詩債，詩債從來隔歲還。"]'),
('0850e701-f6af-4faa-ad48-dc8bbd382f1b','七年十二日夜登清心閣','曹勛','宋','宋诗','song-poetry','','[]','小樓秋夜明月底，仰不見天惟見水。',64,'全唐诗/poet.song.110000.json','["小樓秋夜明月底，仰不見天惟見水。", "岸巾獨立四無人，白月青天伴陽子。", "誰知橫玉作秋聲，一聲吹盡九陌塵。", "月輪半仄吾未睡，樓角風生凉殺人。"]'),
('082b8089-fae9-4e90-8cb8-8e39338e8e49','燈下讀山谷詩','曹勛','宋','宋诗','song-poetry','','[]','天下無雙雙井黄，遺編猶作舊時香。',64,'全唐诗/poet.song.110000.json','["天下無雙雙井黄，遺編猶作舊時香。", "百年人物今安在，千載功名紙半張。", "使我詩篇如許好，關人身事亦何嘗。", "地爐火暖燈花喜，且只移家住醉鄉。"]'),
('bf482a72-c6b9-40bd-8db1-f4becc88c8b9','戲成','曹勛','宋','宋诗','song-poetry','','[]','春光曉看如殘夢，院靜宜兼竹影疏。',32,'全唐诗/poet.song.110000.json','["春光曉看如殘夢，院靜宜兼竹影疏。", "新處觸時佳意在，夜寒猶怯枕衾孤。"]'),
('ecac23c5-c184-4ed1-be83-8fb5a72cfa34','贈祈雨僧彥圓','許端夫','宋','宋诗','song-poetry','','[]','浄戒當年賽願身，積薪危坐志通神。',32,'全唐诗/poet.song.110000.json','["浄戒當年賽願身，積薪危坐志通神。", "應誠甘霔蘇羣品，今有高人繼後塵。"]'),
('e5434c4a-058f-4ab9-825e-fc91703835a1','陪陳太守遊南山道院','宋貺','宋','宋诗','song-poetry','','[]','漫陪仙吏訪仙鄉，仙室傾頹逕路荒。',64,'全唐诗/poet.song.110000.json','["漫陪仙吏訪仙鄉，仙室傾頹逕路荒。", "碧草護壇麏有跡，紅桃照井水浮香。", "巖邊鶴返曾千歲，夢裏丹分近一囊。", "最憐仙術神如此，何不霞新煉藥房。"]'),
('a44d8d98-0ed3-4737-8c26-7bf05e91cc9a','句','宋貺','宋','宋诗','song-poetry','','[]','鼇分雙島江心寺，鷁散連檣海面舟。',16,'全唐诗/poet.song.110000.json','["鼇分雙島江心寺，鷁散連檣海面舟。"]'),
('3dae93da-ff68-4814-8edf-6a3b91a6da4e','遊淡山巖','王資仁','宋','宋诗','song-poetry','','[]','淡山之景真尋幽，我來爲款窮冥搜。',96,'全唐诗/poet.song.110000.json','["淡山之景真尋幽，我來爲款窮冥搜。", "嵌巖呀豁自呈露，天匠巧斲非人謀。", "撐空突兀幾千仞，奇偉萬狀不可侔。", "羣仙祕護人迹絕，元柳不到誰雕鎪。", "惜無好語寫形似，歎息欲去仍遲留。", "惟予六客信心賞，一洗萬古塵中游。"]'),
('f224e51e-36f6-40dc-91a0-5a83dfcfe5f4','句','王資仁','宋','宋诗','song-poetry','','[]','三到澬州不賦詩，溪山應笑懶吟癡。',16,'全唐诗/poet.song.110000.json','["三到澬州不賦詩，溪山應笑懶吟癡。"]'),
('69f24b9f-7310-4238-b943-5efeb8c6eaf4','黄天蕩','張憲','宋','宋诗','song-poetry','','[]','昆明劫燒成灰火，臨平葑湖撥不開。',64,'全唐诗/poet.song.110000.json','["昆明劫燒成灰火，臨平葑湖撥不開。", "黄泥萬頃下無底，海眼一絲通往來。", "南徐江邊海鰌走，江神頓足黄龍吼。", "便翻銀漢濯泥沙，要使妖蛇先授首。"]'),
('c104e6c4-206f-42bd-8004-14bddca3802e','玩鞭亭','張憲','宋','宋诗','song-poetry','','[]','畸烏壓營營作聲，紅光紫電圍金鉦。',80,'全唐诗/poet.song.110000.json','["畸烏壓營營作聲，紅光紫電圍金鉦。", "黄鬚小龍馬上嘯，白日饑豺夢裏驚。", "老奴怒擲珊瑚枕，追兵起合琉璃井。", "巴馬東歸疾似風，道旁遺糞如水冷。", "健兒空玩七寶鞭，荆臺老姥空誰傳。"]'),
('ccdbbf13-f847-4c97-9d12-945ba2182abb','閬州','任約','宋','宋诗','song-poetry','','[]','塵外分明一錦屏，南樓相對競崢嶸。',32,'全唐诗/poet.song.110000.json','["塵外分明一錦屏，南樓相對競崢嶸。", "却緣造化生來別，不信丹青畫得成。"]'),
('a1a275fb-9e38-4954-a457-cb98587c9fe8','巴州西龕','任約','宋','宋诗','song-poetry','','[]','門徑森寒柏，小橋穿□□。',89,'全唐诗/poet.song.110000.json','["門徑森寒柏，小橋穿□□。", "澄江朱檻北，晚照碧巖□。", "修架清泉逗，高楠邃□□。", "虛廊面青壁，危棧跨□□。", "絕頂舒平席，遥峯□□□。", "□□俯星斗，襟袂□□□。", "□□春膏浹，□□□□迷。", "嶺猿□谷。"]'),
('94a658be-e985-4fb8-9e23-0911d0d79b61','老人岩','李惟德','宋','宋诗','song-poetry','','[]','絕巘稜層面勢尊，老人岩洞更連軒。',64,'全唐诗/poet.song.110000.json','["絕巘稜層面勢尊，老人岩洞更連軒。", "何時鑿出青雲路，盡日高開碧玉門。", "靜照井閭森寶秘，靈摩星斗弄清溫。", "直須賦有神仙骨，便好飛騰向上奔。"]'),
('1d3a739c-66c0-42ab-8aa9-d66f2065a26c','題隠真宮','蔡向','宋','宋诗','song-poetry','','[]','福地流傳號隠真，麻姑曾款蔡翁門。',64,'全唐诗/poet.song.110000.json','["福地流傳號隠真，麻姑曾款蔡翁門。", "臼舂雲子自堪飽，井溢丹泉便可吞。", "山露五峯疑指爪，溪盤百疊想裙痕。", "我來既躡靈蹤後，知是仙家第幾孫。"]'),
('797136a5-2303-4208-8bfc-2c644d40fa3d','題張子正觀察溪風亭  其一','蔡向','宋','宋诗','song-poetry','','[]','雅致園林景特奇，綵亭斜跨水淪漪。',64,'全唐诗/poet.song.110000.json','["雅致園林景特奇，綵亭斜跨水淪漪。", "影摇碎日浮霜簟，聲觸危欄倚釣絲。", "岸幘不妨橫醉榻，縈眉時復度新詞。", "溪山風月年年好，長與高人嘯詠期。"]'),
('218243ce-8553-4e73-8bda-94000a6925e7','題張子正觀察溪風亭  其二','蔡向','宋','宋诗','song-poetry','','[]','西山蚤擅三明譽，東淛真成九老游。',64,'全唐诗/poet.song.110000.json','["西山蚤擅三明譽，東淛真成九老游。", "水閣風亭忘歲月，巖花澗草度春秋。", "季鷹自足蒓鱸興，平子寧甘都邑留。", "圯上一編今在否，向來專爲赤松謀。"]'),
('f9c898fb-63c6-4839-98d4-5b16cea101e0','題張子正觀察溪風亭  其三','蔡向','宋','宋诗','song-poetry','','[]','憶昨從游鄞水邊，星霜荏苒幾經年。',64,'全唐诗/poet.song.110000.json','["憶昨從游鄞水邊，星霜荏苒幾經年。", "里居梁宋正連接，僑寓海山相後先。", "別墅豈堪陪謝傅，後堂那復醉彭宣。", "自慚憔悴成疏懶，浪許賡吟池上篇。"]'),
('1e8fcfb1-a5af-4ca7-b58f-9814d7377571','留題授上人曲肱齋','蔡向','宋','宋诗','song-poetry','','[]','莫笑此齋小，曲肱聊度年。',48,'全唐诗/poet.song.110000.json','["莫笑此齋小，曲肱聊度年。", "玉樓容十二，世界納三千。", "亦可羅尊俎，何妨散簡編。", "戲余留歲月，牆遠不能前。"]'),
('fa6dd614-88df-4dd2-8d56-efc062686ab9','題洪景伯分繡閣','蔡向','宋','宋诗','song-poetry','','[]','傑閣橫空爽氣收，一時勝槩壓巖幽。',64,'全唐诗/poet.song.110000.json','["傑閣橫空爽氣收，一時勝槩壓巖幽。", "要將繡嶺匿峰色，分入霞城棲月樓。", "雌霓挂簷供彩筆，雄風拂面快金甌。", "才華便合沖霄去，應爲看雲却少留。"]'),
('7003bc99-744f-48ae-8cab-77f20df1e9e9','贈幽谷老人','蔡向','宋','宋诗','song-poetry','','[]','芒鞋踏破兩淮塵，夢斷邯鄲迹未陳。',64,'全唐诗/poet.song.110000.json','["芒鞋踏破兩淮塵，夢斷邯鄲迹未陳。", "唳鶴啼猿猶有恨，巖花澗草總相親。", "三生頓悟舊緣在，一笑還驚熟處新。", "瓶鉢賸添風月滿，與君同是再來人。"]'),
('b6eb9fa4-d264-49a9-acda-9ba526bb8b40','三學院  其一','王投','宋','宋诗','song-poetry','','[]','精藍本是真人宅，疊嶂今名釋子山。',64,'全唐诗/poet.song.110000.json','["精藍本是真人宅，疊嶂今名釋子山。", "綠樹不妨丹鶴下，白雲常伴老僧閒。", "無風木任秋蟬蔭，積雨庭多石蘚斑。", "儒客坐來除俗態，暮鐘飛出望歸還。"]'),
('3c808a43-64b3-4a97-ac7a-10b4fc8d0efe','三學院  其二','王投','宋','宋诗','song-poetry','','[]','三面松篁簇梵宮，當軒冷砌畫屏風。',32,'全唐诗/poet.song.110000.json','["三面松篁簇梵宮，當軒冷砌畫屏風。", "遊人試問空門理，雲起青山鶴出籠。"]'),
('94a2cd75-b3a3-447e-8841-b6af9348c200','句','楊粹中','宋','宋诗','song-poetry','','[]','山猶連蜀道，人已作秦音。',12,'全唐诗/poet.song.110000.json','["山猶連蜀道，人已作秦音。"]'),
('0c31fef9-5520-4a34-8812-7ca814f56fdb','題淡山巖','陳□諒','宋','宋诗','song-poetry','','[]','我聞淡山之岩深且幽，崆嵌邃竇堪尋搜。',98,'全唐诗/poet.song.110000.json','["我聞淡山之岩深且幽，崆嵌邃竇堪尋搜。", "禪龕剝落氣尚古，龍象□徙初誰謀。", "神仙窟□信有□，功出天造非人侔。", "谽谺磥砢駭未見，石壁字隠苔侵鎪。", "山靈疇昔莫□祕，巨蟒豈得於中留。", "吟來珠璣重滿把，我幸蠟屐欣從游。"]'),
('fc8b0f62-4967-4fad-bee3-0974f1d42f74','吊危一','李炳','宋','宋诗','song-poetry','','[]','南鄉老人危翁一，歲晏雨晴扶杖出。',64,'全唐诗/poet.song.110000.json','["南鄉老人危翁一，歲晏雨晴扶杖出。", "驚聞二聖塵再蒙，歸闔柴門哭三日。", "眼空愁絕聲遂止，里人唁翁翁死矣。", "凜然生氣申包胥，萬古千秋葬忠義。"]'),
('a2087741-738d-4af5-834c-5278f3174328','句','李炳','宋','宋诗','song-poetry','','[]','柳老拋綿後，梅酸著骨時。',12,'全唐诗/poet.song.110000.json','["柳老拋綿後，梅酸著骨時。"]'),
('6e1106c5-911d-4373-ae91-52b31accfbbc','浄因院建炎兵火獨存紀事','聞人偲','宋','宋诗','song-poetry','','[]','湖海浮家二十年，重來春色尚依然。',64,'全唐诗/poet.song.110000.json','["湖海浮家二十年，重來春色尚依然。", "杏花籬落噴紅霧，楊柳林塘護綠煙。", "草暖村人出游地，鳩鳴刺史勸農天。", "覺場獨在三災外，試問支郎第幾禪。"]'),
('64f04d63-b3ca-46f4-9b64-989c4a0d3be9','夏日過莊嚴寺寺僧索詩爲留三絕拉舍弟同賦  其一','晁公休','宋','宋诗','song-poetry','','[]','十里溪橋梵宇新，那知陌上漲紅塵。',32,'全唐诗/poet.song.110000.json','["十里溪橋梵宇新，那知陌上漲紅塵。", "老僧苦要題名姓，不道林泉皆故人。"]'),
('d5576e12-e6aa-45fd-915f-21e02f61c9bb','夏日過莊嚴寺寺僧索詩爲留三絕拉舍弟同賦  其二','晁公休','宋','宋诗','song-poetry','','[]','病起支離倚瘦筇，幅巾芒屩竹陰中。',32,'全唐诗/poet.song.110000.json','["病起支離倚瘦筇，幅巾芒屩竹陰中。", "聞蟬未有驚人句，且就禪床一榻風。"]'),
('481fa259-7620-4b65-bcfb-17d8f9f3330b','夏日過莊嚴寺寺僧索詩爲留三絕拉舍弟同賦  其三','晁公休','宋','宋诗','song-poetry','','[]','機杼聲中禾稻肥，疇瓜區芋綠成畦。',32,'全唐诗/poet.song.110000.json','["機杼聲中禾稻肥，疇瓜區芋綠成畦。", "田家樂事今如許，何日邊城息鼓鼙。"]'),
('8c203511-6461-414d-9a1b-2cb5e1e83158','峽山寺','晁公邁','宋','宋诗','song-poetry','','[]','地闢天分碧峽嵬，雷奔電激駕潮回。',64,'全唐诗/poet.song.110000.json','["地闢天分碧峽嵬，雷奔電激駕潮回。", "神移古殿名猶在，石架禪房勢欲摧。", "璧月近依朱檻轉，冰泉暗度白雲來。", "南遊瘴國吾何恨，懷抱多從此地開。"]'),
('089a0b10-26f3-410b-aa27-9efee3fe61d1','觀鵝山飛瀑','劉洪道','宋','宋诗','song-poetry','','[]','探奇不畏險，撥霧上高岑。',24,'全唐诗/poet.song.110000.json','["探奇不畏險，撥霧上高岑。", "放眼觀飛瀑，枕流聽素琴。"]'),
('8a352717-caeb-413a-af97-b22181a34a5b','挽和靖先生  其一','曾班','宋','宋诗','song-poetry','','[]','凜凜河南已百年，維公高行繼前賢。',64,'全唐诗/poet.song.110000.json','["凜凜河南已百年，維公高行繼前賢。", "早施絳帳崇師席，晚入金華侍講筵。", "斯道未傳今逝矣，彼蒼難問竟茫然。", "回思昨日論交地，不見牙籤列簡編。"]'),
('663558da-941c-4508-ad7e-66d93af47974','挽和靖先生  其二','曾班','宋','宋诗','song-poetry','','[]','道直心無愧，師嚴貌有威。',48,'全唐诗/poet.song.110000.json','["道直心無愧，師嚴貌有威。", "上方虛席待，公忽掛冠歸。", "王室懷元老，天星掩少微。", "簪紳競相弔，奚獨我心悲。"]'),
('2f0c9a81-788d-4cb5-ba3b-4e9ae0f202a8','新嶺庵  其一','鄧柞','宋','宋诗','song-poetry','','[]','千尺長松矗太清，倚松棟宇與雲平。',32,'全唐诗/poet.song.110000.json','["千尺長松矗太清，倚松棟宇與雲平。", "憑闌只恐西風起，吹上青冥九萬程。"]'),
('e8cb7817-69fe-4de5-983f-a4c67d0aa6f4','新嶺庵  其二','鄧柞','宋','宋诗','song-poetry','','[]','三徑從來半草萊，席門那爲故人開。',32,'全唐诗/poet.song.110000.json','["三徑從來半草萊，席門那爲故人開。", "自慚不是梧桐樹，安得朝陽鳴鳳來。"]'),
('f0cb3a56-1adc-46df-add4-1b4686aaf0ba','新嶺庵  其三','鄧柞','宋','宋诗','song-poetry','','[]','彭澤思歸意末成，折腰五斗謾勞生。',32,'全唐诗/poet.song.110000.json','["彭澤思歸意末成，折腰五斗謾勞生。", "何如張翰秋風起，便憶鱸鱼蓴菜羹。"]'),
('e590cefc-59e3-49af-aa93-f7f723e27aff','新嶺庵  其四','鄧柞','宋','宋诗','song-poetry','','[]','厭從薄宦思蓮幕，思見故人映玉山。',32,'全唐诗/poet.song.110000.json','["厭從薄宦思蓮幕，思見故人映玉山。", "須信人生貴適志，相逢樽酒且開顔。"]'),
('266241cc-2c45-425c-a767-5456f2021e07','新嶺庵  其五','鄧柞','宋','宋诗','song-poetry','','[]','筆下文章信有神，西來避地不無因。',32,'全唐诗/poet.song.110000.json','["筆下文章信有神，西來避地不無因。", "要看銀河從天落，一洗人間萬古塵。"]'),
('c8dd9f76-413f-4ba1-9752-8f6fd84e3b06','新嶺庵  其六','鄧柞','宋','宋诗','song-poetry','','[]','中原回首涕沾裳，誰是當時柱石强。',32,'全唐诗/poet.song.110000.json','["中原回首涕沾裳，誰是當時柱石强。", "會喚謫仙天上去，扶將日轂出扶桑。"]'),
('070ff56b-bc23-4deb-ace6-f55559279183','謁姜相祠墳','鄧柞','宋','宋诗','song-poetry','','[]','布衣崛起秉洪鈞，料事當年若有神。',64,'全唐诗/poet.song.110000.json','["布衣崛起秉洪鈞，料事當年若有神。", "三尺孤墳封馬鬣，一時直道犯龍鱗。", "從容未見回天力，流落空聞棄海濱。", "頼有高人秦處士，不妨築室作居鄰。"]'),
('9e93f9c0-c420-477a-82b2-856c1639d9a4','題白蓮院','鄧柞','宋','宋诗','song-poetry','','[]','古樹紛紛千嶂雨，遠寺鳴鐘迷處所。',64,'全唐诗/poet.song.110000.json','["古樹紛紛千嶂雨，遠寺鳴鐘迷處所。", "一水東流浮落花，隔雲應有秦人住。", "海風不斷長松路，萬籟寒生蒼玉麈。", "此去江南山更深，桄榔葉暗猨啼苦。"]'),
('ee770168-c78d-4866-9d7f-523627a01ec1','乞休','鮑彪','宋','宋诗','song-poetry','','[]','一綸長伴月娟娟，滿岸蘆花入短舷。',32,'全唐诗/poet.song.110000.json','["一綸長伴月娟娟，滿岸蘆花入短舷。", "薜荔未堪華衮用，此身甘作老林泉。"]'),
('6d16d9c8-8928-4c3f-b30f-1358818e698c','遊虎邱','焦煥','宋','宋诗','song-poetry','','[]','尋勝訪幽剎，招朋泛遠舟。',48,'全唐诗/poet.song.110000.json','["尋勝訪幽剎，招朋泛遠舟。", "清風楊柳岸，微雨芰荷秋。", "師去餘禪幾，雲閒動客愁。", "無緣陪玉麈，共醉碧山頭。"]'),
('49fccf4d-85ce-4e8c-9371-ee1d71171603','題慈谿慶安寺古松','馮輗','宋','宋诗','song-poetry','','[]','寒松一幹老蒼蒼，古寺門前歲月長。',64,'全唐诗/poet.song.110000.json','["寒松一幹老蒼蒼，古寺門前歲月長。", "匠伯偶圖舟楫利，禪翁方患斧斤傷。", "得全此日同齊櫟，勿翦他年比召棠。", "可但與君期久遠，相將俱列大夫行。"]'),
('819ca326-eb98-4ef3-9d79-63b718c1e060','吳江太湖笠澤虹橋','陳遠','宋','宋诗','song-poetry','','["\u592a\u6e56"]','世間八月十五夜，何處樓臺得月多。',32,'全唐诗/poet.song.110000.json','["世間八月十五夜，何處樓臺得月多。", "不及吳江橋上望，水晶宮裏揖嫦娥。"]'),
('81fd317f-2544-4334-ba09-f8d7b0432e83','重修朝宗門樓集句呈王宰','余壹','宋','宋诗','song-poetry','','[]','茲城實佳麗，上與浮雲齊。',280,'全唐诗/poet.song.110000.json','["茲城實佳麗，上與浮雲齊。", "回望川之陰，津途去不迷。", "一旦起樓高百尺，城高跨樓滿金碧。", "朱門峨峨臨九衢，一片彩霞迎曉日。", "好奇賞俊實難逢，看此寧避雨與風。", "仍誇縣尹風騷客，與人一心成大功。", "應喜中原正無事，出爲蒼生作仙吏。", "大賢爲政即多聞，不獨文章推國器。", "立驅巘崿壓波瀾，千古煙霞一望間。", "江上晚來堪畫處，丹青畫出是君山。", "况乃烹鮮會嘉客，樓上重重歌吹發。", "艷歌一曲酒一杯，華筵有戲呈初徹。", "樓中美人奪神仙，輕身起舞紅燭前。", "須臾宴罷日將夕，斷燼遺香裊翠烟。", "四座少年君聽取，太平時節難身遇。", "先生事業不可量，此中豈是久留處。", "且飲美酒登高樓，高視乾坤又何愁。", "早晚北門下徵詔，珮聲歸去鳳池頭。"]'),
('0f419635-252c-4803-9c06-e30b9f745345','舟次南華寺','李喬木','宋','宋诗','song-poetry','','[]','衣鉢相傳舊，菩提漫爾栽。',48,'全唐诗/poet.song.110000.json','["衣鉢相傳舊，菩提漫爾栽。", "好山僧獨占，冒暑我初來。", "野鳥迎人語，溪塘傍竹開。", "登臨問因果，老衲笑相陪。"]'),
('5511ac9e-aa98-4eba-9169-1756bf52d13e','平黎錫宴','李喬木','宋','宋诗','song-poetry','','[]','聖主當年重武文，柳營韜略孰同群。',64,'全唐诗/poet.song.110000.json','["聖主當年重武文，柳營韜略孰同群。", "名播中外揚三殿，威遏鯨鯢震六軍。", "宴錫九重恩浩蕩，醉酣三爵坐氤氳。", "何人緩带當樽俎，彝鼎重看勒巨勳。"]'),
('b3948923-2b1e-4063-bc09-b0f42e30e34a','吳江縣','李貫','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','四面漁家繞縣城，古今名手謾丹青。',64,'全唐诗/poet.song.110000.json','["四面漁家繞縣城，古今名手謾丹青。", "菰蒲水淺連江寺，橘柚煙深隔洞庭。", "幽鷺下時分野色，遠帆歸處印天形。", "誰知張翰思鱸意，猶勝靈均醉獨醒。"]'),
('48c4d26c-03d1-46a4-8f36-e752a662e3ca','臨高臺','沈濬','宋','宋诗','song-poetry','','[]','上臺意悲傷，下臺夢顛倒。',48,'全唐诗/poet.song.110000.json','["上臺意悲傷，下臺夢顛倒。", "不緣臺高下，心腸自草草。", "臺下東西水，水繞南北道。", "一水一重山，紅顔望中老。"]'),
('55b84166-5383-49db-8cf0-d0d17dff575d','顔魯公祠','胡舜舉','宋','宋诗','song-poetry','','[]','立廟本來皆可紀，凜然英烈殆天啟。',128,'全唐诗/poet.song.110000.json','["立廟本來皆可紀，凜然英烈殆天啟。", "年垂八十官太師，平生所欠惟死爾。", "分甘一死鴻毛輕，舉世俗子何用嗔。", "誰知我公本不死，眉間生氣猶崢嶸。", "堂堂十老皆人傑，逢辰遇合稷與契。", "儼然玉立配我公，忠義文章兩奇絕。", "我來摩挲讀豐碑，扛鼎筆力猶精奇。", "定應神物常護持，勁直千載垂良規。"]'),
('e56715f3-430c-4dc8-80e6-1c5f8c250a11','重過龍居寺','劉政','宋','宋诗','song-poetry','','[]','重來舊遊處，觸目景添幽。',48,'全唐诗/poet.song.110000.json','["重來舊遊處，觸目景添幽。", "故墨猶餘迹，忠魂已斷頭。", "疎鐘號暮雨，枯木響殘秋。", "欲訴愁人意，頻懷杞國憂。"]'),
('e21ae19a-6633-4413-8284-919c947f9bc7','遊大滌山','陳宗古','宋','宋诗','song-poetry','','[]','洞天三十六，奇邃此無儔。',48,'全唐诗/poet.song.110000.json','["洞天三十六，奇邃此無儔。", "笙鶴有時下，神仙何處遊。", "巖花自照水，谷鳥不啼秋。", "盡日松陰底，閑聽寒澗流。"]'),
('d5c6c273-f021-4582-9e36-134109d983ce','遊洞霄','陳宗古','宋','宋诗','song-poetry','','[]','閑訪洞霄宮，幽奇景莫窮。',48,'全唐诗/poet.song.110000.json','["閑訪洞霄宮，幽奇景莫窮。", "溪山雖極遠，巖穴自相通。", "若不尋塵外，無由到此中。", "高真在何處，笑我白頭翁。"]'),
('48529ea3-8a33-41cb-94ac-c9f52fdbcd16','陽關詞','陳剛中','宋','宋诗','song-poetry','','[]','客舍休悲柳色新，東西南北一般春。',32,'全唐诗/poet.song.110000.json','["客舍休悲柳色新，東西南北一般春。", "若知四海皆兄弟，何處相逢非故人。"]'),
('b3ebf6a3-4569-4363-ba6a-b09ac4494b0c','石材廟題柱','陳剛中','宋','宋诗','song-poetry','','[]','疏爵新剛應，論功舊石材。',48,'全唐诗/poet.song.110000.json','["疏爵新剛應，論功舊石材。", "能形文母夢，還訝佞人來。", "海市爲誰出，衡雲豈自開。", "乞靈如見告，逐客幾時回。"]'),
('a651784c-2825-4651-a77c-adaee553b24d','視澇','陳剛中','宋','宋诗','song-poetry','','[]','暨陽古澤中，今歲仍大水。',156,'全唐诗/poet.song.110000.json','["暨陽古澤中，今歲仍大水。", "舟行民田中，一浪四十里。", "農夫相對泣，父子饑欲死。", "酷吏亦何心，誅求殊未已。", "豈繄竭膏血，直欲剝膚髓。", "哀此無告民，有生皆赤子。", "天災自流行，助虐亦何理。", "我愧才術疎，陸陸佐小壘。", "熟視不能救，有淚空如灑。", "皇心念下民，惻怛形詔旨。", "丁寧既諄複，象魏幾黄紙。", "要須盡蠲除，仰稱德意美。", "人微言或棄，歸休從此始。"]'),
('d0a140d8-408f-449a-90c3-27eebdbe6785','傷春','俞處俊','宋','宋诗','song-poetry','','[]','黏天芳草綠蒙茸，久客傷心望不窮。',32,'全唐诗/poet.song.110000.json','["黏天芳草綠蒙茸，久客傷心望不窮。", "山色自隨人遠近，鶑聲只在水西東。"]'),
('57cf7468-72dc-4c7c-94aa-f7389aefb763','搜春','俞處俊','宋','宋诗','song-poetry','','[]','千林欲暗稻秧雨，三月尚寒花信風。',32,'全唐诗/poet.song.110000.json','["千林欲暗稻秧雨，三月尚寒花信風。", "九節老筇應不惜，步隨流水看殘紅。"]'),
('7f1ed3fd-ff9d-42e6-9379-7b4b857c4f7e','句','俞處俊','宋','宋诗','song-poetry','','[]','叫月子規喉舌冷，宿花蝴蝶夢魂香。',16,'全唐诗/poet.song.110000.json','["叫月子規喉舌冷，宿花蝴蝶夢魂香。"]'),
('fd89055c-6ef3-4a7c-8963-169725d1dfaa','補和州助教自况','張尚','宋','宋诗','song-poetry','','[]','老未脫場屋，揆才無寸長。',48,'全唐诗/poet.song.110000.json','["老未脫場屋，揆才無寸長。", "九重難射策，一命不爲郎。", "尚喜衫仍綠，仍憐牒是黄。", "活人何不可，政自有良方。"]'),
('32fb1884-01b8-4aa9-a6fd-ed25bd9142b5','劉帥畫道林冬景','王佐才','宋','宋诗','song-poetry','','[]','破墨方紈趣向深，烟巒幽景鎖冬陰。',64,'全唐诗/poet.song.110000.json','["破墨方紈趣向深，烟巒幽景鎖冬陰。", "溪頭雪細春生牖，岩脚風清晝滿襟。", "千里斷雲藏片石，一江流水映疎林。", "長沙妙跡誰傳寶，龍閣精神學士心。"]'),
('f61f2f5c-8e84-4f56-891d-ad68461fe033','答秦兵部求墨竹  其一','王佐才','宋','宋诗','song-poetry','','[]','夜到茆亭近竹籬，影隨寒月下苔墀。',32,'全唐诗/poet.song.110000.json','["夜到茆亭近竹籬，影隨寒月下苔墀。", "吟餘未懶蕭疎興，曾寫離披一兩枝。"]'),
('ce82ab75-585b-42a1-9a16-f63428d45739','答秦兵部求墨竹  其二','王佐才','宋','宋诗','song-poetry','','[]','墨傳高節未爲精，虛辱佳篇拂素屏。',32,'全唐诗/poet.song.110000.json','["墨傳高節未爲精，虛辱佳篇拂素屏。", "不敢持毫强羞縮，喜公心已厭丹青。"]'),
('f81dab9d-5680-4a4a-966b-d921df9eb7dc','贈徐微中畫龍','王佐才','宋','宋诗','song-poetry','','[]','陰陽變化萬物從，其間至神惟真龍。',192,'全唐诗/poet.song.110000.json','["陰陽變化萬物從，其間至神惟真龍。", "庸夫俗眼不得見，或躍或潜無定跡。", "後來高士探元窟，素縑摹畫求形容。", "在昔擅名能幾人，爭爲妍巧誇殊功。", "東朐徐氏奮奇趣，俊筆醉揮欺古風。", "爲余好事輒寫寄，老鱗蒼鬣驚盲聾。", "怒摶滄海噴白浪，暗拖暮雨橫長空。", "雙雙頭角戰初罷，奔騰半沒寒雲中。", "只恐霹靂生坐上，爪牙活動拏寰穹。", "軒昂當世稱獨步，貴臣褒譽聞宸聰。", "黄金扇成爭進入，雄聲一日喧深宮。", "從此毫端愈珍重，千歲萬歲傳無窮。"]'),
('9a45e98a-1fd2-4d5a-b454-df4072ca0de1','畫虎','王佐才','宋','宋诗','song-poetry','','[]','炳毛威骨自精神，好祝提毫點刷人。',32,'全唐诗/poet.song.110000.json','["炳毛威骨自精神，好祝提毫點刷人。", "縱使不成猶勝狗，休添角翼亂天真。"]'),
('7f56e0cb-2b94-407a-9976-bc2ba16844a2','贈曇潤畫鶉','王佐才','宋','宋诗','song-poetry','','[]','飲啄飛鳴各後先，當時操筆想中傳。',32,'全唐诗/poet.song.110000.json','["飲啄飛鳴各後先，當時操筆想中傳。", "生來野態無拘束，萬里秋風自在天。"]'),
('d7f48208-4e01-49b0-b1de-f5099f6fbe7e','贈徐子虛畫魚','王佐才','宋','宋诗','song-poetry','','[]','我嘗放意遊江湖，喜從釣叟觀真魚。',208,'全唐诗/poet.song.110000.json','["我嘗放意遊江湖，喜從釣叟觀真魚。", "有時臨溪行復坐，秋水無風魚自如。", "鱗鱗鬣滑隨上下，回旋戲躍形皆殊。", "兩兩相逢若對語，聚頭戢戢摇雙鬚。", "忽然散漫皆游去，一半掉尾潜菰蒲。", "往來得所弄晴色，圓波觸動生浮珠。", "困依垂楊看不足，盡日忘歸誰與俱。", "自從北走塵土窟，十年不復瞻蓴鱸。", "憑誰畫出江湖趣，東海今聞徐子虛。", "毫端奪得生時意，京師好事爭傳摹。", "寫成雙幅輒遺我，展舒活動驚堂隅。", "窮搜前古少奇筆，此本只恐人間無。", "任教涸轍强濡沫，對面相忘千里書。"]'),
('baad46b2-ac22-4307-af36-d7bd337b17ed','題織女祠','范某','宋','宋诗','song-poetry','','[]','商飈初至月埋輪，烏鵲橋邊綽約身。',32,'全唐诗/poet.song.110000.json','["商飈初至月埋輪，烏鵲橋邊綽約身。", "聞道佳期唯一夕，因何朝暮對斯人。"]'),
('a4d06934-5107-485b-af19-8c42fb7214ed','句','歐陽凱士','宋','宋诗','song-poetry','','[]','冰姿元住藐姑山。',8,'全唐诗/poet.song.110000.json','["冰姿元住藐姑山。"]'),
('a21e8129-dd66-44d0-892e-ba17887544aa','送樞密使樓先生還鄉','王用','宋','宋诗','song-poetry','','[]','輔治皇朝已有年，一朝辭老意乾乾。',64,'全唐诗/poet.song.110000.json','["輔治皇朝已有年，一朝辭老意乾乾。", "滿京朱紫咸懷德，設席城門表大賢。", "別酒斟來須罄盞，陽關迭唱促開船。", "于今解職歸田里，指日丹書下九天。"]'),
('ac9f144c-c793-4405-8bb8-021dd841b244','絕句','尼正覺','宋','宋诗','song-poetry','','[]','春朝湖上風兼雨，世事如花落又開。',32,'全唐诗/poet.song.110000.json','["春朝湖上風兼雨，世事如花落又開。", "退省閉門真樂處，閑雲終日去還來。"]'),
('c1e94530-c34f-43d1-887c-49122ce0774e','句','傅雱','宋','宋诗','song-poetry','','[]','半淡半濃資眺望，似明似晦喜登臨。',16,'全唐诗/poet.song.110000.json','["半淡半濃資眺望，似明似晦喜登臨。"]'),
('2b607d52-74c9-449d-84ef-739e99c82b0b','送別任龍圖','史才','宋','宋诗','song-poetry','','[]','江上飛檣高數尋，西風客路思難禁。',64,'全唐诗/poet.song.110000.json','["江上飛檣高數尋，西風客路思難禁。", "三千奏議曾經國，十萬兵屯已屬心。", "官驛疏梅春意足，楚天孤鶩曉煙沉。", "閩南君去才稱最，慰我秋鴻達好音。"]'),
('54aef733-da2e-41e1-b6b9-90ec70c3eea3','過蔣學正三徑庵','史才','宋','宋诗','song-poetry','','[]','紛紛處世羨鳴珂，君隠考槃詩獨哦。',64,'全唐诗/poet.song.110000.json','["紛紛處世羨鳴珂，君隠考槃詩獨哦。", "三徑早知皆坦路，一庵聊復障頹波。", "田園無悔歸家晚，松柏存看繞舍多。", "笑我身閑閑未得，不知何日再相過。"]'),
('1a61dc90-2e53-4c87-93d2-4a3fa04863f4','雪竇飛雪亭','史才','宋','宋诗','song-poetry','','[]','蒼岷萬仞起巖巒，潺瀑霏霏盡日寒。',32,'全唐诗/poet.song.110000.json','["蒼岷萬仞起巖巒，潺瀑霏霏盡日寒。", "倒瀉銀河拖白練，人間應作六花看。"]'),
('31ca5471-968e-4cd0-8476-2aa6cf73e189','贈邕管察推陳仲輔  其一','陳鵬飛','宋','宋诗','song-poetry','','[]','闌干一幅鵝溪絹，中有五箴排小篆。',160,'全唐诗/poet.song.110000.json','["闌干一幅鵝溪絹，中有五箴排小篆。", "古字今文認未了，火劑針鋩俱瞑眩。", "平生卷軸有膏肓，首尾年來逾錯亂。", "剩儲藥物走醫門，掉頭嘔冷不下咽。", "一落泥頭千丈强，謝君欲拯非手援。", "銀鈎小變科斗文，挂我牀頭星斗爛。", "退之處士陽冰手，驅逐習氣車輪轉。", "光芒照耀肝膽醒，兩眼頻看淚如霰。", "門前惡草鋤又生，我病七年行復玩。", "會須著意課兒童，日日牀頭誦千遍。"]'),
('c717cc64-1e7a-48d7-9ab9-958dd2c3ec02','贈邕管察推陳仲輔  其二','陳鵬飛','宋','宋诗','song-poetry','','[]','幕下誰人識杲之，微聞贊畫向蓮池。',64,'全唐诗/poet.song.110000.json','["幕下誰人識杲之，微聞贊畫向蓮池。", "登樓不恨鄉關遠，拄笏只言山色奇。", "直道自能消鬼魅，高人何處不軒羲。", "它年坐上話銅狄，可是蓬萊清淺時。"]'),
('8859ab51-5827-4f56-b693-d6d448462806','卓錫泉','陳鵬飛','宋','宋诗','song-poetry','','[]','披沙覓山泉，不知泉在師錫端。',78,'全唐诗/poet.song.110000.json','["披沙覓山泉，不知泉在師錫端。", "借師錫端卓白石，不見師泉見山錫。", "須彌芥子本無別，離一離二別胡越。", "我師胡越俱一家，一念遍滿恒河沙。", "沙河現作天人相，一杯普供人天餉。"]'),
('9c3c0814-4b16-4e67-be94-da846186a853','惠州作','陳鵬飛','宋','宋诗','song-poetry','','[]','手擷春畦爪甲香，黄荑紫筍快先嘗。',32,'全唐诗/poet.song.110000.json','["手擷春畦爪甲香，黄荑紫筍快先嘗。", "我今駢邑無三百，只有園蔬一味長。"]'),
('bd2ce2b5-18e6-4905-8750-141036b75e7f','詠才德','魯訔','宋','宋诗','song-poetry','','[]','韻如風蟬蛻塵垢，氣如春容在楊柳。',32,'全唐诗/poet.song.110000.json','["韻如風蟬蛻塵垢，氣如春容在楊柳。", "風流翰墨俱細事，自是吾家道門友。"]'),
('4e68be30-7eda-4a5d-a04f-3d6fc05ce682','觀武侯陣圖','魯訔','宋','宋诗','song-poetry','','[]','西川漢鼎倚綸巾，翠石纍纍作陣新。',64,'全唐诗/poet.song.110000.json','["西川漢鼎倚綸巾，翠石纍纍作陣新。", "一夜掃雲驚虎旅，九天飛雨泣龍鱗。", "當年已落中原膽，今日猶憐故國身。", "曾踏斜陽看舊壘，英雄千古只伊人。"]'),
('e5193ecf-06e5-4e9c-b23e-8cd51635e4f6','春詞','魯訔','宋','宋诗','song-poetry','','[]','疊穎叢條翠欲流，午陰濃處聽鳴鳩。',32,'全唐诗/poet.song.110000.json','["疊穎叢條翠欲流，午陰濃處聽鳴鳩。", "兒童賭罷榆錢去，狼藉春風漫不收。"]'),
('add8d641-ab09-4e45-8701-2c217edeb589','爽軒','方師尹','宋','宋诗','song-poetry','','[]','鶴嶺重登不作難，自緣蘿月喜同攀。',64,'全唐诗/poet.song.110000.json','["鶴嶺重登不作難，自緣蘿月喜同攀。", "勝遊不減謝安石，佳士況逢元魯山。", "眼底更無塵事擾，窗開又得許時閒。", "丁仙已有歸來約，他日尋盟共往還。"]'),
('c0ff471c-f00e-4457-bf75-8550970ae407','再扈從游小山二首  其一','過孟玉','宋','宋诗','song-poetry','','[]','中官促召走雙驂，詔許從游聖澤覃。',64,'全唐诗/poet.song.110000.json','["中官促召走雙驂，詔許從游聖澤覃。", "歷覽仙山瞻鳳閣，徑行禁籞識龍潭。", "萬方寧謐宜遊豫，一曲昇平樂宴酣。", "淺薄承恩愧無補，願歌風雅繼周南。"]'),
('8a00cc22-177d-4bd7-a57b-a59729d4461d','再扈從游小山二首  其二','過孟玉','宋','宋诗','song-poetry','','[]','仙闕岧嶤紫翠凝，蓬萊樓觀喜重登。',64,'全唐诗/poet.song.110000.json','["仙闕岧嶤紫翠凝，蓬萊樓觀喜重登。", "桫欏樹老當金殿，靈壁峰高倚玉繩。", "輦路苔深龍甃古，瀛洲風靜海波澄。", "分明記得經行處，曾侍君王到上層。"]'),
('c1545eb1-c6ad-4582-840e-856331c2448d','避地白巖山中書懷','吳說','宋','宋诗','song-poetry','','[]','胡虜憑陵甚，長驅青海邊。',48,'全唐诗/poet.song.110000.json','["胡虜憑陵甚，長驅青海邊。", "携家遭困頓，憂國憤迍邅。", "不省歲月換，徒驚花草鮮。", "到頭蘇息否，灑淚問蒼天。"]'),
('662876fb-6035-4638-9395-d2e4c2be25fe','次廉布書事三首呈郎中機宜詩韻  其一','吳說','宋','宋诗','song-poetry','','[]','當代青雲士，皆言子獨賢。',48,'全唐诗/poet.song.110000.json','["當代青雲士，皆言子獨賢。", "異時猶未遇，多難更堪憐。", "妙契環中趣，飽參方外禪。", "海涯孤絕處，誰識孝廉船。"]'),
('97c9bde5-430e-4d27-9c39-6f9fa1679eab','次廉布書事三首呈郎中機宜詩韻  其二','吳說','宋','宋诗','song-poetry','','[]','區宇半荆棘，干戈猶未休。',48,'全唐诗/poet.song.110000.json','["區宇半荆棘，干戈猶未休。", "屢空無計奈，多病不禁愁。", "農具應須辦，朝簪便合投。", "全家耕谷口，一飽更何憂。"]'),
('006a674f-6f17-4aa8-be0c-4c4d4b2c4d17','次廉布書事三首呈郎中機宜詩韻  其三','吳說','宋','宋诗','song-poetry','','[]','棲遁雲巖下，無人到此邊。',48,'全唐诗/poet.song.110000.json','["棲遁雲巖下，無人到此邊。", "階庭穿蚓穴，窗戶蠹蝸涎。", "寂寞春將老，淹留月再絃。", "羈愁知幾許，素髮挽華巔。"]'),
('7e5e01eb-ce90-46c7-af46-806dca98a29f','山中元夕','吳說','宋','宋诗','song-poetry','','[]','憶昔觀燈夜，維舟天漢灣。',48,'全唐诗/poet.song.110000.json','["憶昔觀燈夜，維舟天漢灣。", "千官環鳳輦，萬炬轉鼇山。", "異縣方營窟，佳辰獨掩關。", "悲凉追往事，華髮坐來斑。"]'),
('cd30b555-a21b-49f8-bbfb-1e7401c513ec','題梁王寺清辯大師房','吳說','宋','宋诗','song-poetry','','[]','雲收霧落天圍浄，乞與游人眼界寬。',32,'全唐诗/poet.song.110000.json','["雲收霧落天圍浄，乞與游人眼界寬。", "獨恨不當新雪霽，月明來此倚闌干。"]'),
('dc5f39ad-4a9b-49df-9632-9a53eb4c867f','仙都山','吳說','宋','宋诗','song-poetry','','[]','佳住從來說鼎湖，茲遊直欲到清都。',64,'全唐诗/poet.song.110000.json','["佳住從來說鼎湖，茲遊直欲到清都。", "參天玉筍千尋許，墮地金蓮十丈無。", "江觀便思眠一柱，海山今喜識方壺。", "直須買取鵝溪絹，要畫滄洲水墨圖。"]'),
('2a9ac12d-e4e1-43cf-8b6e-bff1c5579d6c','題清芬閣','吳說','宋','宋诗','song-poetry','','[]','乃祖飛英標萬古，後來奕葉盛三吳。',64,'全唐诗/poet.song.110000.json','["乃祖飛英標萬古，後來奕葉盛三吳。", "傳家孫達吾何慊，配食子陵德不孤。", "秀句至今輝簡表，故山從昔鎖松梧。", "他年我欲修清供，一盞寒泉一束芻。"]'),
('44a00487-85cf-48e8-9c82-fde2df93e333','酬次李辰甫所寄三首  其一','吳說','宋','宋诗','song-poetry','','[]','近知盡室入烟霞，兒女甘貧慣食鮭。',64,'全唐诗/poet.song.110000.json','["近知盡室入烟霞，兒女甘貧慣食鮭。", "方外何人差可友，歲闌底處定爲家。", "江城潮盛漫秋鹵，驛道風高捲霽沙。", "子拾墮樵歸未得，能無借地種桃花。"]'),
('d1d10a53-72cd-4bf5-a9b9-9de53e3a30db','酬次李辰甫所寄三首  其二','吳說','宋','宋诗','song-poetry','','[]','桐花竹實幾時生，桑野秋枯繭未成。',64,'全唐诗/poet.song.110000.json','["桐花竹實幾時生，桑野秋枯繭未成。", "肯信饑寒能累道，唯餘寂寞許尋盟。", "年顔已愧神仙事，江海難忘故舊情。", "何日往來同井陘，清談清坐到天明。"]'),
('53adba90-f55a-40f0-8d1c-a55ca1d2b9f1','酬次李辰甫所寄三首  其三','吳說','宋','宋诗','song-poetry','','[]','扁舟東下初乘興，明月南飛竟失羣。',64,'全唐诗/poet.song.110000.json','["扁舟東下初乘興，明月南飛竟失羣。", "田父語言時近道，世人嘲笑尚論文。", "九山歛氣橫寒野，一塢朝陽聚暖雲。", "勝處借人教暫看，後來何必問靈氛。"]'),
('b1adb046-6648-4d43-9dfd-5a6e1f266e47','題義節夫人傳  其一','吳說','宋','宋诗','song-poetry','','[]','國步阽危古所稀，曠無仗節不勝譏。',32,'全唐诗/poet.song.110000.json','["國步阽危古所稀，曠無仗節不勝譏。", "得夫人輩戡多難，撥亂興衰亦庶幾。"]'),
('5581c7f1-b345-481d-a0b8-88721e7e8e68','題義節夫人傳  其二','吳說','宋','宋诗','song-poetry','','[]','丈夫效死以成人，何事臨危反愛身。',32,'全唐诗/poet.song.110000.json','["丈夫效死以成人，何事臨危反愛身。", "有靦閨門全節義，傷今思古淚霑巾。"]'),
('e63e28cb-719b-4880-8892-81e8d92b5f31','句  其一','吳說','宋','宋诗','song-poetry','','[]','出峽名標第一樓。',8,'全唐诗/poet.song.110000.json','["出峽名標第一樓。"]'),
('48bef281-8b6b-48c3-ab98-00bea2da11cc','句  其二','吳說','宋','宋诗','song-poetry','','[]','越山長青水長白，越人長家山水國。',16,'全唐诗/poet.song.110000.json','["越山長青水長白，越人長家山水國。"]'),
('dc927793-a5f3-4566-940d-82a8a19cb897','從吳傅朋遊芝山登五老亭以駕言出遊分韻賦詩','向𤃃','宋','宋诗','song-poetry','','[]','茲山何巍巍，氣欲等嵩華。',120,'全唐诗/poet.song.110000.json','["茲山何巍巍，氣欲等嵩華。", "從公二三子，勝日飽閑暇。", "躋攀謝車輿，自辦兩不借。", "捫蘿覓幽磴，行椒得孤榭。", "側送夕陽移，俯視高鳥下。", "登臨記曩昔，歲月驚代謝。", "却數一周星，復命千里駕。", "身從泛梗流，事與浮雲化。", "朅來共一尊，似爲天所赦。", "明發還問塗，合離足悲叱。"]'),
('a15e836d-0849-4391-a132-5f40db3e433c','題吳傅朋遊絲書','向𤃃','宋','宋诗','song-poetry','','[]','先生著名節，百世追延陵。',48,'全唐诗/poet.song.110000.json','["先生著名節，百世追延陵。", "我評先生賢，不以能書稱。", "功成磨蒼崖，盛德頌日昇。", "勿書凌雲榜，華顛踏高層。"]'),
('f97d8a48-fff2-43e6-b641-57e7d60b8aeb','句','向𤃃','宋','宋诗','song-poetry','','[]','脩篁萬箇玉生煙，芳木千名花欲語。',16,'全唐诗/poet.song.110000.json','["脩篁萬箇玉生煙，芳木千名花欲語。"]'),
('97daddc7-a40a-4f26-9fdb-71afdde6da57','句','劉卓','宋','宋诗','song-poetry','','[]','傍人未必知心事。',8,'全唐诗/poet.song.110000.json','["傍人未必知心事。"]'),
('fa76782f-bb9f-48f1-a350-961ef5ea3975','次唐彥猷顧亭林韻','宋輝','宋','宋诗','song-poetry','','[]','昔時高士宅，今日梵王居。',48,'全唐诗/poet.song.110000.json','["昔時高士宅，今日梵王居。", "樓影銜山遠，鍾聲隔岸疎。", "風流嗟往事，精爽閟遺墟。", "回首烏衣巷，凋零兵火餘。"]'),
('e9776b4c-ca2f-485e-afae-2e82d16bac88','贈別通古','周金','宋','宋诗','song-poetry','','[]','良人輕一別，奄忽幾經秋。',48,'全唐诗/poet.song.110000.json','["良人輕一別，奄忽幾經秋。", "明月望不見，白雲徒自愁。", "征鴻悲北渡，江水奈東流。", "會話知何日，如今已白頭。"]'),
('feace4f0-9400-4bcf-919b-561ef42f3fa0','題慈雲院雙松亭','晁公爲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','雲閒龍躩千尋榦，地底雷奔萬仞泉。',32,'全唐诗/poet.song.110000.json','["雲閒龍躩千尋榦，地底雷奔萬仞泉。", "寄語廬山舊游客，箇中端不減棲賢。"]'),
('cb125d96-d330-4976-86dd-4a8b15431f05','劉阮洞','晁公爲','宋','宋诗','song-poetry','','[]','桃花開已繁，溪水濺濺去。',24,'全唐诗/poet.song.110000.json','["桃花開已繁，溪水濺濺去。", "不見持盃人，自歎來何暮。"]'),
('9daaa2d0-e9f6-4256-b909-ca75c0f77d1b','東湖','尼妙雲','宋','宋诗','song-poetry','','[]','山環湖水水環山，短艇白鷗窗几間。',32,'全唐诗/poet.song.110000.json','["山環湖水水環山，短艇白鷗窗几間。", "野外更將供給至，飽參著得十僧閑。"]'),
('b7af0233-f653-4969-b137-5296f04453aa','句','袁坰','宋','宋诗','song-poetry','','[]','雖云誤失風霜操，不替調羹爲子賢。',16,'全唐诗/poet.song.110000.json','["雖云誤失風霜操，不替調羹爲子賢。"]'),
('0cc31ee1-0547-485d-b2d3-a14761466036','題漠口鋪','韓玉父','宋','宋诗','song-poetry','','[]','南行踰萬山，復入武陽路。',60,'全唐诗/poet.song.110000.json','["南行踰萬山，復入武陽路。", "黎明與雞興，理髮漠口鋪。", "旴江在何所，極目烟水暮。", "生平良自珍，羞爲浪子婦。", "知君非秋胡，强顔且西去。"]'),
('8fd3aa6f-c4cb-460c-b3bc-8cc8cc84f678','寄良人','汪氏','宋','宋诗','song-poetry','','[]','旅食京華歲月多，聖賢事業竟如何。',32,'全唐诗/poet.song.110000.json','["旅食京華歲月多，聖賢事業竟如何。", "明年佇聽泥金報，閑把關雎獨自歌。"]'),
('36b8d11c-34a0-43cb-a9d0-15a6b8adee22','餞范子','胡景裕','宋','宋诗','song-poetry','','[]','當年邂逅帝王畿，歲月侵尋若電飛。',64,'全唐诗/poet.song.110000.json','["當年邂逅帝王畿，歲月侵尋若電飛。", "學士榮除青鎖闥，故人老著白麻衣。", "尊前且鬭閑身健，眼底休論往事非。", "第恐鋒車促嚴召，片帆明發不輕違。"]'),
('b0ef6ba4-d17f-4c5a-9993-14ad1d2113d9','南山留題','馮晦','宋','宋诗','song-poetry','','[]','南山之景幽且清，臺亭上下知幾層。',32,'全唐诗/poet.song.110000.json','["南山之景幽且清，臺亭上下知幾層。", "王吳妙手寫不得，若非造物其誰能。"]'),
('93179f67-45b0-4e11-adb7-1c4a0f1d3d03','水心新居','趙汝鐸','宋','宋诗','song-poetry','','[]','開扉待嘉客，沽酒解閑愁。',48,'全唐诗/poet.song.110000.json','["開扉待嘉客，沽酒解閑愁。", "半夜秋霖歇，滿塘寒水流。", "風聲生葉底，月色在沙頭。", "憶著鱸魚美，松江有舊游。"]'),
('5aee012f-3773-4165-a45c-b35ade8f6c66','過訪詩妓謝金蓮見庭中紅梨花盛開因賦','趙汝州','宋','宋诗','song-poetry','','[]','換却冰肌玉骨胎，丹心吐出異香來。',32,'全唐诗/poet.song.110000.json','["換却冰肌玉骨胎，丹心吐出異香來。", "武陵溪畔人休說，只恐夭桃不敢開。"]'),
('9638d8fc-a44f-4f53-a5b5-5e4f5b1883b8','雪','趙汝鋌','宋','宋诗','song-poetry','','[]','病倦扶危坐，起看天雨花。',48,'全唐诗/poet.song.110000.json','["病倦扶危坐，起看天雨花。", "蹇馿東野句，破屋玉川家。", "勇羨穿籬犬，饑憐噪樹鴉。", "龍山雲壑勝，冰柱憶劉叉。"]'),
('71ef8411-c895-4800-a42b-4a908b27da14','題臨江清遠軒壁','趙汝鋌','宋','宋诗','song-poetry','','[]','江清疑可濯吾纓，小泊扁舟繞寺行。',32,'全唐诗/poet.song.110000.json','["江清疑可濯吾纓，小泊扁舟繞寺行。", "對岸丹楓尋不見，雨雲遮斷古蕭城。"]'),
('a9a6726c-0a97-44e8-bdd3-bb9d109b6e2a','烏石驛','趙汝鋌','宋','宋诗','song-poetry','','[]','落日銜山烏石堠，淡煙籠月白茅坪。',32,'全唐诗/poet.song.110000.json','["落日銜山烏石堠，淡煙籠月白茅坪。", "乍離城市雖蕭索，喜是還家第一程。"]'),
('e55023c5-8bde-4a62-a638-72c53c87aa4d','廬山卧龍庵','趙汝鋌','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','一線飛泉遶碧蘿，白雲來往暗山阿。',32,'全唐诗/poet.song.110000.json','["一線飛泉遶碧蘿，白雲來往暗山阿。", "雨中貪共樵人語，行過庵前路忽多。"]'),
('6805b678-7f2c-48cf-84f5-252b770b1840','雲峰寺','趙汝鋌','宋','宋诗','song-poetry','','[]','好峰藏寺背，此景只僧知。',48,'全唐诗/poet.song.110000.json','["好峰藏寺背，此景只僧知。", "古樹侵天直，寒泉入澗遲。", "深行尋舊址，久竚讀荒碑。", "時有僊人過，靈風滿路吹。"]'),
('35dbbb1d-3e30-4822-9a02-4b6f73efd3a2','送澄古潭由豫章歸鑑湖','趙汝鋌','宋','宋诗','song-poetry','','[]','數椽書屋守蛛絲，一出三年夢見稀。',32,'全唐诗/poet.song.110000.json','["數椽書屋守蛛絲，一出三年夢見稀。", "寄語家僮日開戶，莫妨燕子認巢歸。"]'),
('36184dc3-ed95-41bc-8d39-be2b87aca709','謝友人惠襪布','趙汝鋌','宋','宋诗','song-poetry','','[]','客裏行終日，難逢識面人。',48,'全唐诗/poet.song.110000.json','["客裏行終日，難逢識面人。", "所交新有幾，相語又俱貧。", "句□推敲長，情增邂逅親。", "絲絇到雙足，那敵襪材真。"]'),
('f7cd34c1-8c90-424f-97b9-b4345a7e387b','金陵作','趙汝鎣','宋','宋诗','song-poetry','','[]','龍虎帝王宅，鳳凰僊子臺。',48,'全唐诗/poet.song.110000.json','["龍虎帝王宅，鳳凰僊子臺。", "六朝遺事冷，八月夜潮回。", "隴雁秋仍到，江花晚自開。", "憑高一樽酒，何代獨無才。"]'),
('cff90dc3-1deb-411b-94fd-276725a104f4','題龍君祠','趙汝鎣','宋','宋诗','song-poetry','','[]','萬頃鯨波內，巋然一石山。',48,'全唐诗/poet.song.110000.json','["萬頃鯨波內，巋然一石山。", "江神擎貝闕，湘女露雲鬟。", "客棹蒼茫外，祇園紫翠間。", "我來嗟索寞，登眺却忘還。"]'),
('8b2794eb-222c-48ab-b1b4-f455f0943b34','宿山隠齋','趙汝旗','宋','宋诗','song-poetry','','[]','平生悅山隠，一室容我借。',48,'全唐诗/poet.song.110000.json','["平生悅山隠，一室容我借。", "弄泉掬明月，坐石延清話。", "既調松下琴，復得松風和。", "仙人搗藥禽，獨叫青山夜。"]'),
('fa372859-139d-4986-9b91-4388ca64acc2','乞貲曹勣','釋法空','宋','宋诗','song-poetry','','[]','一夢江湖已十春，芒鞋不踐馬頭塵。',64,'全唐诗/poet.song.110000.json','["一夢江湖已十春，芒鞋不踐馬頭塵。", "只知今日了今日，豈料一身愁一身。", "南阮固應慚北阮，越人那得累秦人。", "西風不但吹游子，吹老天涯白髮親。"]'),
('9ba125e0-0f7e-4bdc-becc-1afe12ea78da','疊石庵','釋德止','宋','宋诗','song-poetry','','[]','疊石峰之顛，下瞰楊梅澗。',24,'全唐诗/poet.song.110000.json','["疊石峰之顛，下瞰楊梅澗。", "平地數畝餘，水石光燦爛。"]'),
('d7c60ab4-d420-46c6-bdc9-8a7a208383d8','偈','釋德止','宋','宋诗','song-poetry','','[]','不因言句不因人，不因物色不因聲。',32,'全唐诗/poet.song.110000.json','["不因言句不因人，不因物色不因聲。", "夜半吹燈方就枕，忽然這裏已天明。"]'),
('823a24fc-4dab-457b-aa5d-707e9541b310','浯溪圖','釋德止','宋','宋诗','song-poetry','','[]','夷途勿拋控，拋控馬多失。',168,'全唐诗/poet.song.110000.json','["夷途勿拋控，拋控馬多失。", "挹水勿極量，極量器多溢。", "安史起天寶，轉戰竟奔北。", "辭臣獻頌詩，要垂萬世則。", "一字堪白首，大書仍深刻。", "誰作浯溪圖，千里在咫尺。", "飛湍如有聲，旁匯浸層碧。", "巉絕半巖間，髣髴見鳥迹。", "不覺加手磨，真恐苔蘚沒。", "國姓前後異，天運古今一。", "向來文武才，坐籌或操筆。", "種種皆可稱，俯仰重歎息。", "願君寶此圖，置之丹粉壁。", "昔人如可作，想像壯胸臆。"]'),
('224b8d86-c768-45bf-b01f-b6929e6fee95','偈','釋善能','宋','宋诗','song-poetry','','[]','萬古長空，一朝風月。',38,'全唐诗/poet.song.110000.json','["萬古長空，一朝風月。", "不可以一朝風月昧却萬古長空，不可以萬古長空不明一朝風月。"]'),
('e90f5b7c-c2fd-4142-9e6e-519efab54cf4','頌古二首  其一','釋善能','宋','宋诗','song-poetry','','[]','古殿無人到者稀，蒲團端坐有誰知。',32,'全唐诗/poet.song.110000.json','["古殿無人到者稀，蒲團端坐有誰知。", "不因院主通消息，爭得寒光萬里輝。"]'),
('7ad42b88-ea83-4c73-86b6-34e599b0e8a2','頌古二首  其二','釋善能','宋','宋诗','song-poetry','','[]','西山路上有獼猴，嘯雨哀風動客愁。',32,'全唐诗/poet.song.110000.json','["西山路上有獼猴，嘯雨哀風動客愁。", "忽遇此林師子子，萬般伎倆一時休。"]'),
('626ddbc3-a867-48e6-b679-8e6b187200fd','栽松題石','釋天石','宋','宋诗','song-poetry','','[]','偃蓋覆巖石，歲寒傲霜雪。',24,'全唐诗/poet.song.110000.json','["偃蓋覆巖石，歲寒傲霜雪。", "深根蟠茯苓，千古飽風月。"]'),
('9f639f31-d3c2-45f0-88f4-8d995008ad80','長歌行','郭世模','宋','宋诗','song-poetry','','[]','若木無停陰，積石無還流。',72,'全唐诗/poet.song.110000.json','["若木無停陰，積石無還流。", "葵藿變旦莫，蟪蛄疑春秋。", "寸晷輕尺璧，神功寧九州。", "仰思坐待旦，禮樂隆成周。", "君子不可閒，努力崇嘉猷。", "當思竹帛載，不爲鬢髮羞。"]'),
('a8de3c6c-2b51-4d49-bf3d-f5649beaea77','短歌行','郭世模','宋','宋诗','song-poetry','','[]','天東銜燭龍，光景照四溟。',108,'全唐诗/poet.song.110000.json','["天東銜燭龍，光景照四溟。", "羲和攬龍轡，鞭策日夜征。", "露華以春暉，霜葉當秋零。", "危柱無弱絃，急轅無留旌。", "華髮不再綠，彫顔寧重榮。", "良辰足行樂，羈旅難爲情。", "烏程有美餉，爲人駐頹齡。", "玉指陳蘭藉，歌鍾閒鸞笙。", "短章可娛日，意氣聊相傾。"]'),
('f1108868-e4d6-42bd-81b7-39a40ba8cd7f','烏夜啼','郭世模','宋','宋诗','song-poetry','','[]','碧煙障樓天欲暮，飛烏夜集蕪城戍。',64,'全唐诗/poet.song.110000.json','["碧煙障樓天欲暮，飛烏夜集蕪城戍。", "雲外畢逋銜尾來，月明腷膊同枝語。", "樓中有人輟機杼，玉笙怨咽凝江霧。", "惆悵幽棲夜未闌，桂樹秋風蘭葉露。"]'),
('11b1c4f5-3ffe-4c53-be8f-afbbb2a298ec','題清芬閣','郭世模','宋','宋诗','song-poetry','','[]','視世軒裳一露螢，平生苦節抱遺經。',64,'全唐诗/poet.song.110000.json','["視世軒裳一露螢，平生苦節抱遺經。", "卧雲句好傳弟子，釣瀨名高齊客星。", "尚想臞儒在山澤，空留遺廟落丹青。", "發揮家傳標潜德，奕奕元孫有典刑。"]'),
('7a81bdc1-9c5d-4e16-9750-ae6b1b440949','楚州','沈長卿','宋','宋诗','song-poetry','','[]','楚州淮陰娑羅木，霜露榮倅今何如。',48,'全唐诗/poet.song.110000.json','["楚州淮陰娑羅木，霜露榮倅今何如。", "能令草木死不枯，當時爲有北海書。", "荒碑雨侵苔蘚濕，尚寫墨本傳東吳。"]'),
('31ec6bb3-29e1-4d8e-ad74-c20af9283811','題清芬閣','沈長卿','宋','宋诗','song-poetry','','[]','元英以隠名，務德以仕顯。',192,'全唐诗/poet.song.110000.json','["元英以隠名，務德以仕顯。", "人言不同調，是說一何淺。", "丈夫生世間，出處各有意。", "仕以行其道，隠以求其志。", "一以隠爲高，伊呂當不起。", "一以仕爲樂，夷齊不餓死。", "我觀二子心，舒卷如春雲。", "邂逅作霖雨，本是版築君。", "乃祖配子陵，桐江飽風月。", "乃孫擁麾幢，遺愛浹閩粵。", "相望二百年，家學留青編。", "冥鴻與棲鳳，進退兩俱賢。", "秋冬享烝嘗，瞻像不泚顙。", "獨抱元成經，肯作世南匠。", "種田刈禾黍，種圃收蘭芝。", "請誦裳華篇，有之以似之。"]'),
('3d4c02d2-1eb3-4c1f-9ea0-f5f080f4ae00','書壁四韻','沈長卿','宋','宋诗','song-poetry','','[]','約客探名勝，停輈得所欣。',48,'全唐诗/poet.song.110000.json','["約客探名勝，停輈得所欣。", "山寒多做雨，洞古不收雲。", "夜宿聽鳴麂，晨炊摘野芹。", "黄冠尤喜事，添炷石爐熏。"]'),
('438b35b3-2a9c-4524-8bce-3f8651e26ee6','句','沈長卿','宋','宋诗','song-poetry','','[]','翠蛾環坐憶洲錢。',8,'全唐诗/poet.song.110000.json','["翠蛾環坐憶洲錢。"]'),
('8cf0abee-f32b-4f75-bf30-171bef6aa117','贈明道人','施宜生','宋','宋诗','song-poetry','','[]','休論道骨與仙風，自許平生義與忠。',64,'全唐诗/poet.song.110000.json','["休論道骨與仙風，自許平生義與忠。", "千古已嘗窺治亂，一身何足計窮通。", "仰天但覺心如鐵，覽鏡猶欣髮未蓬。", "塵世紛紛千百輩，只君雙眼識英雄。"]'),
('a44a1274-202a-4322-850e-ce2832672d27','詩一首','施宜生','宋','宋诗','song-poetry','','[]','久坐鄉關夢已迷，歸來投宿舊沙溪。',64,'全唐诗/poet.song.110000.json','["久坐鄉關夢已迷，歸來投宿舊沙溪。", "一天風雨龍移穴，半夜林巒鳥擇棲。", "賣菜無人求好語，種瓜何地不成畦。", "男兒未老中原在，寄語鵾鷄莫浪啼。"]'),
('d1b1dc15-2386-45bf-80ae-b1b32dcb1820','嚴子陵釣臺','施宜生','宋','宋诗','song-poetry','','[]','懸崖斷壑少人蹤，只合先生卧此中。',64,'全唐诗/poet.song.110000.json','["懸崖斷壑少人蹤，只合先生卧此中。", "漢業已無一抔土，釣臺今是幾秋風。", "同學劉郎已冕旒，未應換與此羊裘。", "子雲到老不曉事，不信人間有許由。"]'),
('a3447e40-0d3f-46e7-b326-f3d1ce87907a','至黄州弔東坡','施宜生','宋','宋诗','song-poetry','','[]','文星落處天應泣，此老已知吾道窮。',32,'全唐诗/poet.song.110000.json','["文星落處天應泣，此老已知吾道窮。", "事業謾誇生仲達，功名猶忌死姚崇。"]'),
('af2f32c2-1252-4b22-bb5a-a7527eb4195a','題平沙落雁屏景','施宜生','宋','宋诗','song-poetry','','[]','江南江北八九月，葭蘆伐盡洲渚闊。',48,'全唐诗/poet.song.110000.json','["江南江北八九月，葭蘆伐盡洲渚闊。", "欲下未下風悠揚，影落寒潭三兩行。", "天涯是處有菰米，如何偏愛來瀟湘。"]'),
('7e26204a-0ebb-4b02-926c-1f5db434f0da','感春','施宜生','宋','宋诗','song-poetry','','[]','感事傷懷誰得知，故園閒日自暉暉。',64,'全唐诗/poet.song.110000.json','["感事傷懷誰得知，故園閒日自暉暉。", "江南地暖先花發，塞北天寒遲雁歸。", "夢裏江河依舊是，眼前阡陌似疑非。", "無愁只有雙蝴蝶，解趁殘紅作陣飛。"]'),
('c2e89a6e-aba6-4018-85a5-3b94d1322cd2','感錢王戰臺','施宜生','宋','宋诗','song-poetry','','[]','層層樓閣捧昭回，元是錢王舊戰臺。',64,'全唐诗/poet.song.110000.json','["層層樓閣捧昭回，元是錢王舊戰臺。", "山色不隨興廢去，水聲長逐古今來。", "年光似月生還沒，世事如花落又開。", "多少英雄無處問，夕陽行客自徘徊。"]'),
('a283be1c-62b5-4cbf-bb05-d19de9f47686','題將臺','施宜生','宋','宋诗','song-poetry','','[]','梅花摘索未全開，老倦無心上將臺。',32,'全唐诗/poet.song.110000.json','["梅花摘索未全開，老倦無心上將臺。", "人在江南望江北，征鴻時送客愁來。"]'),
('5c031d78-b759-40c3-9b1f-b7e5b8221101','題壁','施宜生','宋','宋诗','song-poetry','','[]','君子雖窮道不窮，人生自古有飄蓬。',64,'全唐诗/poet.song.110000.json','["君子雖窮道不窮，人生自古有飄蓬。", "文章筆下千堆錦，志氣胸中萬丈虹。", "大抵養龍須是海，算來棲鳳莫非桐。", "山東宰相關西將，俯仰懷賢倚暮風。"]'),
('105ee68f-0a79-4c1c-a5f3-f2b058aaea3b','柳','施宜生','宋','宋诗','song-poetry','','[]','魏王堤暗雨垂垂，還似春殘欲別時。',32,'全唐诗/poet.song.110000.json','["魏王堤暗雨垂垂，還似春殘欲別時。", "傳語西風且停待，黛殘黄淺不禁吹。"]'),
('89903fd0-d73d-4bb4-9c81-fec492daabe2','無題','施宜生','宋','宋诗','song-poetry','','[]','唱得新翻穩貼腔，阿誰能得肯雙雙。',32,'全唐诗/poet.song.110000.json','["唱得新翻穩貼腔，阿誰能得肯雙雙。", "天寧寺裏尊前月，分擘清寒入小窗。"]'),
('485db6e3-787f-4819-9f23-e22426927617','盆池','施宜生','宋','宋诗','song-poetry','','[]','盆池瀲灧蔭芭蕉，點水圓荷未出條。',32,'全唐诗/poet.song.110000.json','["盆池瀲灧蔭芭蕉，點水圓荷未出條。", "分得江湖好風景，斷雲飛去晚蕭蕭。"]'),
('b329d3d3-c21b-46ff-9326-73169caec49e','平陽書事','施宜生','宋','宋诗','song-poetry','','[]','春寒窣窣透春衣，沿路看花緩轡歸。',32,'全唐诗/poet.song.110000.json','["春寒窣窣透春衣，沿路看花緩轡歸。", "穿過水雲深密處，馬前蝴蜨作團飛。"]'),
('dd3854c4-0f43-4089-82c4-9de70266efb3','山谷草書','施宜生','宋','宋诗','song-poetry','','[]','行所當行止當止，錯亂中間有條理。',32,'全唐诗/poet.song.110000.json','["行所當行止當止，錯亂中間有條理。", "意溢毫摇手不知，心自書空不書紙。"]'),
('bc90bca6-b61f-4c5e-921c-424777f73826','社日  其一','施宜生','宋','宋诗','song-poetry','','[]','濁澗迴湍激，青烟弄晚暉。',48,'全唐诗/poet.song.110000.json','["濁澗迴湍激，青烟弄晚暉。", "緣隨春酒熟，分與故山違。", "社鼓喧林莽，孤城隠翠微。", "山花羞未發，燕子喜先歸。"]'),
('54e63a7c-19b6-42b9-a4a4-2b609059e548','社日  其二','施宜生','宋','宋诗','song-poetry','','[]','割少詼諧語，分均宰制功。',48,'全唐诗/poet.song.110000.json','["割少詼諧語，分均宰制功。", "靈祇依古樹，醉叟泥村童。", "萬里開耕稼，三時順雨風。", "行春從此樂，著意酒杯中。"]'),
('a50a2dc9-c539-4777-b5f7-9ee12832a49b','含笑花','施宜生','宋','宋诗','song-poetry','','[]','百步清香透玉肌，滿堂和氣自心知。',32,'全唐诗/poet.song.110000.json','["百步清香透玉肌，滿堂和氣自心知。", "褰帷跛客相迎處，射雉春風得意時。"]'),
('1a23cd9b-c92e-4c75-abf0-ae8beee7b905','句  其一','施宜生','宋','宋诗','song-poetry','','[]','只因未有良媒在，直到如今萬萬秋。',16,'全唐诗/poet.song.110000.json','["只因未有良媒在，直到如今萬萬秋。"]'),
('1cc726a5-f1ef-43f4-90b8-6cc91658f9ed','句  其二','施宜生','宋','宋诗','song-poetry','','[]','朱門處處臨官道，流水年年繞禁宮。',16,'全唐诗/poet.song.110000.json','["朱門處處臨官道，流水年年繞禁宮。"]'),
('500e1511-74a9-410d-a9f4-c55ff5c245b6','句  其三','施宜生','宋','宋诗','song-poetry','','[]','臨池翕忽雲霧集，舞劍浩蕩波濤翻。',16,'全唐诗/poet.song.110000.json','["臨池翕忽雲霧集，舞劍浩蕩波濤翻。"]'),
('c2a89815-2cb1-42dc-ba97-086197c96772','偈','釋如哲','宋','宋诗','song-poetry','','[]','瑞巖長喚主人公，突出須彌最上峯。',32,'全唐诗/poet.song.110000.json','["瑞巖長喚主人公，突出須彌最上峯。", "大地掀翻無覓處，笙歌一曲畫樓中。"]'),
('d03ad1f1-e082-45ea-8994-a257be4e8bb2','句','欽宗','宋','宋诗','song-poetry','','[]','秋來一鳳向南飛。',8,'全唐诗/poet.song.110000.json','["秋來一鳳向南飛。"]'),
('7c1659bd-f19e-4b1f-bf13-b13b00701b3b','覽夢得所藏李伯時畫吳中三賢像因各書絕句 范蠡','趙楷','宋','宋诗','song-poetry','','[]','已將勳業等浮鷗，鳥盡弓藏見遠謀。',32,'全唐诗/poet.song.110000.json','["已將勳業等浮鷗，鳥盡弓藏見遠謀。", "越國江山留不住，五湖風月一扁舟。"]'),
('9215bedc-a699-4088-a82d-213b242d3aab','覽夢得所藏李伯時畫吳中三賢像因各書絕句 張翰','趙楷','宋','宋诗','song-poetry','','[]','西風淅淅動高梧，目送浮雲悟卷舒。',32,'全唐诗/poet.song.110000.json','["西風淅淅動高梧，目送浮雲悟卷舒。", "自是歸心感秋色，不應高興爲鱸魚。"]'),
('5a7f683a-6898-4146-b66b-f14bfbfe5c78','覽夢得所藏李伯時畫吳中三賢像因各書絕句 陸龜蒙','趙楷','宋','宋诗','song-poetry','','[]','杞菊蕭條遶屋春，不教鵝鴨惱比鄰。',32,'全唐诗/poet.song.110000.json','["杞菊蕭條遶屋春，不教鵝鴨惱比鄰。", "滿身花影猶沈醉，真是江湖一散人。"]'),
('41d05e9a-6fec-4ad4-8480-84e214e8d0ac','句','趙楷','宋','宋诗','song-poetry','','[]','正是霜高木落時。',8,'全唐诗/poet.song.110000.json','["正是霜高木落時。"]'),
('6c37d1e4-8514-4294-9ac7-e712c36eeecc','送馬擴詣行在  其一','趙榛','宋','宋诗','song-poetry','','[]','全趙收燕至太平，朔方寸土比千金。',32,'全唐诗/poet.song.110000.json','["全趙收燕至太平，朔方寸土比千金。", "氛祲一掃鑾輿返，若個將軍肯用心。"]'),
('2b1db30e-6404-445e-be95-8ff6e882863b','送馬擴詣行在  其二','趙榛','宋','宋诗','song-poetry','','[]','遣公直往面天顔，一奏臨朝莫避難。',32,'全唐诗/poet.song.110000.json','["遣公直往面天顔，一奏臨朝莫避難。", "多少焦苗待霖雨，雨霖只在月旬間。"]'),
('5f879449-770d-49f1-801d-ebff25849db4','歌二首  其一','欽宗朱后','宋','宋诗','song-poetry','','[]','幼富貴兮厭綺羅裳，長入宮兮陪奉尊陽。',36,'全唐诗/poet.song.110000.json','["幼富貴兮厭綺羅裳，長入宮兮陪奉尊陽。", "今委頓兮流落異鄉，嗟造化兮速死爲强。"]'),
('04e19e68-f40e-4bf4-af0d-4760ba6cff69','歌二首  其二','欽宗朱后','宋','宋诗','song-poetry','','[]','昔居天上兮珠宮玉闕，今入草莽兮事何可說。',41,'全唐诗/poet.song.110000.json','["昔居天上兮珠宮玉闕，今入草莽兮事何可說。", "屈身辱志兮恨何時雪，誓速歸泉下兮此愁可絕。"]'),
('f8971422-38f2-4d7e-bf81-2edb185b3dd7','贊達磨大師','釋宗元','宋','宋诗','song-poetry','','[]','十萬里來賣口嘴，宜乎打落當門齒，面壁九年誰採你。',49,'全唐诗/poet.song.110000.json','["十萬里來賣口嘴，宜乎打落當門齒，面壁九年誰採你。", "深雪之中若不得救苦救難觀世音菩薩，有甚面目歸鄉里。"]'),
('e433f681-981b-4412-b0b0-2b7a7214e4c0','贊五祖和尚','釋宗元','宋','宋诗','song-poetry','','[]','貌古而清，語俚而新。',52,'全唐诗/poet.song.110000.json','["貌古而清，語俚而新。", "同乎流俗，大有逕庭。", "常心是道，殺人活人。", "使當時磨下玉潔冰清，則楊岐一宗未必中興者也。"]'),
('05ab9d46-bf47-42a4-a845-3f78d427f80c','贊大慧和尚','釋宗元','宋','宋诗','song-poetry','','[]','世尊去世，二千餘年，到此尊慈，恰五十代。',73,'全唐诗/poet.song.110000.json','["世尊去世，二千餘年，到此尊慈，恰五十代。", "渠以壁上安燈盞，雨前置酒臺。", "悶來打三碗，何處得愁來。", "頌清浄行者不入涅槃，破戒比丘不墮地獄，佛法興衰可見也。"]'),
('426a1f92-d7a3-48fe-a236-0d5118056abe','贈學者','李衡','宋','宋诗','song-poetry','','[]','學詩如參禪，初不在言句。',192,'全唐诗/poet.song.110000.json','["學詩如參禪，初不在言句。", "傴僂巧承蜩，梓慶工削鐻。", "借問孰師承，妙處應自悟。", "向來大江西，洪徐暨韓呂。", "山谷擅其宗，諸子爲之輔。", "短句與長篇，一一皆奇語。", "卓爾自名家，無愧城南杜。", "君詩亦可人，羞作女工蠹。", "正臨百尺竿，到此方進步。", "我性文字空，志在學農圃。", "老矣甘摧頹，肯復事雕組。", "少讀三百篇，每自歎無補。", "一念絕邪思，得處忘我所。", "學詩如參禪，無舍亦無取。", "立雪謾齊要，斷臂徒自苦。", "君欲問活法，活法無覓處。"]'),
('b9357378-1d83-42a0-afff-888a3e8d01f5','短項翁','李衡','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','我生懶放世無偶，身即囂塵志林莽。',160,'全唐诗/poet.song.110000.json','["我生懶放世無偶，身即囂塵志林莽。", "寒饑未免困啼號，束带深慚爲升斗。", "先生閉戶傲羲皇，雲夢胸中吞八九。", "摶風暫爾抑雄飛，萬事紛紛付巵酒。", "年來得此短項翁，落落虛懷真勝友。", "煙蓑稱體翦疏筠，老態婆娑固不羣。", "每笑鴟夷託後塵，臭味仍復羞崑崙。", "何曾爲致常持滿，來此與爾談胚渾。", "異時先生登紫微，定自與爾相追隨。", "想應頼爾排紛擾，坐覺秋毫泰山小。"]'),
('152f89e9-4d5c-4b9d-a018-863e9f12958f','功成亦賦短項翁詩復次其韵','李衡','宋','宋诗','song-poetry','','[]','君不見仲淹居河汾，目營四海心六經。',178,'全唐诗/poet.song.110000.json','["君不見仲淹居河汾，目營四海心六經。", "又不見子幼反田里，拊缶烏烏徒快耳。", "續經憤世雖自喜，豈識濁醪函妙理。", "皤然短項滑稽徒，却笑兩翁非通儒。", "可人風味敵冰壺，惟酒是務焉知餘。", "不學羽衣李集賢，斗酒過量項飛泉。", "復憐胡子名空傳，緩急由人腸中乾。", "高情陶彼勳華風，放懷那惜傾千鍾。", "鄙哉成德真小器，一擊墮地羞空空。", "嗟余磊磈填心胸，安得與爾長相逢。", "會當乞爾扁舟去，煙雨空濛伴釣翁。"]'),
('eb72d9c6-d119-4b8c-bab7-686e952c24f2','與仲彌性同次唐人二詩韵  其一','李衡','宋','宋诗','song-poetry','','[]','盡日困登陟，跏趺聊對牀。',48,'全唐诗/poet.song.110000.json','["盡日困登陟，跏趺聊對牀。", "巖空眩層碧，草細函幽香。", "弔古謾秋思，開尊延月光。", "隨身有竿木，作戲且逢場。"]'),
('fd6fa22e-a29f-43fc-9d5e-884e1ba7a018','與仲彌性同次唐人二詩韵  其二','李衡','宋','宋诗','song-poetry','','[]','天面無纖靄，平川灝氣吞。',48,'全唐诗/poet.song.110000.json','["天面無纖靄，平川灝氣吞。", "搘筇臨閣道，拂石憩雲根。", "柳映山前路，煙摇水北村。", "醉歸風滿袖，斜月在蓬門。"]'),
('01b730a5-c9da-4c91-ac83-2803d727a6f6','樂庵初成二首  其一','李衡','宋','宋诗','song-poetry','','[]','老子平生百不足，庵成那管食無肉。',32,'全唐诗/poet.song.110000.json','["老子平生百不足，庵成那管食無肉。", "終朝閉戶只讀書，四面開窗都見竹。"]'),
('42766441-8fd2-4f02-a44b-ea3b82c9f3f4','樂庵初成二首  其二','李衡','宋','宋诗','song-poetry','','[]','投老庵居百事宜，早眠晏起不論時。',32,'全唐诗/poet.song.110000.json','["投老庵居百事宜，早眠晏起不論時。", "更長睡足披衣坐，傾耳林間竹畫眉。"]'),
('47d75e05-2b06-458b-a46d-60b069f26ccd','樂庵所藏柳影及松梅二畫因作二絕摹作砑花牋至今盛行於吳門  其一','李衡','宋','宋诗','song-poetry','','[]','三月江南花滿枝，風輕簾幕燕爭飛。',32,'全唐诗/poet.song.110000.json','["三月江南花滿枝，風輕簾幕燕爭飛。", "遊人休惜夜秉燭，楊柳陰濃春欲歸。"]'),
('739f6ece-287e-4125-ac93-06c8d978ca29','樂庵所藏柳影及松梅二畫因作二絕摹作砑花牋至今盛行於吳門  其二','李衡','宋','宋诗','song-poetry','','[]','崔嵬霜幹欲凌雲，俯映寒梢數尺春。',32,'全唐诗/poet.song.110000.json','["崔嵬霜幹欲凌雲，俯映寒梢數尺春。", "須信蒼髯浄明老，坐中容有散花人。"]'),
('937789a5-d9a4-4a95-b843-b7a08ebf1aca','偈','李衡','宋','宋诗','song-poetry','','[]','竿木隨身得自由，應緣已畢復何求。',32,'全唐诗/poet.song.110000.json','["竿木隨身得自由，應緣已畢復何求。", "翛然來往等孤雁，影落寒潭迹不留。"]'),
('52f533c1-4b30-4276-9679-fbd529761908','蒲鞋','劉章','宋','宋诗','song-poetry','','[]','吳江浪浸白蒲春，越女初挑一樣新。',64,'全唐诗/poet.song.110000.json','["吳江浪浸白蒲春，越女初挑一樣新。", "纔自繡窗離玉指，便隨羅襪上輕塵。", "石榴花下從容久，玳瑁筵前整頓頻。", "今日高樓鴛瓦上，不知擲果是何人。"]'),
('d1a83f36-b13c-4c4a-9dab-abeb5ce933ca','和唐子固見寄初冬晚步韻','錢億年','宋','宋诗','song-poetry','','[]','凄風滿寒谷，廣陌照落日。',144,'全唐诗/poet.song.110000.json','["凄風滿寒谷，廣陌照落日。", "繁霜排岸草，尪瘁怯寒慄。", "塊坐閲殘編，十日九不出。", "時爲孤憤吟，嗟嗟類蟋蟀。", "歧路多阻艱，煙霞成痼疾。", "保是千金軀，他慕無終畢。", "遠覽塵垢外，無得初無失。", "溺志膠擾間，跧跽信匪一。", "阮生亦有言，何異褌中虱。", "呼童洗破觥，一醉真可必。", "耳熱即嗚嗚，鄙野誰訶詰。", "浩歌莫予知，奚用聆清瑟。"]'),
('31374f30-6d50-4c72-a57f-39fa2a412799','重陽','錢億年','宋','宋诗','song-poetry','','[]','商飈驚秀木，松桂不受秋。',120,'全唐诗/poet.song.110000.json','["商飈驚秀木，松桂不受秋。", "萸菊有光輝，芬芳滿金甌。", "古來賢達人，逢時聊解憂。", "龍山孟參軍，帽落初不羞。", "東籬陶徵士，得酒更何求。", "若人不常有，至今稱風流。", "節物自爾殊，生滅同一漚。", "浮世夢幻身，適意是良謀。", "山翁未嘗樂，而亦未嘗愁。", "吾獨可奈何，任渠自悠悠。"]'),
('df0b4eee-6b24-4055-9d01-08e2c1613679','避暑椒山呈潘師清','錢億年','宋','宋诗','song-poetry','','[]','凉風生層巒，炎日遮疊嶂。',120,'全唐诗/poet.song.110000.json','["凉風生層巒，炎日遮疊嶂。", "我來茲地遊，心焉樂清曠。", "爲吏即華顛，愧臨士民上。", "老醜畏近人，筋骸非少壯。", "知止遠卑辱，奚敢謂高尚。", "齪齪方自持，良心未容放。", "促柱有繁音，龐聒無清唱。", "却暑御絺綌，自修終弭謗。", "居閑無適莫，且免縈重恙。", "俯仰心不慚，無言亦疏暢。"]'),
('71a7facb-e307-4eec-af13-5d230dbaead4','次太守李侍郎和郡博士包丈芍藥韻二首  其一','錢億年','宋','宋诗','song-poetry','','[]','栽花未免惜花殘，忙裏應須護小欄。',32,'全唐诗/poet.song.110000.json','["栽花未免惜花殘，忙裏應須護小欄。", "何似長松與修竹，不妨耐久靜中看。"]'),
('0cc73875-fdf5-4c5b-a278-4e8bed5282b0','次太守李侍郎和郡博士包丈芍藥韻二首  其二','錢億年','宋','宋诗','song-poetry','','[]','豔草妖花理易殘，無勞太息撫雕欄。',32,'全唐诗/poet.song.110000.json','["豔草妖花理易殘，無勞太息撫雕欄。", "終年費盡壅培力，能共樽前幾日看。"]'),
('fc554b4e-54c1-4c17-979b-7656f1a15da5','呈盛逢時','錢億年','宋','宋诗','song-poetry','','[]','倦翮知還心已休，無窮世事懶回頭。',32,'全唐诗/poet.song.110000.json','["倦翮知還心已休，無窮世事懶回頭。", "是非不屬閑人耳，月自當空水自流。"]'),
('8e95000e-2d74-40d0-a8ff-90e3698a1829','次遊玉虛洞韻','錢億年','宋','宋诗','song-poetry','','[]','茂松修竹晝陰陰，澗水幽流一徑深。',32,'全唐诗/poet.song.110000.json','["茂松修竹晝陰陰，澗水幽流一徑深。", "未必山中無外事，須知靜躁總因心。"]'),
('ece48f41-9436-4abf-83a3-e27bbeaba19c','巫山高','王銍','宋','宋诗','song-poetry','','[]','十二危峯隠寒霧，旁連三巴下三楚。',192,'全唐诗/poet.song.110000.json','["十二危峯隠寒霧，旁連三巴下三楚。", "斷崖青黄聳天壁，秀色蒼茫接天路。", "鼓瑟玉京嬉帝傍，下鎮九淵稱帝女。", "冥心可見類相求，夢裏襄王契神遇。", "鏘然玉佩似可期，倏爾霓旌去無所。", "天風浩蕩吹太清，萬里憑虛送飛步。", "行雲行雨終不來，歲月人間幾朝暮。", "那知一戲疑萬古，至今不知高唐處。", "仙兮神兮非與是，流傳只有蘭臺賦。", "山藏虎兕爭怒號，峽束江水翻波濤。", "舟楫寄命輕鴻毛，猶起羨慕成譏嘲。", "行人所見日卑淺，仰首彌覺巫山高。"]'),
('860b73f6-1686-43e1-88fc-75097a981102','關山月','王銍','宋','宋诗','song-poetry','','[]','戍樓炯炯關山月，白首征人數圓缺。',112,'全唐诗/poet.song.110000.json','["戍樓炯炯關山月，白首征人數圓缺。", "關山不隔四時寒，夜夜冷光沙如雪。", "照破天崖萬里心，閨中又是經年別。", "雁飛唯願得書歸，月下有人魂斷絕。", "閨中月下不勝情，獨戍關山更堪說。", "一時北闕賀書多，萬古西戎終不滅。", "陽和待得活枯荄，東風洗盡征人血。"]'),
('a194ab4c-1444-4c02-b02a-89155ae9a8f6','白頭吟一首','王銍','宋','宋诗','song-poetry','','[]','浮雲高映天上月，月華未落雲已滅。',256,'全唐诗/poet.song.110000.json','["浮雲高映天上月，月華未落雲已滅。", "濁水長羨清路塵，濁水尚流塵已絕。", "人心不如雲與塵，變態無窮旋消歇。", "我家火齊堆金盤，朱樓鎖煙青冥端。", "昨憶聞琴纔等閒，夜奔臨邛相與還。", "鳳皇曲成保懽樂，驌驦裘典無艱難。", "當爐滌器兩憔悴，幾度暗啼愁遠山。", "君儕狗監動人主，君乘駟馬跨故園。", "檄書呵譏蜀父老，未足灑恥徒小恩。", "顔色何嘗不如舊，自是心存憎愛間。", "我方失意天地窄，君視浮雲江海寬。", "一身情易復情難，百年有來終有去。", "凄凄嫁娶不須啼，出門萬里淪中路。", "我憐秀色茂陵女，既有新人須有故。", "請把阿嬌作近喻，到底君王不重顧。", "若知此事爲當然，千金莫換長門賦。"]'),
('34b411b8-0637-4357-a704-f584a0b18fcd','折楊柳','王銍','宋','宋诗','song-poetry','','[]','手拗楊柳贈行人，情條恨葉江南春。',112,'全唐诗/poet.song.110000.json','["手拗楊柳贈行人，情條恨葉江南春。", "朦朧疎煙濕芳草，摇落微風生白蘋。", "長亭短亭銷離魂，古情不盡今情新。", "一聲驪歌幾聲哭，行人去後春江綠。", "歌哭相雜江水頭，相看不發情何屬。", "江河到海有窮日，輪蹄行路無已時。", "路傍楊柳折已盡，東風再換明年枝。"]'),
('d24855ab-2e11-4f07-924d-5fc72dd245d1','送純師歸眉山吉祥寺','王銍','宋','宋诗','song-poetry','','[]','上人峨嵋秀，冥冥聳高風。',168,'全唐诗/poet.song.110000.json','["上人峨嵋秀，冥冥聳高風。", "依游王公間，尚带山水容。", "謫仙信奇逸，蜀僧論絲桐。", "寂默誰爲聽，誤比萬壑松。", "崎嶇古今塗，勢利紛其中。", "晚遺似高識，物我無異同。", "是心湛寒水，處處流真空。", "猶嫌百年夢，剩此一枝筇。", "忽懷煙霞想，永念菽水供。", "身爲反哺烏，更逐高飛鴻。", "斜日澹歸袂，不似秋色濃。", "孤行拾黄葉，一笑千山重。", "桑宿揮餘戀，雲樓杳歸蹤。", "從茲與明月，相伴落何峯。"]'),
('1c15227d-afda-4bc7-8070-016429fc55c8','舟中夜雪讀正卿教授近詩輒賦鄙句并以爲別','王銍','宋','宋诗','song-poetry','','[]','百年半羈棲，輕與故山別。',192,'全唐诗/poet.song.110000.json','["百年半羈棲，輕與故山別。", "回首千萬峯，飛雲不可越。", "弭棹濠上亭，非鄉愴時節。", "朝號迥野風，夜聽孤舟雪。", "濕薪無煖焰，濁淚共明滅。", "癡坐增灑然，何以慰清絕。", "斯時咏君詩，心抱益澄沏。", "未從觀魚莊，先得馭風列。", "荆玉出此邦，誰獻復誰刖。", "山川漫奇麗，文物久銷歇。", "君詞吐白虹，神寶疑不沒。", "我欲賡餘思，景好句逾拙。", "如逢勾漏令，未得丹砂訣。", "萬里煙雲開，揚舲及明發。", "荆山自茲遠，雲濤渺天末。", "兩地見梅花，相思不同折。"]'),
('a2c96820-93a5-48a0-a354-d0677cb6b5b0','無題','王銍','宋','宋诗','song-poetry','','[]','三月柳花飛，東風繡香國。',156,'全唐诗/poet.song.110000.json','["三月柳花飛，東風繡香國。", "桂影弄春光，飛瓊悵分缺。", "雲輿返積霄，翠浪翻天末。", "閬苑桃李花，莫使芳香歇。", "緬懷霞中人，芙蕖艷秋色。", "煙鸞吟碧空，行雲不停刻。", "何事寄紅埃，悲聲調綠髮。", "神觀洞太虛，紫清注金格。", "玉宸丹鳳檢，詞章煥瓊笈。", "孰執招真旗，笙簫下空闕。", "靈光湛法身，生死本無別。", "妙合造化機，陰陽時出沒。", "欲識天中真，寒江浸明月。"]'),
('4d307054-bd81-468f-ab66-d2de937fab13','寄題真州扃岫寺','王銍','宋','宋诗','song-poetry','','[]','一峯秀色何高寒，更以木杪橫飛欄。',240,'全唐诗/poet.song.110000.json','["一峯秀色何高寒，更以木杪橫飛欄。", "荆吳形勝妙天下，閒鎖雲錦光斕斑。", "山從千古混沌始，江自萬里岷峨還。", "江山無際真賞遠，人境未如心境寬。", "乃知萬象自變滅，我與天地俱清閒。", "時來登覽健意氣，興落煙靄空濛間。", "宛如列岫在扃鐍，何待謝守窗中看。", "仙壺日月悟世換，蟻穴富貴羈夢殘。", "易中求象山有天，須彌納芥曾何難。", "乾坤橐籥一氣內，鉅細兩不離區寰。", "徑呼飛仙來取醉，笙簫彷彿鏘珮環。", "已鞭鸞鳳到三境，何待虎豹號九關。", "只今朱甍半落日，誰繫畫舸臨蒼灣。", "何當脫身戎馬際，共契妙旨相追攀。", "懷哉欲往波浪闊，回首江南江北山。"]'),
('f804c9b3-5367-4513-a8c7-66c31dce60a4','蔡天啟作中興碑詩且邀同賦','王銍','宋','宋诗','song-poetry','','[]','一日屠戮三庶人，天理已盡殺氣昏。',160,'全唐诗/poet.song.110000.json','["一日屠戮三庶人，天理已盡殺氣昏。", "青宮惴惴二十載，免禍自求黄屋尊。", "忠臣開除兩京路，未知日月雙懸處。", "歸來祈哀語可憐，今日貴作天子父。", "瀟湘江邊鑱穹碑，煙雲相連愁九疑。", "湖南萬古長嗟地，剩與屈賈添餘悲。", "雄文漫郎來作吏，正色顔公謁西內。", "兩賢憤托金石堅，莫求此碑求此意。", "休闖九閽訴帝傍，莫化杜鵑啼故鄉。", "磨崖難摧幽恨長，水流不盡山蒼蒼。"]'),
('288d077f-96d7-4b8d-b61a-415a04d65bb7','題洛神賦圖詩','王銍','宋','宋诗','song-poetry','','[]','曹公文武俱絕倫，傳與陳王賦洛神。',192,'全唐诗/poet.song.110000.json','["曹公文武俱絕倫，傳與陳王賦洛神。", "高情寓託八荒外，曾是親逢絕世人。", "五官郎將莫輕怒，椒房自是袁家婦。", "聞道生時覆玉衣，便是于今腰束素。", "驚鴻翻然不重顧，射鹿深寃更凄楚。", "不將降虜賜周公，先識禍機楊德祖。", "此意明明可自知，豈有神人來洛浦。", "空用平生八斗才，七步那能說微步。", "楚離日月常爭光，湘夫人後誇高唐。", "丹青畫寫鬼神趣，筆端調出返魂香。", "妙畫高文盡天藝，神理人心兩無異。", "此情萬古恨茫茫，且爲陳王說餘意。"]'),
('ed71bf7a-5c9a-4435-91e0-81ad55a1eea3','和江子我見送詩','王銍','宋','宋诗','song-poetry','','[]','放舟弄清泚，始覺南風清。',144,'全唐诗/poet.song.110000.json','["放舟弄清泚，始覺南風清。", "白雲認鄉樹，永念隨父兄。", "一夢三十載，將老猶遠行。", "聊將鄭衛耳，一聽新蟬鳴。", "空懷煙霞想，下及飛鴻征。", "多公久要誼，獻紵復班荆。", "茅屋照野水，寒窗抱深明。", "相期脫覊網，豈肯縛簪嬰。", "此生纔一戲，萬物何營營。", "我行別良友，執袂中心怦。", "公來貽新詩，折柳何多情。", "他時簪還盍，莫忘歲寒盟。"]'),
('052be0fc-d97b-40f3-b475-f98c7498bb7a','追和周昉琴阮美人圖詩','王銍','宋','宋诗','song-poetry','','[]','丹青有神藝，周郎獨能兼。',48,'全唐诗/poet.song.110000.json','["丹青有神藝，周郎獨能兼。", "圖畫絕世人，真態不可添。", "却憐如畫者，相與落誰手。", "想像猶可言，雨重春籠柳。"]'),
('c6366433-f8f4-445b-b821-f95b1c1d7b78','次韻國香詩','王銍','宋','宋诗','song-poetry','','[]','百花零落悲春晚，不復林園門可款。',256,'全唐诗/poet.song.110000.json','["百花零落悲春晚，不復林園門可款。", "待花結實春已歸，到頭只有東家管。", "楚宮女子春華敷，爲雲爲雨皆有餘。", "親逢一顧傾國色，不解迎人專城居。", "目成未到投梭處，後會難憑人已去。", "可憐天壤擅詩聲，不如崔護桃花句。", "坐令永抱埋玉悲，遊手那知京兆眉。", "難堪別鶴分飛後，猶是驚鴻初見時。", "新懽密愛應長久，暫向華筵賞賓友。", "舞盡春風力不禁，困裏腰肢一渦柳。", "座上何人贈翠翹，蜀中風調尤情饒。", "懽濃酒暈上玉頰，香暖紅酥疑欲銷。", "佳人薄命古相似，先後乃逢天下士。", "但惜盈盈一水時，當年不寄相思字。", "宜州遺恨君能詳，瘴雲萬里空悲凉。", "無限風流等閒別，幾人賞鑒得黄香。"]'),
('f613ea12-0437-4a47-89c3-f7e56de23151','妾薄命  其一','王銍','宋','宋诗','song-poetry','','[]','寒閨有靜女，十載念遠征。',96,'全唐诗/poet.song.110000.json','["寒閨有靜女，十載念遠征。", "命似絳綃薄，身同朝露輕。", "存心合懽綺，待得機杼成。", "從來君獨賞，詎可賣都城。", "憑夢欲寄遠，舊路春草生。", "獨夜理瑶琴，泪燭剪不明。", "待誰相應節，要自不勝情。", "會有不眠者，聽此斷腸聲。"]'),
('06c7b668-a816-4700-b1ca-6e82586d6a1c','妾薄命  其二','王銍','宋','宋诗','song-poetry','','[]','少年輕遠行，易發同爾汝。',96,'全唐诗/poet.song.110000.json','["少年輕遠行，易發同爾汝。", "紅顔望中老，離恨尚如許。", "妾身異金石，更涉幾寒暑。", "長天誰云廣，不見收墮雨。", "愁來津頭望，信絕不得渡。", "鄰婦念幽獨，艇子隔溪語。", "落日下空江，脩煙淡晴渚。", "流恨滿春風，西飛數歸羽。"]'),
('7018856a-2e57-41bd-b781-6a4cee4ecb6f','古意','王銍','宋','宋诗','song-poetry','','[]','茅簷祕秀色，從古歎不遭。',60,'全唐诗/poet.song.110000.json','["茅簷祕秀色，從古歎不遭。", "遊子去未返，徒使寸心勞。", "朝歎江海深，夜視星斗高。", "歸期約春風，今已木葉凋。", "一日兩回來，看取門前潮。"]'),
('ec032dfa-3249-4b5c-9cc3-e459b94ea7ee','送王道元運判致政歸潛皖','王銍','宋','宋诗','song-poetry','','[]','好山如幽人，深絕常避地。',168,'全唐诗/poet.song.110000.json','["好山如幽人，深絕常避地。", "潛峯獨呈露，孤立信奇最。", "高擁一峯寒，縹緲亂雲氣。", "萬古招行人，誰與賞心會。", "我公實仙才，崑閬失品次。", "挽公青霞襟，來作綉衣使。", "終尋汗漫遊，高舉九霄外。", "行色開畫圖，秋容掩新霽。", "造化爲我娛，神超物無累。", "我窮知音稀，與世久無味。", "落葉掃不禁，歲月水東逝。", "愁作送公詩，出門更何詣。", "贈言詞亦貧，無以報高誼。", "野宿慎衣裘，寒霜方夜墜。"]'),
('279d0524-8523-4e65-b52f-3641453e042a','送和斜川詩二首  其一','王銍','宋','宋诗','song-poetry','','[]','兩脚垂天際，愁雲慘不休。',120,'全唐诗/poet.song.110000.json','["兩脚垂天際，愁雲慘不休。", "尋幽抱奇癖，欲繼斜川游。", "中原苦兵革，誰能障倒流。", "野老且吞聲，蹤跡逐閒鷗。", "策杖過短壑，蠟屐登高邱。", "臨風一長嘯，慨然伊呂儔。", "神交溯二子，新詩遠寄酬。", "魚緘生春色，風流似舊否。", "恰喜心期合，且緩杞人憂。", "我曹非天厄，伐木友聲求。"]'),
('e246991a-5455-4251-acdf-2aac92ec31ca','送和斜川詩二首  其二','王銍','宋','宋诗','song-poetry','','[]','採藥遊名山，恐是韓伯休。',120,'全唐诗/poet.song.110000.json','["採藥遊名山，恐是韓伯休。", "款段下澤車，久師馬少游。", "兩公學真隠，異世今同流。", "遇害能鳴雁，多猜不下鷗。", "何如脫羈馽，尋壑與經丘。", "人生亦誤計，獨醒無匹儔。", "天地本虛靜，萬物自應酬。", "陰陽驅意氣，定能相勝否。", "况復漆室女，浪爲魯國憂。", "真妄兩非是，湛然一無求。"]'),
('ad31ab7e-1056-4010-86d1-cc2a5914674a','山中梅花盛開戲作','王銍','宋','宋诗','song-poetry','','[]','化工難迴天地春，下遣第一天仙人。',208,'全唐诗/poet.song.110000.json','["化工難迴天地春，下遣第一天仙人。", "前驅飛雪助幽絕，千里隔盡埃與塵。", "何心百卉擅獨秀，寒入萬物無精神。", "綽約肌膚瑩香玉，借與東皇立花國。", "開破天地發生心，引出世問凡草木。", "品流不數廣寒宮，爲嫌月姊長孀獨。", "波上輕雲掌上身，有來比肩皆塵俗。", "須知尤物到絕言，從昔華詞吟不足。", "溪回路轉一枝斜，可惜天寒倚修竹。", "窮塗遊子歲華晚，腸斷夜投山館宿。", "古今幽怨不盡情，更入凄凉笛中曲。", "荒山偶賦梅花詩，佇立花前香在衣。", "傷心不忍別紅紫，付與曉風零亂飛。"]'),
('ef908e3f-c82c-4c81-9703-b8bebbe55b7d','繫舟餘杭門訪西湖金輪寺參上人','王銍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','北郭望西湖，微徑幾尋尺。',144,'全唐诗/poet.song.110000.json','["北郭望西湖，微徑幾尋尺。", "澹與人意長，雲寒正無色。", "深尋幽禪居，步轉蒼山側。", "落葉不可紀，遮盡山下石。", "師方無定居，我亦何所適。", "四海漭無歸，老矣山中客。", "百年熟機緣，還此共禪寂。", "語罷今古分，坐上有陳迹。", "一笑視此生，何事非戲劇。", "開門納遥峯，暮雨一江白。", "茲遊非世逢，歸路晚蕭瑟。", "積陰迷曉昏，鐘聲報將夕。"]'),
('c44c9026-4786-43f2-8a02-53cbaeb23940','縉雲縣仙都山黄帝祠宇','王銍','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','我渡溪水尋荒村，羣峯勢若萬馬奔。',384,'全唐诗/poet.song.110000.json','["我渡溪水尋荒村，羣峯勢若萬馬奔。", "酣酣春色雪初霽，靄靄野氣山猶昏。", "瓊樓金闕滌地盡，松柏半带斤斧痕。", "要還清浄掃塵俗，一炬劫火安得焚。", "行人鞠躬下馬拜，仙都妙理吾能言。", "威神可畏凜如在，有臺今亦祠軒轅。", "當年垂衣正南面，制作取盡坤與乾。", "鑿開鴻荒肇人紀，首爲區宇立本根。", "風后力牧來聯翩，神機開闢施無垠。", "初傳聞道廣成子，後乃密契中皇君。", "功高德大不可擬，幾與造物分遺恩。", "遥遥唐虞建炎運，萬年聖子兼神孫。", "至人御世用常道，飛升輕舉安足論。", "爰作一氣生萬物，奈何已把天人分。", "伏羲八卦畫已破，女媧欲補理亦繁。", "飄然獨返紫清去，却斂造化歸金渾。", "廟前仙石表今古，屹立霄壤爭雄尊。", "鼎湖可望不可見，意今後世難攀援。", "頂中玄宮號泥丸，自然有路朝天閽。", "此身內外神氣合，俯仰自超生死門。", "默運四時無詭異，試觀日月誰吐吞。", "祇今湖邊送風雨，草木吹動旗與幡。", "飄然十丈紅菡萏，碧溪下插玻璃盆。", "馬蹄車轍不須有，雖迷襄野道自存。"]'),
('848c47de-f7dd-4a2d-b95f-6b086747c238','明覺山中始見梅花戲呈妙明老','王銍','宋','宋诗','song-poetry','','[]','急晷馳輪歲將歇，我更荒村轉冰轍。',208,'全唐诗/poet.song.110000.json','["急晷馳輪歲將歇，我更荒村轉冰轍。", "凝巖萬物凍無姿，水墨陂塘葭葦折。", "是誰向背此間來，破萼梅花伴幽絕。", "遥山誰恨天作愁，澹盡眉峯半明滅。", "清香自滿不因風，玉色素高非鬭雪。", "竹籬凝睇一凄凉，沙水澄鮮兩明潔。", "天仙謫自廣寒宮，定與桂娥新作別。", "尚憐孀獨各相望，多情與照黄昏月。", "從來耐冷月中人，一任北風吹石裂。", "漫勞粉鏡學粧遲，欲寫冰膚畫工拙。", "千古無人識歲寒，獨有廣平心似鐵。", "我因花意拂埃塵，尚恐人傳向城闕。", "詩成火煖夜堂深，地爐細與山僧說。"]'),
('e9c0fdc7-e013-4bfe-a577-48b08425be7f','明師見和梅詩再用韻兼奉送還福唐','王銍','宋','宋诗','song-poetry','','[]','斲輪妙手聲名歇，誰信出門猶合轍。',208,'全唐诗/poet.song.110000.json','["斲輪妙手聲名歇，誰信出門猶合轍。", "後來世外有高禪，凜凜蘭摧并玉折。", "久將生死付八還，不數圖書號三絕。", "詩來乃與梅爭妍，獺髓補痕紅未滅。", "那知一夜卷東風，開盡寒枝千點雪。", "漢宮婕妤體自香，月裏飛仙長玉潔。", "白頭對鏡憶年少，每到花開重離別。", "愛花取醉惜夜闌，眷戀盈盈花上月。", "人歸吹恨落關山，恨極欲吹羌管裂。", "何况東溪漫草寒，學世猶嗤顔謝拙。", "還驚詩律張吾軍，塵戰愧非求嚼鐵。", "歸舟滿載萬珠璣，莫顯神龍藏貝闕。", "明朝詩逐暮潮還，餘意憑師筆端說。"]'),
('58cd3200-e5ef-498e-9b08-0ee8ed86c4b6','次韻率行之見投因以賦別','王銍','宋','宋诗','song-poetry','','[]','素空零玉露，碧梧墮金井。',180,'全唐诗/poet.song.110000.json','["素空零玉露，碧梧墮金井。", "周年不待人，去我如斷綆。", "歸翼懶飛翔，老驥倦馳騁。", "山空風月滿，人戀松桂影。", "窮方屢厄陳，喜動初入郢。", "文豪獲勝游，羈思發深省。", "周原富十箱，漢儀重九鼎。", "王謝樂江海，巢由本箕潁。", "談深光明藏，游遍妙峯頂。", "頌橘悲屈平，賦梅思宋璟。", "炎凉梁上燕，喜怒坎中黽。", "千年六龍轡，萬事一漁艇。", "居人望歸騎，暝色暗前嶺。", "淺學字識丁，美穴魚知丙。", "書隨新雁行，慰我心炯炯。"]'),
('78b80232-d402-49f6-9f41-365e8026937f','蒙蔡藏用惠古風一軸歎仰不足輒賦病桐書爲謝慼深而詞哀耳','王銍','宋','宋诗','song-poetry','','[]','老境憂患集，坐受衰病侵。',180,'全唐诗/poet.song.110000.json','["老境憂患集，坐受衰病侵。", "山林成獨往，樽酒惟孤斟。", "萬事信已矣，滅迹栖蒼岑。", "對鏡未免愁，寒雲生嶽陰。", "斯時瓊瑶贈，無以報兼金。", "酬之病桐詩，歎息成永吟。", "風霜入枯枝，螻蟻穿病心。", "艷艷上林樹，已朽難寄林。", "幽人識爨下，取作綠綺琴。", "拂拭延妙聲，泠泠朱絲繩。", "淳風散已久，世僞多洼淫。", "一弄清風還，三古盡可尋。", "自然俯仰中，山水見高深。", "同心齊取捨，何歎異古今。", "永真遇□賞，江海有知音。"]'),
('73b98f34-9c85-4932-bb28-9ad19824d7fd','中秋招葉子謙','王銍','宋','宋诗','song-poetry','','[]','堂上月已滿，樽中酒更空。',48,'全唐诗/poet.song.110000.json','["堂上月已滿，樽中酒更空。", "故人眇何許，出門惟清風。", "不如一夕飲，所至皆能同。", "悄然望玉杵，無聲桂影中。"]'),
('7668622c-a627-416c-99b9-72b6b4f32fe0','除夕','王銍','宋','宋诗','song-poetry','','[]','一歲盡今夕，既往那可追。',180,'全唐诗/poet.song.110000.json','["一歲盡今夕，既往那可追。", "疎梅吐幽豔，輕冰釋寒澌。", "新陳自相代，長作萬古悲。", "亦復强取醉，椒盤雜兒嬉。", "天回萬象春，除盡羣陰卑。", "地除衆枯槁，從今作華滋。", "一除不可復，綠髮成鬢絲。", "此是有盡處，那知無盡時。", "凡所未除者，所願皆除之。", "晚景安分守，幻身絕思維。", "生死我所明，聖賢吾所師。", "優游觀物變，翼戢仍鮮差。", "山嶽惟塵爾，寸心不可移。", "浩歌自達曉，自信何用疑。", "樓頭畫角聲，已逐東風吹。"]'),
('36da8914-62d8-4cc1-8a99-2d0a2d0a89db','元日雪','王銍','宋','宋诗','song-poetry','','[]','布和舊重王正月，佳祥元日初逢雪。',192,'全唐诗/poet.song.110000.json','["布和舊重王正月，佳祥元日初逢雪。", "飄入椒觴氣更蘇，積滿玉蒲水已怯。", "歲歷今纔第一行，三百六十完未缺。", "故使重窺混沌時，太素山川始融結。", "但聞南陌流懽聲，懶將西佛論初劫。", "九門想得千官期，高聳岧嶢白銀闕。", "事隠東林夜宿年，靜灑僧窗更幽絕。", "草堂人去空舊賞，夢入江山半明滅。", "祗今縱橫天上來，勢壓丘陵動溟渤。", "映山更倚百尺樓，始見天工盛施設。", "明日東風掃玉塵，輸與寒梅亂花發。", "壯觀新年意氣張，天巧空奇吾語拙。"]'),
('e8ab42cd-0377-4e95-8512-3a12ec5e5ae9','向伯恭薌林詩','王銍','宋','宋诗','song-poetry','','[]','楚人喻薌草，可佩復可食。',240,'全唐诗/poet.song.110000.json','["楚人喻薌草，可佩復可食。", "靈均楚同姓，放逐去其國。", "皎皎忠良心，惕惕懼讒賊。", "扁舟下滄浪，魂迷招不得。", "至今芳洲上，寂寞少春色。", "我公異於是，聲譽超八極。", "挽公青霞裾，接武紫鸞翼。", "直契慕湘纍，論心不論迹。", "我是衆薌林，澡身而浴德。", "同心等崇蘭，直節逾蒼柏。", "登善味芝朮，去惡鋤枳棘。", "荀令十里香，揚雄一區宅。", "君臣相唯諾，品題來藻飾。", "日光萬丈長，衆薌馥芳澤。", "况了大因緣，功名皆戲劇。", "手擎妙喜國，心湛水精域。", "諸天衆薌雲，旃檀雜薝蔔。", "登門三十年，歲晚仍作客。", "誦公薌林詩，心境爲澄澈。", "雖非歌商頌，聲亦出金石。"]'),
('d367f76a-4833-4dda-b9fb-3340ac03f995','會稽楊梅雄天下其佳者皆出項里相傳項羽鄉里也驗圖志信然戲作楊梅詩供作者一笑耳','王銍','宋','宋诗','song-poetry','','[]','越山楊梅最珍美，人傑地靈生項里。',160,'全唐诗/poet.song.110000.json','["越山楊梅最珍美，人傑地靈生項里。", "江東廟食憶至今，應緣似舜重瞳子。", "南方炎威無時窮，落在故鄉草木中。", "請看枝頭萬點火，猶是咸陽三月紅。", "摧剛作柔隨物轉，婦人之仁仍可見。", "風姿和味說難名，顔色與香收易變。", "炎炎夏日簾影垂，玷污玉筍明瓠犀。", "映出越女天下白，壓倒驪山生荔枝。", "金鼎奪胎尤出類，萬人口腹非其對。", "外丹須要內丹成，任君封樹連園買。"]'),
('17011bbb-5b2e-4a2f-ab5b-300f355c226a','詩送韓簡伯學官于臨浦呈勸其重修西子祠','王銍','宋','宋诗','song-poetry','','[]','昔遊臨浦春正濃，小江縈委如無窮。',256,'全唐诗/poet.song.110000.json','["昔遊臨浦春正濃，小江縈委如無窮。", "花浮千林錦繡幄，舟揚萬頃玻瓈風。", "西施故鄉擅佳麗，會稽秀氣藏華穠。", "是時山晴見真色，落日西南千萬峯。", "今情不盡古情在，恨疊晚粧眉暈重。", "恨應但知傾國貌，無人能說亡吳功。", "倘非絕態動君意，姑蘇臺上猶歌鐘。", "成功未甘歸范蠡，素衣故國寧相從。", "文公之孫重端世，衮衣門戶推八龍。", "官閒援毫來弔古，溪山頓爲開愁容。", "謫仙亦賦浣紗石，至今翠絹不停織。", "浴池邀伴下瑶池，霑丐越女天下白。", "風流昭洗待名流，有德于人當血食。", "紅心草葬舊金釵，黄陵廟成新石刻。", "霞裙瓊佩無消息，怨魄凄魂招不得。", "一杯流水奠江蘺，苧蘿山前已秋色。"]'),
('7d2630cc-0991-44cf-84b5-f3c68e53d719','送史純夫歸餘杭','王銍','宋','宋诗','song-poetry','','[]','霜晴九月交，送子越東門。',96,'全唐诗/poet.song.110000.json','["霜晴九月交，送子越東門。", "同舟此水上，再對波清渾。", "聚散三十載，惟此一意存。", "邦國有大慶，去承曠蕩恩。", "我老百不堪，視子猶弟昆。", "新寒黄菊枝，落照黄葉村。", "慘愴欲別語，零落未歸魂。", "臨分吐情實，衰境意彌敦。"]'),
('7e94f11d-28db-4f8d-a268-8ea7e79bc41d','黄州栖霞樓蘇翰林所賦小舟橫截春江是也曾竑父罷郡畫爲圖求詩','王銍','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','銅雀不得鏁二喬，春江亦夢携西子。',128,'全唐诗/poet.song.110000.json','["銅雀不得鏁二喬，春江亦夢携西子。", "此樓縹緲相風流，此恨纏綿在雲水。", "洞庭葉下愁湘君，不獨陽臺雲雨神。", "精神感通若相遇，夢境幻境皆成真。", "黄州刺史清如鏡，水光山色心同瑩。", "牧之出守到元之，誰解把詩聞萬乘。", "圖成携得千里行，孤帆趁落斜陽城。", "江頭莫指挽鄧處，離合古今同一情。"]'),
('ca3dd695-eb45-48b4-9222-3d6bbb5550f3','登育王山示現塔贈鄉璉與三上人','王銍','宋','宋诗','song-poetry','','[]','危岫戴寶塔，亭亭起虛空。',156,'全唐诗/poet.song.110000.json','["危岫戴寶塔，亭亭起虛空。", "金鐸韻廣樂，日夜鏘天風。", "氣真逼雲漢，興逸追鸞鴻。", "嘉有三禪子，超曠栖禪宮。", "相追不憚遠，幽致惟我同。", "興盡歸一默，人逐歸雲東。", "平軒架絕壑，上與絕頂通。", "滄溟忽破碎，百川競朝宗。", "斜陽無遠近，山亂高低紅。", "四表倏明晦，變化安可窮。", "夜深風雨來，陰氣誇驕雄。", "響劇百谷咽，靜若一氣融。", "明發石路乾，清韻生寒松。"]'),
('ebc8ef18-73df-43f2-a8eb-db74d9a0f5d7','苕溪僧妙詢于其所居浄域開小軒楚僧舉季若爲永名僕以陶靖節乘流遇坎之語榜曰乘遇亦足以觸所遇而安不然雖無名可矣','王銍','宋','宋诗','song-poetry','','[]','一性本爲明，返爲羣物迷。',180,'全唐诗/poet.song.110000.json','["一性本爲明，返爲羣物迷。", "境浄皆徑山，心清即苕溪。", "啟扉迥臨湖，湖寬覺天低。", "花木春艷艷，松竹凉凄凄。", "憑欄快神襟，永與塵事暌。", "歸船動菰蒲，興斷殘霞西。", "浮煙暝自起，待得衆羽栖。", "貯空諸佛心，妙理何端倪。", "乘流與遇坎，萬理皆筌蹄。", "聊陳淵明意，斧藻粲幽題。", "豈有明月珠，祇照濁水泥。", "期我老中林，滅跡爲圃畦。", "况復大開士，賦詠自攀躋。", "禪深有根源，句圓無角圭。", "乃知文字工，自與造化齊。"]'),
('c86170ac-a5ff-44a0-8987-74d60e05bb2b','書謝文靖東山圖','王銍','宋','宋诗','song-poetry','','[]','山如出繭眉，溪似縈風带。',108,'全唐诗/poet.song.110000.json','["山如出繭眉，溪似縈風带。", "雅意樂溪山，安用携粉黛。", "煙雲無定姿，姝麗有真態。", "謝公經世心，遇物何顯晦。", "鐘鼎與山林，生處初一槩。", "均令四海間，如我常安泰。", "臨難無喜懼，與人共憂愛。", "百年但影殂，千載猶心在。", "風流不可追，超然八荒外。"]'),
('5936dcd8-c24d-440d-933d-45a857a19324','送王敦素歸金陵','王銍','宋','宋诗','song-poetry','','[]','曉踏河堤月，逢人問去舟。',48,'全唐诗/poet.song.110000.json','["曉踏河堤月，逢人問去舟。", "已爲羈旅客，更挽別離愁。", "索寞憐同姓，丁寧數舊遊。", "欲知幽獨意，風露滿城秋。"]'),
('f1f7b64c-5603-4d44-954c-160ef4df4117','洪駒父泛舟將過潁同張仲宗出餞席間留詩爲別且邀用韻  其一','王銍','宋','宋诗','song-poetry','','[]','已作分携計，尤傷送客歸。',48,'全唐诗/poet.song.110000.json','["已作分携計，尤傷送客歸。", "經行汝南郡，爲問漢陰機。", "晚菊饒秋色，丹楓带恨飛。", "平生無別泪，相對倍霑衣。"]'),
('07f8935b-4509-4ffa-bfc5-26cd403058ad','洪駒父泛舟將過潁同張仲宗出餞席間留詩爲別且邀用韻  其二','王銍','宋','宋诗','song-poetry','','[]','晚岸雲低月，相隨照夢歸。',48,'全唐诗/poet.song.110000.json','["晚岸雲低月，相隨照夢歸。", "行藏嘆人境，開闔在天機。", "身與江山遠，書尋鴻雁飛。", "薄情怨青女，偏解透征衣。"]'),
('898ce0e1-246a-440a-b61e-12e2c3102189','別高子勉兄弟','王銍','宋','宋诗','song-poetry','','[]','南北奔波歲月催，足間渾未洗塵埃。',64,'全唐诗/poet.song.110000.json','["南北奔波歲月催，足間渾未洗塵埃。", "休將舊事從頭說，且喜新年入手來。", "千里遠同傳信雁，一枝同插未開梅。", "濁醪有盡情無盡，醉入都門首重回。"]'),
('be73c3e0-edc3-454a-ad7e-06e3615a5ecf','別張自彊','王銍','宋','宋诗','song-poetry','','[]','燕子低飛入壞簷，柳條輕拂綠毿毿。',64,'全唐诗/poet.song.110000.json','["燕子低飛入壞簷，柳條輕拂綠毿毿。", "故園更在北山北，佳節可憐三月三。", "萬古愁多憑濁酒，九原事往落清談。", "都門別恨終難寫，滿眼風光思不堪。"]'),
('e3cd067c-cae4-46a9-9eaa-6268011ef9d6','和趙德麟','王銍','宋','宋诗','song-poetry','','[]','故國春濃懶縱觀，强尋幽境步蹣跚。',64,'全唐诗/poet.song.110000.json','["故國春濃懶縱觀，强尋幽境步蹣跚。", "風酣蕙草清香煖，煙濕杏花紅粉寒。", "但覺時光自催換，可憐人事幾悲酸。", "百年未必長于夢，虛作邯鄲枕上看。"]'),
('8528db58-3365-45ed-ab06-c658f33c7451','夢中賦秋望','王銍','宋','宋诗','song-poetry','','[]','閣小寒宜遠，林荒晚带風。',48,'全唐诗/poet.song.110000.json','["閣小寒宜遠，林荒晚带風。", "遥山秋色外，獨樹雨聲中。", "念起三生異，心傷萬境同。", "此邦非我里，隨意作流通。"]'),
('c0f2a096-6d9e-4b16-ac52-53774d04ed48','送楊道士歸蔡州','王銍','宋','宋诗','song-poetry','','[]','列子風回馭，林宗雨墊巾。',48,'全唐诗/poet.song.110000.json','["列子風回馭，林宗雨墊巾。", "花明千嶂晚，雲暖一山春。", "爐竈聊隨俗，簪裾未稱貧。", "壺公觀中路，聞道接天津。"]'),
('58bf2447-4a23-4c8d-ade4-34206789d31f','用前韻寄洪駒父  其一','王銍','宋','宋诗','song-poetry','','[]','共臨寒水別，獨趨暮春歸。',48,'全唐诗/poet.song.110000.json','["共臨寒水別，獨趨暮春歸。", "萬事風前燭，百年梭過機。", "應尋騎鶴客，重詠落霞飛。", "林葉終何補，京塵化舊衣。"]'),
('cf94b86a-28ab-46e8-9d4e-dc7ae761d867','用前韻寄洪駒父  其二','王銍','宋','宋诗','song-poetry','','[]','江山霜落木，千里一身歸。',48,'全唐诗/poet.song.110000.json','["江山霜落木，千里一身歸。", "去國憐張翰，回舟爲陸機。", "煙林無際遠，寒葉有聲飛。", "何必少陵老，悲傷未拂衣。"]'),
('162f6e35-aca5-4337-821d-8989f9fede54','徐師川典祀廬山延真觀用送駒父韻餞別四首  其一','王銍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','徐穉前風在，何勞白首歸。',48,'全唐诗/poet.song.110000.json','["徐穉前風在，何勞白首歸。", "書來寄文錦，詩報守寒機。", "駑驥難同力，鸞凰任自飛。", "前村幽獨意，且放酒淋衣。"]'),
('389c8747-f005-4a4f-a8d8-beba5de38fc4','徐師川典祀廬山延真觀用送駒父韻餞別四首  其二','王銍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','都門兩河路，誰送李膺歸。',48,'全唐诗/poet.song.110000.json','["都門兩河路，誰送李膺歸。", "人望終調鼎，親慈早斷機。", "漫虛崑閬集，不盡羽翰飛。", "酒聖君家事，霜清怯減衣。"]'),
('5a5eff86-698c-4ae7-a16b-935d799c9dd6','徐師川典祀廬山延真觀用送駒父韻餞別四首  其三','王銍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','丁令飛昇去，千年始一歸。',48,'全唐诗/poet.song.110000.json','["丁令飛昇去，千年始一歸。", "琳宮況廬岳，煙闕替塵機。", "洞口斜暉入，蒼崖素練飛。", "水雲會作伴，愧我薜蘿衣。"]'),
('c88d9726-f27f-43a0-a92f-23e301978c8a','徐師川典祀廬山延真觀用送駒父韻餞別四首  其四','王銍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','康阜如蓬島，欲尋風引歸。',48,'全唐诗/poet.song.110000.json','["康阜如蓬島，欲尋風引歸。", "煙藤猿嘯月，雲碓水鳴機。", "剩結餐霞侶，深隨杖錫飛。", "謝公行樂處，山翠撲人衣。"]'),
('8b94eadb-ad4b-4f01-80af-1083b477f671','送酒與許田史純風','王銍','宋','宋诗','song-poetry','','[]','塵土裝懷歲月侵，賤官情味我能任。',64,'全唐诗/poet.song.110000.json','["塵土裝懷歲月侵，賤官情味我能任。", "龍鍾老態渾非昨，索漠英游不可尋。", "蜨遶書窗空費夢，蟻浮玉琖不同斟。", "相望解寄重陽酒，滿路西風黄葉深。"]'),
('a9c365a7-ada9-410c-b72d-ba902f1d76d8','送李文若歸修水並弔其兄商老之亡','王銍','宋','宋诗','song-poetry','','[]','子去何悽斷，鄉關歲月新。',48,'全唐诗/poet.song.110000.json','["子去何悽斷，鄉關歲月新。", "荒山寒带雨，古驛夜無人。", "生死風前燭，音容夢裏身。", "臨分感平昔，揮淚到松筠。"]'),
('8db39530-6dd9-47af-bacb-2bb986af85f7','遊鴻福寺和關子東','王銍','宋','宋诗','song-poetry','','[]','劉家古寺城南曲，選得僧坊共醉吟。',64,'全唐诗/poet.song.110000.json','["劉家古寺城南曲，選得僧坊共醉吟。", "野草幽花閒自媚，黄蜂白蝶靜相尋。", "半簷落日留難住，滿地東風掃不禁。", "漫道青春一分在，池邊綠樹已成陰。"]'),
('0cd3e990-0340-45bc-b85f-9f3e3cf4a842','秋晚洛中道上','王銍','宋','宋诗','song-poetry','','[]','數雁橫空送斷霞，窮秋遊子向天涯。',64,'全唐诗/poet.song.110000.json','["數雁橫空送斷霞，窮秋遊子向天涯。", "泉甘野店黄粱酒，霜重荒原白菊花。", "滿目劫灰傷井邑，回頭佳氣戀京華。", "故人他日如尋我，試問雲溪舊釣沙。"]'),
('cb24d50a-590a-4b16-8940-67bf5d3b5f54','題沈休文八詠樓','王銍','宋','宋诗','song-poetry','','[]','詩人不見舊樓空，只見溪山與昔同。',64,'全唐诗/poet.song.110000.json','["詩人不見舊樓空，只見溪山與昔同。", "望處地寬閒白晝，坐來天濶剩清風。", "六朝遺恨沈衰草，八詠雄篇麗彩虹。", "何待吟哦清庾月，暫來佳賞自無窮。"]'),
('b5bcec03-b6ee-41eb-b305-9a82841f3802','幽居','王銍','宋','宋诗','song-poetry','','[]','幽居寂無事，晨起伴僧禪。',48,'全唐诗/poet.song.110000.json','["幽居寂無事，晨起伴僧禪。", "曉澹巖前月，秋明水底天。", "望鄉書斷雁，問路客回船。", "阻絕平生友，清遊有夢傳。"]'),
('a24a6bf9-b80d-4b51-a15c-3f99049cac9e','芭蕉','王銍','宋','宋诗','song-poetry','','[]','六曲欄干院宇深，影連苔色晝沈沈。',64,'全唐诗/poet.song.110000.json','["六曲欄干院宇深，影連苔色晝沈沈。", "已將虛實論因果，尤稱風流寫醉吟。", "夢短不禁簾外雨，愁多常怯檻邊陰。", "可憐今古無窮恨，卷在凋零如寸心。"]'),
('005e5154-b1eb-4000-be5b-65a9d509512a','別故人張孝先','王銍','宋','宋诗','song-poetry','','[]','平生嘗嘆少陵詩，豈謂殘年盡見之。',64,'全唐诗/poet.song.110000.json','["平生嘗嘆少陵詩，豈謂殘年盡見之。", "共脫兵戈身偶在，各懷鄉國語尤悲。", "又尋芳草春風路，猶聽孤舟夜雨時。", "避地海山周萬里，此行無處寄相思。"]'),
('3ac61268-6896-4232-b8ca-c70b962093bb','訪關子開兄弟于餘姚懷先世舊契','王銍','宋','宋诗','song-poetry','','[]','山嵇交契自當年，重到同鄉各愴然。',64,'全唐诗/poet.song.110000.json','["山嵇交契自當年，重到同鄉各愴然。", "百里山川清自舊，兩家子弟老于前。", "疎梅開處數枝玉，小雨來時一段煙。", "歲晚不調相會數，溪頭尚趁有歸船。"]'),
('261b5457-0f46-4508-b391-85840e894243','頃在廬山與故友可師爲詩社嘗次韻和予詩云空中千尺墮柳絮溪上一旗開茗芽絕愛晴泥翻燕子未須風雨落梨花重江碧樹遠連雁刺水綠蒲深映沙想見方舟端取醉酒酣風帽任欹斜後三十年避地剡溪山中時可師委蛻亦二紀矣靈隠明上人追和此爲贈感念存沒淚落衣巾因用韻謝之','王銍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','昔訪廬山惠遠家，尋春草木未萌芽。',64,'全唐诗/poet.song.110000.json','["昔訪廬山惠遠家，尋春草木未萌芽。", "自從柳折煙中色，不寄梅開雪後花。", "事往淚多添海水，詩來恨滿算河沙。", "驚回三十年前夢，放鶴峯頭日未斜。"]'),
('6a4f0649-d41a-4243-85ee-053b4e3983fc','溪上觀雪','王銍','宋','宋诗','song-poetry','','[]','沙洲蒼莽水雲昏，雪落寒溪鏡有痕。',64,'全唐诗/poet.song.110000.json','["沙洲蒼莽水雲昏，雪落寒溪鏡有痕。", "山際疏鐘煙際寺，林邊微逕水邊村。", "天涯歲月行將盡，人世窮愁孰與論。", "憶與鄒枚同賦詠，人非事往但心存。"]'),
('98c116c2-a7ae-475f-9cde-1bb87dc3dd1a','秀遠亭','王銍','宋','宋诗','song-poetry','','[]','鏡似冰壺表裏清，我來閒伴白雲行。',64,'全唐诗/poet.song.110000.json','["鏡似冰壺表裏清，我來閒伴白雲行。", "四山迤邐青圍野，一水蜿蜒綠繞城。", "試問春來觀秀色，何如雨後聽泉聲。", "昔人飛馭煙霞外，落日空懷萬古情。"]'),
('e9143f5d-32e0-4ecc-81b0-7bf646f1b098','送呂道師還天台山','王銍','宋','宋诗','song-poetry','','[]','結宇孤峯蘚徑危，身閒鷗鳥信忘機。',64,'全唐诗/poet.song.110000.json','["結宇孤峯蘚徑危，身閒鷗鳥信忘機。", "水聲山色何今古，物態人情果是非。", "子踏白雲來問道，我垂華髮自生輝。", "赤城歸去松門晚，萬里秋風上客衣。"]'),
('31896457-77a8-4043-95e2-8652f269bf33','早秋寄昔慧老且弔慈受老師之亡','王銍','宋','宋诗','song-poetry','','[]','昔日禪河早預流，老尋支許剡中遊。',64,'全唐诗/poet.song.110000.json','["昔日禪河早預流，老尋支許剡中遊。", "一枝數粒同過夏，萬壑千巖相映秋。", "眼看珠沈滄海底，心傷塔就亂峯頭。", "不須月落龍天泣，萬古白雲無去留。"]'),
('dc7a1fe4-a28b-4812-a049-2227caa1e26d','送孫肖之還縉雲','王銍','宋','宋诗','song-poetry','','[]','蓬蒿頻歲掩鄉關，再喜相逢一破顔。',64,'全唐诗/poet.song.110000.json','["蓬蒿頻歲掩鄉關，再喜相逢一破顔。", "遊子年華紅葉老，幽人風味白雲閒。", "那知篋裏書成後，猶作溪邊興盡還。", "流落天涯俱避地，念君更入萬重山。"]'),
('47e0b920-5e75-4b02-bd4f-4848c545b25b','送郭壽翁還廬陵','王銍','宋','宋诗','song-poetry','','[]','共遭胡騎汝陰城，十載相逢尚甲兵。',64,'全唐诗/poet.song.110000.json','["共遭胡騎汝陰城，十載相逢尚甲兵。", "萬里鵷鴻自鶱舉，九關虎豹任縱橫。", "雨昏山遠行人恨，日暮草長幽鳥聲。", "只有別離心似舊，亂來難得是交情。"]'),
('5d7a76f4-063f-4167-b0f8-2e59fce3cf1b','與郭壽翁俱客錢塘壽翁歸吉州追餞至龍山白塔寺惜別悵然終日始登車而去既行旬日予得請廬山太平觀將歸隠浙東山中寄詩奉懷','王銍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','江邊孤寺舊曾經，重枉驪駒當短亭。',64,'全唐诗/poet.song.110000.json','["江邊孤寺舊曾經，重枉驪駒當短亭。", "落日催人心去住，東風回首淚飄零。", "魂歸但覺楓林黑，書就終期汗簡青。", "歸隠我無衝斗氣，相思時望少微星。"]'),
('187c9f34-5166-4877-8b27-d5776b3aacdc','送謝景思假太常少卿奉祀溫州太廟先至三衢省覲','王銍','宋','宋诗','song-poetry','','[]','神遊眇邈海邊城，捧詔躬祠盛此行。',64,'全唐诗/poet.song.110000.json','["神遊眇邈海邊城，捧詔躬祠盛此行。", "九代衣冠漢原廟，百年禮樂魯諸生。", "東山世德聲名早，南省仙班氣象清。", "曉雨都門携錦帳，路人更羨綵衣榮。"]'),
('60f945f1-16d3-4792-a18d-80e38f82227b','古意','王銍','宋','宋诗','song-poetry','','[]','有恨匆匆別，無期緩緩歸。',48,'全唐诗/poet.song.110000.json','["有恨匆匆別，無期緩緩歸。", "天涯作孤客，樓上對斜暉。", "目斷路不斷，魂飛花更飛。", "無多清滴淚，恐損別時衣。"]'),
('823db36d-5e82-4863-bb7a-d43a622f1f25','寒食','王銍','宋','宋诗','song-poetry','','[]','故國千峯外，孤舟一水濱。',48,'全唐诗/poet.song.110000.json','["故國千峯外，孤舟一水濱。", "天涯未歸客，江上欲殘春。", "雁去銷魂久，花開墜淚頻。", "東風吹晚雨，芳草路邊人。"]'),
('aaef1c54-eaa3-448e-be5b-f6f0670608c4','病中','王銍','宋','宋诗','song-poetry','','[]','久知身是幻，况復病相侵。',48,'全唐诗/poet.song.110000.json','["久知身是幻，况復病相侵。", "古寺松篁瘦，山空雨雪深。", "定知書不達，豈有客相尋。", "伴我殘燈火，應知夜夜心。"]'),
('f9b2b354-a3d2-4177-b0e9-076f84550004','春近','王銍','宋','宋诗','song-poetry','','[]','山色銀屏曉，溪梅玉鏡春。',48,'全唐诗/poet.song.110000.json','["山色銀屏曉，溪梅玉鏡春。", "東風露消息，萬物有精神。", "索漠貧遊世，龍鍾老迫身。", "欲浮滄海去，風浪濶無津。"]'),
('e96faa46-97da-43ad-aca5-825874e02562','禹廟  其一','王銍','宋','宋诗','song-poetry','','[]','書稱堯舜沒，禹獨錫成功。',48,'全唐诗/poet.song.110000.json','["書稱堯舜沒，禹獨錫成功。", "須信賓天去，何疑窆石空。", "市聲朝夕變，山色古今同。", "誰與明真理，蒼崖松柏風。"]'),
('a7837788-2cc1-4a33-85e6-337b86cf48da','禹廟  其二','王銍','宋','宋诗','song-poetry','','[]','夏后東階殯，遺蹤照路隅。',48,'全唐诗/poet.song.110000.json','["夏后東階殯，遺蹤照路隅。", "今觀四山拱，猶似百神趨。", "功已百王冠，言尤萬世謨。", "死生懷舜德，舊邑對姚虞。"]'),
('0c76662a-5dc9-4215-85eb-05efa4d60dc2','八月十四日送葉子謙自會稽遊江觀湖歸閩','王銍','宋','宋诗','song-poetry','','[]','傾蓋論交意已傾，斷絃重續喜君聽。',64,'全唐诗/poet.song.110000.json','["傾蓋論交意已傾，斷絃重續喜君聽。", "山川妙意藏千古，天地神機在六經。", "朝夕事皆翻覆手，古人情寄短長亭。", "濤江君往觀秋注，萬頃漲溟無淺行。"]'),
('0fc38fa6-c2c7-4d77-9cb5-94e64eee987b','夜坐','王銍','宋','宋诗','song-poetry','','[]','夜久燈花自吐紅，歲華已盡尚飄蓬。',64,'全唐诗/poet.song.110000.json','["夜久燈花自吐紅，歲華已盡尚飄蓬。", "身遊百越風波外，路入千山雨雪中。", "失馬舊知無得喪，拂龜那更問窮通。", "懶將今古從頭數，幾度邯鄲夢不同。"]'),
('7f10843d-071e-47c3-87f7-2fc448108f8f','送僧秀遊海上諸山','王銍','宋','宋诗','song-poetry','','[]','丈室凝塵鎖寂寥，飄然更打衲僧包。',64,'全唐诗/poet.song.110000.json','["丈室凝塵鎖寂寥，飄然更打衲僧包。", "春風正滿碧溪水，落日偏宜紅杏梢。", "身外誰非追日杖，法中我是續絃膠。", "雲山煙海雖深廣，未抵安棲一把茅。"]'),
('47239f47-1ccf-443c-9230-c25839f0e655','十二月中旬書戴溪亭','王銍','宋','宋诗','song-poetry','','[]','天上東風轉斗星，天涯羈客尚飄萍。',64,'全唐诗/poet.song.110000.json','["天上東風轉斗星，天涯羈客尚飄萍。", "道塗况復經殘歲，風雪那堪宿旅亭。", "春到怯添雙鬢白，夜寒愁對一燈青。", "殘年萬古凄凉恨，不計樽前一醉醒。"]'),
('f116a3d1-b84b-4716-b0d2-e28b6379076e','重賦梅花','王銍','宋','宋诗','song-poetry','','[]','誰言今無返魂香，年年末上開孤芳。',64,'全唐诗/poet.song.110000.json','["誰言今無返魂香，年年末上開孤芳。", "韻高水天冷相照，清極雪月寒交光。", "姑射神仙瑩冰骨，水精宮人素霓裳。", "迎年送臘各愁絕，付與世間幽恨長。"]'),
('463faf17-e2cb-436d-88a4-862b1cf5521e','謝史純夫畫連昌宮圖頃歲京洛間作此今再觀舊本','王銍','宋','宋诗','song-poetry','','[]','筆下春風錦繡浮，花光山影照清流。',64,'全唐诗/poet.song.110000.json','["筆下春風錦繡浮，花光山影照清流。", "唐朝憂樂君新意，洛邑興衰我舊遊。", "急雨打成今夜夢，孤燈挑動昔年愁。", "此身此畫俱非實，白髮天涯萬事休。"]'),
('eaef5877-e696-4a4e-bc1e-ef63d60f9979','寄九峰覺老時自因勝退居','王銍','宋','宋诗','song-poetry','','[]','京江別我正堅冰，拂袖歸來道更增。',64,'全唐诗/poet.song.110000.json','["京江別我正堅冰，拂袖歸來道更增。", "又見嶺梅來驛使，懶將庭柏對談僧。", "半廊冷月溪山霧，一炷幽香殿閣燈。", "此亦世間愁絕處，嶺猿歲晚哭寒藤。"]'),
('62521a94-cfe9-4de2-ac8a-c2f63487a9fd','雪聲','王銍','宋','宋诗','song-poetry','','[]','飛滿前村夜不知，憑風聲與靜相宜。',64,'全唐诗/poet.song.110000.json','["飛滿前村夜不知，憑風聲與靜相宜。", "銀釭志士詩成後，玉枕佳人夢覺時。", "乍聽打窗投米急，想同糝徑落梅遲。", "孤舟曾向江湖宿，清入寒蘆韻更奇。"]'),
('72ed28bf-0124-4ff9-b438-3aaf9a33d979','梅花  其一','王銍','宋','宋诗','song-poetry','','[]','孤高來處自天人，末上常先萬物新。',64,'全唐诗/poet.song.110000.json','["孤高來處自天人，末上常先萬物新。", "不有大寒風氣勢，難開小朵玉精神。", "冰溪影鬭斜斜月，粉鏡粧成澹澹春。", "直伴東風到青子，多情不逐雪成塵。"]'),
('cb421fd0-8f72-40c9-8f62-92b3b19bba27','梅花  其二','王銍','宋','宋诗','song-poetry','','[]','古稱秀色若堪餐，冷豔幽香畫更難。',64,'全唐诗/poet.song.110000.json','["古稱秀色若堪餐，冷豔幽香畫更難。", "草木盡枯風正惡，雪霜初霽月偏寒。", "須知浄几明窗見，不似蒼山迥野看。", "羌笛一聲悲落盡，傷心何待百花殘。"]'),
('a9b954cb-cc37-4115-a774-a05656ef5af0','臨海僧珂公出梅花詩和其韻','王銍','宋','宋诗','song-poetry','','[]','天公飛雪鬭梅英，未有東風便有情。',64,'全唐诗/poet.song.110000.json','["天公飛雪鬭梅英，未有東風便有情。", "竹裏藏春春不覺，水邊見月月羞明。", "神人自惜迷姑射，天女何妨伴浄名。", "第一花中拈實相，談禪說法大修行。"]'),
('b1b39daf-46e5-4ed2-b5ae-78cbd01f3012','姜山通闍黎真骨歸塔以詩送之','王銍','宋','宋诗','song-poetry','','[]','空門龍象道高升，坐使山川勝氣增。',64,'全唐诗/poet.song.110000.json','["空門龍象道高升，坐使山川勝氣增。", "天道不言成四運，人間無處證三乘。", "雲深尚有遊山客，煙冷空餘禮塔僧。", "一葦莫嗟成萬古，幻身來往本何曾。"]'),
('92400dbb-2dcd-4c34-ad61-93dab855df96','剡溪月下泛舟','王銍','宋','宋诗','song-poetry','','[]','歲殘清夜一溪澄，更愛千峯霽月升。',64,'全唐诗/poet.song.110000.json','["歲殘清夜一溪澄，更愛千峯霽月升。", "天地高低銀色界，山川表裏玉壺冰。", "裘單擁火宜無倦，石響舟行恐不勝。", "休數興來并興盡，茲遊今古亦何曾。"]'),
('b4741b70-6ed7-4294-9568-921daa4f8f46','歲杪道中','王銍','宋','宋诗','song-poetry','','[]','巖風號萬木，天意自悲傷。',48,'全唐诗/poet.song.110000.json','["巖風號萬木，天意自悲傷。", "野店逢殘歲，危峯半夕陽。", "吾生猶道路，此恨付杯觴。", "正是凄凉極，寒梅逗晚香。"]'),
('aa9a3f5b-d653-44da-b77a-4f1040d0c56a','送黄生還臨安','王銍','宋','宋诗','song-poetry','','[]','舊事恍如前後身，龍門四紀更情親。',64,'全唐诗/poet.song.110000.json','["舊事恍如前後身，龍門四紀更情親。", "茅廬驚歎見斯客，天馬超騰感似人。", "三逕草荒殘歲雨，一枝梅作渡江春。", "莫言胡越方成別，纔隔雲濤莫問津。"]'),
('4aeab40a-9386-48bd-a38b-9b3baa78b908','再和雪聲','王銍','宋','宋诗','song-poetry','','[]','天上威儀地豈知，六花寒路夜偏宜。',64,'全唐诗/poet.song.110000.json','["天上威儀地豈知，六花寒路夜偏宜。", "半空環佩朝元罷，滿地珠璣按舞時。", "簌簌初隨風更急，蕭蕭却雜霰俱遲。", "房公松竹分清俗，除却天聲總未奇。"]'),
('9cfde96e-ec2f-4e99-ae98-600dd05c952f','舟行扶病訪王文孺曜菴且蒙和賜佳章次韻爲別','王銍','宋','宋诗','song-poetry','','[]','西風過雨冷孤雲，客路衰骸與病親。',64,'全唐诗/poet.song.110000.json','["西風過雨冷孤雲，客路衰骸與病親。", "煙渚好橫今夜笛，雲林還憶舊時人。", "凌空丹藥傳巖客，照水紅蓮賦洛神。", "老淚數行傷別盡，自憐無可更霑巾。"]'),
('8cedd04a-bbc8-4c91-996c-7ce7cfb54647','九月二十七日與客遊龍山','王銍','宋','宋诗','song-poetry','','[]','野服芒鞋步步同，天寒酒薄客情濃。',64,'全唐诗/poet.song.110000.json','["野服芒鞋步步同，天寒酒薄客情濃。", "身如萍水同千里，路入煙蘿更幾重。", "滄海清江共今古，黄花紅葉雜秋冬。", "暝雲自與千峯合，送我歸鞍寺寺鐘。"]'),
('2d316a5d-c56f-4c55-ac04-ea2b5ea2a89c','送無相祖老真骨歸塔','王銍','宋','宋诗','song-poetry','','[]','去來一念等孤雲，隻履西歸道更尊。',64,'全唐诗/poet.song.110000.json','["去來一念等孤雲，隻履西歸道更尊。", "落葉滿山新塔就，雨花盈几故經存。", "風清罷放林間鶴，月冷空啼嶺上猿。", "白髮來爲生死別，寒溪猶繞舊松門。"]'),
('938a7b96-0d89-42f5-b16d-af4329cd54ef','送嘉魚周尉','王銍','宋','宋诗','song-poetry','','[]','大門志與古人謀，萬卷詩書第一流。',64,'全唐诗/poet.song.110000.json','["大門志與古人謀，萬卷詩書第一流。", "文采聲華今有繼，死生契濶獨相求。", "天回凉色偏宜月，地近潮聲先带秋。", "此別頻書訪存沒，老人曾見綵衣遊。"]'),
('2165d1d2-1ab7-4892-b27a-93f0e9ce9c98','上巳日送韓簡伯','王銍','宋','宋诗','song-poetry','','[]','門戶荀陳士論僉，却隨王謝老江南。',64,'全唐诗/poet.song.110000.json','["門戶荀陳士論僉，却隨王謝老江南。", "一官傲世妨才命，萬事承家任苦甘。", "漁艇我將還舊隠，僧窗誰與對清談。", "落花風雨西陵渡，佳節可憐三月三。"]'),
('a9440df0-4108-4218-a565-74c1badb70f0','次韻梅花','王銍','宋','宋诗','song-poetry','','[]','廣寒宮裏自無倫，不祇塵中第一人。',64,'全唐诗/poet.song.110000.json','["廣寒宮裏自無倫，不祇塵中第一人。", "絕態乍辭天上舊，清香更占世間新。", "煙愁月恨迎回臘，日暖風遲俗却春。", "且對流年覓新意，橫斜疏影句皆陳。"]'),
('b1deed10-6934-45ad-9c72-f739a79ff270','望大梅欲回雪竇路險而止口占示同行','王銍','宋','宋诗','song-poetry','','[]','起曉尋幽意氣豪，冥冥重霧溼征袍。',64,'全唐诗/poet.song.110000.json','["起曉尋幽意氣豪，冥冥重霧溼征袍。", "天扶寶勢千山拱，海助寒聲萬籟高。", "休數興衰兩蝸角，從來憂樂一鴻毛。", "了知終老林泉是，渡水穿雲久亦勞。"]'),
('66bb84da-3f13-43bf-a73e-a180ff813486','倚樓曲','王銍','宋','宋诗','song-poetry','','[]','天邊皎月凝清光，圓缺不如人意長。',64,'全唐诗/poet.song.110000.json','["天邊皎月凝清光，圓缺不如人意長。", "夜來常娥和月落，清曉鏡裏看新粧。", "此情同生復同死，君似欄桿要堪倚。", "樓高風送管絃聲，腸斷五陵年少子。"]'),
('a9fec670-d4a0-41ce-a5d9-8bf36361f4d9','雜興效阮步兵','王銍','宋','宋诗','song-poetry','','[]','松巔負殘雪，高映寒食輝。',84,'全唐诗/poet.song.110000.json','["松巔負殘雪，高映寒食輝。", "衝風忽飄墮，勢若從天飛。", "庭虛四散入，凌亂侵人衣。", "衣重不忍拂，恐與清景違。", "援琴弄太古，聲淡節亦稀。", "衆笑己獨賞，恍然迷是非。", "乃知絕絃意，千載同依依。"]'),
('4d6125b0-48b0-4101-83db-12a341edb88c','賦得隔樹見秋燈','王銍','宋','宋诗','song-poetry','','[]','隔樹見秋燈，青熒更可愛。',72,'全唐诗/poet.song.110000.json','["隔樹見秋燈，青熒更可愛。", "半籠宜葉疎，微透嫌枝礙。", "深誤暗蟲投，靜窺栖羽在。", "望疑簾幕中，吟惜欄桿外。", "月到冷光幽，風來孤影碎。", "山客遥夜歸，耿耿如相待。"]'),
('b825b6c7-7557-42e2-92d7-156cbca5d970','游東陽涵碧亭劉夢得所賦詩也明日過中興寺遊覽終日記所見','王銍','宋','宋诗','song-poetry','','[]','我遊東陽城，隠侯昔所制。',288,'全唐诗/poet.song.110000.json','["我遊東陽城，隠侯昔所制。", "山川無古今，城邑有存廢。", "夢寐涵碧亭，草間得遺記。", "飛流落天明，噴灑寒玉碎。", "停車風雪中，豈特生秋意。", "李杜到韓劉，崢嶸相品次。", "景因真賞見，遺句細吟味。", "假蓋上前峯，提携有兒稚。", "明朝春開晴，步到中興寺。", "山僧引客遊，佳處相指示。", "羣峯四抱圓，浮煙生暖翠。", "唐年故刺史，宅作布金地。", "報以遺姓存，猶感邑中厲。", "寶月生旁邑，應真傳絕藝。", "峨峨畫三佛，張吳意能儷。", "氣象隨世低，病鶻無猛鷙。", "碑陰筆縱橫，才翁雄近世。", "疑是蘇躭鶴，去家已千歲。", "懷土一來歸，故畫華表字。", "上方有重閣，景與衆山會。", "一酌玻璃泉，碧色劍鋩淬。", "小叢相思樹，紅蘂粲丹荔。", "僧言此芳根，草木獨靈異。", "上枝花盡開，下實方委墜。"]'),
('97ecc526-e7ca-407a-8226-47df3feae4f1','剡溪王秀才畫子猷訪戴圖','王銍','宋','宋诗','song-poetry','','[]','剡溪萬壑千巖景，人境誰能識心境。',96,'全唐诗/poet.song.110000.json','["剡溪萬壑千巖景，人境誰能識心境。", "君畫山陰雪後船，始悟前人發清興。", "眼中百里舊山川，荒林雪月縈寒煙。", "應緣興盡故無盡，賓主不見寧非禪。", "當年戲留一轉語，不意丹青能再覩。", "更畫人琴已兩忘，妙盡子猷真賞處。"]'),
('aaed273a-609d-4540-9a75-3f04c6f63ca9','必明菴','王銍','宋','宋诗','song-poetry','','[]','佛心猶日出，何曾礙須彌。',168,'全唐诗/poet.song.110000.json','["佛心猶日出，何曾礙須彌。", "散爲普光明，合作四威儀。", "萬古止此日，羣目盡見之。", "普現一切水，君自分澠淄。", "高垂大圓鏡，君自存妍媸。", "方寸無盡燈，何處存思惟。", "高禪聞妙道，行作人天師。", "維摩開丈室，菴成更求詩。", "衆說列山岳，我以一理推。", "萬方聲一槩，我初拙言詞。", "至現莫如心，舉念周四維。", "必明乃本明，盡掃棘與茨。", "豈知都用晦，隠顯兩不知。", "大千在毫髮，聖言不吾欺。"]'),
('aecf4364-9654-4b3c-9778-2998d3859893','追和淵明九日閑居詩','王銍','宋','宋诗','song-poetry','','[]','白髮不堪鏡，殘骸寧久生。',108,'全唐诗/poet.song.110000.json','["白髮不堪鏡，殘骸寧久生。", "已是夢中事，那知身後名。", "古今黄花節，增重由淵明。", "後來杜與蘇，感慨皆同聲。", "乘化入無窮，留恨何千齡。", "令我過佳節，濁酒惟頻傾。", "豈比區中士，軒冕矜暫榮。", "滄溟芳歲晚，古寺久客情。", "洗滌流落歎，支公句新成。"]'),
('db3f37b2-ac82-42ff-a36b-a37a99db534e','畢少董繙經圖詩','王銍','宋','宋诗','song-poetry','','[]','我知君子有常心，誰謂春秋無定法。',304,'全唐诗/poet.song.110000.json','["我知君子有常心，誰謂春秋無定法。", "常心定法皆一途，萬變在前吾不惑。", "錦衣白馬青油客，回首傷心淪異域。", "縞带喜贈延州來，一見渾如舊相識。", "片時偷生萬年泣，倘得義成身乃立。", "已將死生委天公，要因筆削明吾迹。", "偃蹇榻上書千帙，坐使羣儒仆牆壁。", "凜然紬史行天誅，掃除坦塗大搜索。", "贊辭自昔非游夏，叛去于今無籍湜。", "鴻雁書聞到上林，管絃聲任來凝碧。", "嫣然侍側兩少麗，桃葉桃根莫能及。", "荳蔻梢輕露有華，早梅花嫩春無力。", "欲將婢子固君心，豈料君心堅鐵石。", "果聞遠使報還家，萬里精誠初不隔。", "書成初奏未央宮，金馬石渠皆動色。", "不與左氏作忠臣，忠欲天王坐中國。", "聖人大法先能識，節義大閑今獨得。", "傷麟嘆鳳非道窮，千載相逢猶咫尺。", "尊王便是祝釐心，聖人壽與天無極。"]'),
('275a3d76-a991-4b0b-af8e-9b40a8406986','和明上人見贈  其一','王銍','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖梅蕊暗香浮，錫杖凌空過沃洲。',64,'全唐诗/poet.song.110000.json','["西湖梅蕊暗香浮，錫杖凌空過沃洲。", "後會重尋人更老，頹光不駐水爭流。", "夕陽天際青山出，暝色煙中白鳥留。", "此境只曾支遁賞，剡溪今始得湯休。"]'),
('3d4fa1e0-d4a3-4337-b5c7-008de303c38e','和明上人見贈  其二','王銍','宋','宋诗','song-poetry','','[]','六見月華虧又盈，却來松下笑相迎。',64,'全唐诗/poet.song.110000.json','["六見月華虧又盈，却來松下笑相迎。", "事銷臘雪渾非舊，人似寒梅獨有情。", "香火舊緣生理足，煙霞新志著書成。", "明朝又入千峯去，猶恐時人識姓名。"]'),
('d02e946a-f888-4c7d-aafe-eca8bfb3e237','寄陳彥山','王銍','宋','宋诗','song-poetry','','[]','送君憶昔入鼇山，愁折江梅踏雪還。',64,'全唐诗/poet.song.110000.json','["送君憶昔入鼇山，愁折江梅踏雪還。", "別後重添十年老，靜中猶借半生閒。", "文章千古心空在，書史三冬手自刪。", "歲晚山中有琪樹，傷心何日得同攀。"]'),
('f30623f9-2884-49a1-96be-ca7b2fe677a4','中秋山間觀月','王銍','宋','宋诗','song-poetry','','[]','月出雲開天宇閒，幽居真賞異塵寰。',64,'全唐诗/poet.song.110000.json','["月出雲開天宇閒，幽居真賞異塵寰。", "冰輪孤掛夜千丈，玉露密零秋一山。", "莫望鄉關起愁色，勝居沙漠慘離顔。", "桂娥應恨無佳句，不識幽人到老閒。"]'),
('9389fe39-2b19-4b44-98cb-a2f9da1a1719','雨後登雙溪閣','王銍','宋','宋诗','song-poetry','','[]','夢寐登臨處，漂流來此行。',48,'全唐诗/poet.song.110000.json','["夢寐登臨處，漂流來此行。", "長年爲客意，落日倚欄情。", "雨過水光發，風生雲態輕。", "山川沈郎舊，巉絕有餘青。"]'),
('199636e8-66a3-4215-bc73-e7f2c7a3c024','剡溪久寓','王銍','宋','宋诗','song-poetry','','[]','山水戴逵色，尚餘清興中。',48,'全唐诗/poet.song.110000.json','["山水戴逵色，尚餘清興中。", "千巖落花雨，一徑卷松風。", "酒茗延幽子，圖書伴老翁。", "長生吾不羨，久悟去來同。"]'),
('4b3fb087-556b-4cc7-a31e-dac8bf3ac257','送史純夫出疆','王銍','宋','宋诗','song-poetry','','[]','悠悠遠水李膺舟，漠漠餘寒季子裘。',64,'全唐诗/poet.song.110000.json','["悠悠遠水李膺舟，漠漠餘寒季子裘。", "隔歲梅花新舊恨，入春山色古今愁。", "重游梁宋三千里，看復關河四百州。", "辯舌縱橫報知己，古人憑軾取封侯。"]'),
('8265ef4b-2787-479c-be04-f777a0431d9c','秋日','王銍','宋','宋诗','song-poetry','','[]','半落庭前葉，始知秋意新。',48,'全唐诗/poet.song.110000.json','["半落庭前葉，始知秋意新。", "風嚴柳疏細，霜薄水清勻。", "句裏存佳景，詩中見古人。", "一峯矜絕態，雲外掩孤顰。"]'),
('abd1f764-95d3-402e-81ed-8e197c258be5','小立','王銍','宋','宋诗','song-poetry','','[]','茅屋藤蘿外，憑欄煙靄間。',48,'全唐诗/poet.song.110000.json','["茅屋藤蘿外，憑欄煙靄間。", "亂蟬催暑去，急雨带秋還。", "路入雙溪口，門當四面山。", "詩成題未有，翰墨伴清閒。"]'),
('b84f857d-aeea-44c0-a289-74601a35cd42','將卜山居寄懷','王銍','宋','宋诗','song-poetry','','[]','山居香火伴殘經，幽絕全家在畫屏。',64,'全唐诗/poet.song.110000.json','["山居香火伴殘經，幽絕全家在畫屏。", "黄葉村藏一溪碧，白雲堆擁萬峯青。", "安知遇酒分賢聖，但可與人同醉醒。", "萬事休心惟白髮，更須結托老人星。"]'),
('783977ae-b187-4838-8560-0cbe4b0d44f3','除日得銅溪老人書','王銍','宋','宋诗','song-poetry','','[]','除日相思輒寄詩，流光不特我衰遲。',64,'全唐诗/poet.song.110000.json','["除日相思輒寄詩，流光不特我衰遲。", "歲窮滄海波濤急，天冷空山鳥獸悲。", "一氣先觀雲暖處，百花猶避歲寒枝。", "迎年送臘須臾夢，正似須彌不動時。"]'),
('c98e3947-6eb9-4d37-901e-834cda4ef177','望秋','王銍','宋','宋诗','song-poetry','','[]','門對萬山深，登臨老病侵。',48,'全唐诗/poet.song.110000.json','["門對萬山深，登臨老病侵。", "牛羊隨野色，草樹带秋陰。", "此景聊供望，何人肯見尋。", "猜鷗不用下，我自信無心。"]'),
('9f2e58fb-ebb6-4aa5-a2da-c65a24d077f7','病中','王銍','宋','宋诗','song-poetry','','[]','遥夜支頤坐，春醪負十分。',48,'全唐诗/poet.song.110000.json','["遥夜支頤坐，春醪負十分。", "碧烟沈宿靄，清月入微雲。", "真妄怯多病，翔潛喜不聞。", "鞦韆人樂處，十載愴離羣。"]'),
('6f7673e9-7837-4799-a4c1-d097cde46e7f','寄東山覺老','王銍','宋','宋诗','song-poetry','','[]','紅粧碧嶂舊登臨，來演真常契佛心。',64,'全唐诗/poet.song.110000.json','["紅粧碧嶂舊登臨，來演真常契佛心。", "漫道山林無獨往，那知笙磬有同音。", "堂前明月四時好，山外白雲千古深。", "此別松門無復見，漁樵爲伴老相侵。"]'),
('b1718974-741e-48af-b84e-19895d560746','陸左丞夫人鄭氏輓詞四首  其一','王銍','宋','宋诗','song-poetry','','[]','家學開皇紀，淑聲通德門。',48,'全唐诗/poet.song.110000.json','["家學開皇紀，淑聲通德門。", "內朝班早貴，中壺譽尤尊。", "聞說百年事，扶携兩世孫。", "從夫得文伯，萬古姓名存。"]'),
('a51f2710-f26d-4fe1-91b6-d8fbec01c194','陸左丞夫人鄭氏輓詞四首  其二','王銍','宋','宋诗','song-poetry','','[]','寒日明丹旐，流塵暗綵衣。',48,'全唐诗/poet.song.110000.json','["寒日明丹旐，流塵暗綵衣。", "那知長夜去，無復逝川歸。", "方士言終誤，神丹事已非。", "出門尋弔客，惟有鶴雙飛。"]'),
('4aa2628d-2a8c-4cd7-9ced-6672caec6af0','陸左丞夫人鄭氏輓詞四首  其三','王銍','宋','宋诗','song-poetry','','[]','軒冕三從盛，門庭五福優。',48,'全唐诗/poet.song.110000.json','["軒冕三從盛，門庭五福優。", "凄凉孝子淚，悲慟故山秋。", "楊子新阡啟，班昭舊史留。", "空堂對萱草，無復更忘憂。"]'),
('f1f4618a-992b-4296-af78-494f409e56a1','陸左丞夫人鄭氏輓詞四首  其四','王銍','宋','宋诗','song-poetry','','[]','貌燬欒欒棘，心傷蓼蓼莪。',48,'全唐诗/poet.song.110000.json','["貌燬欒欒棘，心傷蓼蓼莪。", "斷機慈訓在，懷橘孝思多。", "露草霑寒淚，雲山翠涌波。", "悲風感行路，楚輓不成歌。"]'),
('371ade1e-92a8-4b72-b2b3-69d8f58229c0','同賦梅花十二題 半開','王銍','宋','宋诗','song-poetry','','[]','一枝開破一年春，鬭蕊稠花總後塵。',32,'全唐诗/poet.song.110000.json','["一枝開破一年春，鬭蕊稠花總後塵。", "却恨無媒憐獨夜，月偷清影向何人。"]'),
('4f7c66f7-d8fc-4674-9df4-70cafb0da5f4','同賦梅花十二題 清晨','王銍','宋','宋诗','song-poetry','','[]','曉色宜春露蕊鮮，玉人斜插鬭清妍。',32,'全唐诗/poet.song.110000.json','["曉色宜春露蕊鮮，玉人斜插鬭清妍。", "新花更映新粧面，無限風光在鬢邊。"]'),
('175f7606-b986-471f-a2b4-8b14afc9619d','同賦梅花十二題 風前','王銍','宋','宋诗','song-poetry','','[]','清香自滿不因風，花氣迷人處處同。',32,'全唐诗/poet.song.110000.json','["清香自滿不因風，花氣迷人處處同。", "祇與吹開又吹落，春愁已在笛聲中。"]'),
('88111ee5-4dc3-43fa-b367-d247551b2cf4','同賦梅花十二題 月下','王銍','宋','宋诗','song-poetry','','[]','樽前舊厭繁多態，雪裏曾嫌淡少情。',32,'全唐诗/poet.song.110000.json','["樽前舊厭繁多態，雪裏曾嫌淡少情。", "何似天容開夜色，數枝寒玉轉輕盈。"]'),
('cb03030c-73b5-442e-ba50-6753e36e65bd','同賦梅花十二題 雪後','王銍','宋','宋诗','song-poetry','','[]','枝留晴雪色難分，似向殘粧試粉痕。',32,'全唐诗/poet.song.110000.json','["枝留晴雪色難分，似向殘粧試粉痕。", "恨滿前村花落處，萬重煙靄遠連雲。"]'),
('78fa2db3-0021-4744-9047-38c3d73fe14e','同賦梅花十二題 雨中','王銍','宋','宋诗','song-poetry','','[]','水泛殘香不可尋，更堪煙雨鎖花心。',32,'全唐诗/poet.song.110000.json','["水泛殘香不可尋，更堪煙雨鎖花心。", "祇知賜浴恩波重，未識和戎怨淚深。"]'),
('827d8178-2381-4b46-8736-54cd726cb6be','同賦梅花十二題 水邊','王銍','宋','宋诗','song-poetry','','[]','雪後溶溶嫩水通，滿枝煙雨暗春風。',32,'全唐诗/poet.song.110000.json','["雪後溶溶嫩水通，滿枝煙雨暗春風。", "試看照影橫斜處，渾似靚粧清鏡中。"]'),
('44a6a4b3-5a01-43ec-b69f-10c44a66ae29','同賦梅花十二題 竹外','王銍','宋','宋诗','song-poetry','','[]','枝上淡煙籠白雪，此君高節助清真。',32,'全唐诗/poet.song.110000.json','["枝上淡煙籠白雪，此君高節助清真。", "要知謝女姿容別，林下孤標迥出塵。"]'),
('cf5a4492-3dde-4c21-bff9-acec286fa0fd','同賦梅花十二題 江村','王銍','宋','宋诗','song-poetry','','[]','竹籬茅屋江郊路，未肯鬭粧塵市間。',32,'全唐诗/poet.song.110000.json','["竹籬茅屋江郊路，未肯鬭粧塵市間。", "小朵飄零水風晚，又隨殘月落關山。"]'),
('f34d3c45-85d1-48d8-a88e-05bdfc8b09fb','同賦梅花十二題 山館','王銍','宋','宋诗','song-poetry','','[]','窮塗遊子年華晚，折贈無人信手題。',32,'全唐诗/poet.song.110000.json','["窮塗遊子年華晚，折贈無人信手題。", "留戀清香忍回首，五更立馬斷橋西。"]'),
('e9266b37-4623-4d4d-a704-d9c4dee19709','同賦梅花十二題 薄暮','王銍','宋','宋诗','song-poetry','','[]','寒欺雪勒未逢春，照影今宵借月魂。',32,'全唐诗/poet.song.110000.json','["寒欺雪勒未逢春，照影今宵借月魂。", "可惜孤山吟已盡，後來幽絕幾黄昏。"]'),
('d2e01bf0-3e1e-42fc-b98e-0f248be0529e','同賦梅花十二題 欲謝','王銍','宋','宋诗','song-poetry','','[]','零落斜枝雪未乾，且垂薄暮護微寒。',32,'全唐诗/poet.song.110000.json','["零落斜枝雪未乾，且垂薄暮護微寒。", "大都榮悴人情別，我爲殘英特倚欄。"]'),
('cac8d9e6-a5fa-454a-a0c0-c4d28b3df38a','墨君十詠 弄雨','王銍','宋','宋诗','song-poetry','','[]','一段風煙筆下開，小枝带雨思縈迴。',32,'全唐诗/poet.song.110000.json','["一段風煙筆下開，小枝带雨思縈迴。", "障風一袖如相向，說與嫦娥淚落來。"]'),
('6617ec58-f2f9-4594-b8b1-886bd77c55a7','墨君十詠 藏巖','王銍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','小年輕別廬山道，林下微吟夜更幽。',32,'全唐诗/poet.song.110000.json','["小年輕別廬山道，林下微吟夜更幽。", "影落人行半巖月，五更風露一山秋。"]'),
('77bd61fb-1789-4c32-980a-3ffc1b059ca1','墨君十詠 露葉','王銍','宋','宋诗','song-poetry','','[]','秀色娟娟自出塵，曉枝更带露華新。',32,'全唐诗/poet.song.110000.json','["秀色娟娟自出塵，曉枝更带露華新。", "清風一至如相語，從此開簾來故人。"]'),
('3b1f3219-377d-4b42-b98d-8b570b783aeb','墨君十詠 霜節','王銍','宋','宋诗','song-poetry','','[]','春花秋月不同時，高節偏于墨色宜。',32,'全唐诗/poet.song.110000.json','["春花秋月不同時，高節偏于墨色宜。", "莫遣世間丹綠筆，等閒俗却歲寒枝。"]'),
('db4ad535-634c-41bf-857b-7cdb877865ae','墨君十詠 舞月','王銍','宋','宋诗','song-poetry','','[]','江樓月下夜聞歌，不奈忠州刺史何。',32,'全唐诗/poet.song.110000.json','["江樓月下夜聞歌，不奈忠州刺史何。", "輕嫋腰肢更清峭，柳枝何似竹枝多。"]'),
('bec38a7c-f852-4b4c-9133-365cf0a9f80e','墨君十詠 迸石','王銍','宋','宋诗','song-poetry','','[]','渭水侯多失舊封，平泉池館亂來空。',32,'全唐诗/poet.song.110000.json','["渭水侯多失舊封，平泉池館亂來空。", "青青石上何人賞，孤映暮山風雪中。"]'),
('78133e09-8546-4def-b8fb-0ae4c4bede44','墨君十詠 欺雪','王銍','宋','宋诗','song-poetry','','[]','愛竹高風已自賢，興來更泛剡溪船。',32,'全唐诗/poet.song.110000.json','["愛竹高風已自賢，興來更泛剡溪船。", "枝間清響風驚雪，憶得東林夜宿年。"]'),
('3475216b-ce03-46f5-aca7-3b665cab6bce','墨君十詠 雪梢','王銍','宋','宋诗','song-poetry','','[]','第五橋邊一徑遥，滿林野竹立江郊。',32,'全唐诗/poet.song.110000.json','["第五橋邊一徑遥，滿林野竹立江郊。", "鴛鴦浮破水涵影，翡翠壓斜風舞梢。"]'),
('046b31ba-d7ab-43cb-b1ff-42faee769215','墨君十詠 夜風','王銍','宋','宋诗','song-poetry','','[]','倚竹佳人生暮愁，那知情伴夜蟬幽。',32,'全唐诗/poet.song.110000.json','["倚竹佳人生暮愁，那知情伴夜蟬幽。", "一山風月龍吟罷，聲入江雲嫋嫋秋。"]'),
('e5f69433-4528-4df1-a682-3f94ecc154d0','墨君十詠 憶昔','王銍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡廬古寺暗松藤，曾宿寒巖最上層。',32,'全唐诗/poet.song.110000.json','["匡廬古寺暗松藤，曾宿寒巖最上層。", "火煖爐溫四山靜，前溪風雪後窗燈。"]'),
('dbd7adf9-ce17-416c-9e8a-0042556cf4ae','春郊  其一','王銍','宋','宋诗','song-poetry','','[]','不斷煙蕪起暮愁，無窮楊柳拂東流。',32,'全唐诗/poet.song.110000.json','["不斷煙蕪起暮愁，無窮楊柳拂東流。", "一聲歌罷香輪去，只有斜陽伴畫樓。"]'),
('2e80ddca-5b15-4c87-b79e-1a6a0ea4680f','春郊  其二','王銍','宋','宋诗','song-poetry','','[]','碧飛紅斷正傷春，萬里天涯一病身。',32,'全唐诗/poet.song.110000.json','["碧飛紅斷正傷春，萬里天涯一病身。", "芳草路長樓百尺，樓中更有憑欄人。"]'),
('fb95d749-4833-4c94-a02e-871b100742c7','曉發石牛','王銍','宋','宋诗','song-poetry','','[]','匆匆車馬出清晨，日淡風微已仲春。',32,'全唐诗/poet.song.110000.json','["匆匆車馬出清晨，日淡風微已仲春。", "松竹陰中山未盡，梅花林外有行人。"]'),
('1f34caa7-2561-40d0-af31-ff2de3dabc5a','山中夜聞風雨','王銍','宋','宋诗','song-poetry','','[]','空山清夜寒無寐，松檜摇聲風雨高。',32,'全唐诗/poet.song.110000.json','["空山清夜寒無寐，松檜摇聲風雨高。", "行盡江湖忘巖壑，猶疑遶屋盡波濤。"]'),
('2350c1d5-d8f6-47a8-ac1d-24cac2736728','芳草','王銍','宋','宋诗','song-poetry','','[]','會時曾憶梅籠雪，別後常懷月照沙。',32,'全唐诗/poet.song.110000.json','["會時曾憶梅籠雪，別後常懷月照沙。", "到底多情是芳草，長隨離恨遍天涯。"]'),
('c21bd8bc-b4a6-42d8-a4de-3bbd55aba1a5','晚望','王銍','宋','宋诗','song-poetry','','[]','春濃已伴客愁濃，門掩雨餘江上峯。',32,'全唐诗/poet.song.110000.json','["春濃已伴客愁濃，門掩雨餘江上峯。", "莫道夕陽無一事，遠顰眉黛更千重。"]'),
('4372d686-6ec4-4d79-a331-bb9cf71b51ca','杏花  其一','王銍','宋','宋诗','song-poetry','','[]','玉人半醉暈豐肌，何待武陵花下迷。',32,'全唐诗/poet.song.110000.json','["玉人半醉暈豐肌，何待武陵花下迷。", "記得鞦韆歸後約，黄昏新月粉牆西。"]'),
('7efbc05e-f36c-4d40-852a-33c83ba22cc7','杏花  其二','王銍','宋','宋诗','song-poetry','','[]','醉裏餘香夢裏雲，又隨風雨去紛紛。',32,'全唐诗/poet.song.110000.json','["醉裏餘香夢裏雲，又隨風雨去紛紛。", "人間春色都多少，莫掃殘英枉斷魂。"]'),
('f64f399f-4f6f-46f3-8957-6bfb30f51f19','古意','王銍','宋','宋诗','song-poetry','','[]','歌聲怨極珠難續，琴韻愁深水易分。',32,'全唐诗/poet.song.110000.json','["歌聲怨極珠難續，琴韻愁深水易分。", "公子何須賦巫峽，夢中真復有朝雲。"]'),
('59e80cd3-62ea-4a93-afa3-d112d00050a0','雨夜','王銍','宋','宋诗','song-poetry','','[]','去國襟懷離別情，夜眠雨驛嘆孤征。',32,'全唐诗/poet.song.110000.json','["去國襟懷離別情，夜眠雨驛嘆孤征。", "轉頭三十年前恨，猶聽當時枕上聲。"]'),
('10f1ee3b-5aa4-40bc-9046-84d4d51989d9','雪溪亭觀雨','王銍','宋','宋诗','song-poetry','','[]','晚雨廉纖正滿空，萬峯多在暝雲中。',32,'全唐诗/poet.song.110000.json','["晚雨廉纖正滿空，萬峯多在暝雲中。", "風回變態何深淺，坐看天施水墨工。"]'),
('9037064b-a11b-4397-9cea-3c8554bb9a69','山中早秋','王銍','宋','宋诗','song-poetry','','[]','蒼茫山口月西沈，瀟灑新秋院落深。',32,'全唐诗/poet.song.110000.json','["蒼茫山口月西沈，瀟灑新秋院落深。", "雨滴梧桐河漢淡，夢回猶記少年心。"]'),
('fc13523f-13e4-456a-8102-36b00242bd21','山居追凉','王銍','宋','宋诗','song-poetry','','[]','松門東路有柴關，凉卧清宵夢亦閒。',32,'全唐诗/poet.song.110000.json','["松門東路有柴關，凉卧清宵夢亦閒。", "更待海風來萬里，一天霜月滿空山。"]'),
('91a0e7e8-7ba3-4926-a55e-1ceaf3cfdc87','秋容','王銍','宋','宋诗','song-poetry','','[]','如畫羣峯從復橫，孤煙收盡片雲輕。',32,'全唐诗/poet.song.110000.json','["如畫羣峯從復橫，孤煙收盡片雲輕。", "天容常带秋容浄，萬里碧天新雨晴。"]'),
('4eb07513-eb74-4cb8-b1df-1dfd9295eab9','雪作望剡溪','王銍','宋','宋诗','song-poetry','','[]','玉樓瓊樹曉煙披，擁衲開門四望迷。',32,'全唐诗/poet.song.110000.json','["玉樓瓊樹曉煙披，擁衲開門四望迷。", "清曠世人誰似我，雪中更到子猷溪。"]'),
('204cd42d-0cff-414a-9750-4b15126cfba9','寄南巖悟禪師','王銍','宋','宋诗','song-poetry','','[]','雪後千峯玉刻成，瓊瑶寒照寺樓明。',32,'全唐诗/poet.song.110000.json','["雪後千峯玉刻成，瓊瑶寒照寺樓明。", "遥知禪老開窗坐，指點煙村看晚晴。"]'),
('fb3738f3-c64a-4434-ad34-bc65f079b833','雪晴閒渡西溪','王銍','宋','宋诗','song-poetry','','[]','雪後孤村一段煙，晴光遠射玉山川。',32,'全唐诗/poet.song.110000.json','["雪後孤村一段煙，晴光遠射玉山川。", "酒旗隔岸招閒客，獨上西溪渡口船。"]'),
('8f26902e-212b-4d7b-ab25-10c6d5956d1f','送淳上人遊九巖','王銍','宋','宋诗','song-poetry','','[]','殘菊孤花留暮秋，勞師問路亂山頭。',32,'全唐诗/poet.song.110000.json','["殘菊孤花留暮秋，勞師問路亂山頭。", "九巖只望孤雲去，舒卷如雲得自由。"]'),
('fc5efe21-3e6c-4c42-be68-fd29fc9afe5e','泉聲','王銍','宋','宋诗','song-poetry','','[]','娟娟山月半岩明，霜重樓臺夜氣清。',32,'全唐诗/poet.song.110000.json','["娟娟山月半岩明，霜重樓臺夜氣清。", "誰把玉琴來寫取，松風吹斷夜泉聲。"]'),
('c7110ad9-52ac-481c-b940-caa0b4ddd127','寄和邢子屑孫肖之始春見寄  其一','王銍','宋','宋诗','song-poetry','','[]','東風初到亂山頭，無數殘梅雨未收。',32,'全唐诗/poet.song.110000.json','["東風初到亂山頭，無數殘梅雨未收。", "何待傷春對晴景，暝雲橫盡古今愁。"]'),
('a8c2c6dd-fe11-4869-af01-ee7b275c304a','寄和邢子屑孫肖之始春見寄  其二','王銍','宋','宋诗','song-poetry','','[]','海山雪後海天寬，羣玉參差萬里寒。',32,'全唐诗/poet.song.110000.json','["海山雪後海天寬，羣玉參差萬里寒。", "岩谷無人共清夜，倚欄獨向月中看。"]'),
('bc3cf42d-86e6-4cea-a9c1-97909993c666','寄和邢子屑孫肖之始春見寄  其三','王銍','宋','宋诗','song-poetry','','[]','山林老去萬緣休，只有情鍾舊輩流。',32,'全唐诗/poet.song.110000.json','["山林老去萬緣休，只有情鍾舊輩流。", "芳草無窮山四向，斷腸人在最高樓。"]'),
('f9a6f696-7d44-4d77-af1a-3b979548ec24','憶廬阜寄機上人','王銍','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','憶在東林學夜禪，月中清響聽風泉。',32,'全唐诗/poet.song.110000.json','["憶在東林學夜禪，月中清響聽風泉。", "不須更作廬山夢，魚鳥相忘二十年。"]'),
('31c55dc9-7973-41cc-88e2-18d8d653799d','上方','王銍','宋','宋诗','song-poetry','','[]','松間清月佛前燈，菴在孤峯更上層。',32,'全唐诗/poet.song.110000.json','["松間清月佛前燈，菴在孤峯更上層。", "犬吠一聲秋意靜，敲門時有夜歸僧。"]'),
('04eda792-ec18-4556-a15f-d9e5e6e123a2','寒夜','王銍','宋','宋诗','song-poetry','','[]','淡月新霜似舊時，更憐秋與夜遲遲。',32,'全唐诗/poet.song.110000.json','["淡月新霜似舊時，更憐秋與夜遲遲。", "夢回一枕凄凉恨，帳外青燈不得知。"]'),
('c3941ef0-401d-48f1-a295-d8508cda1d66','晚意','王銍','宋','宋诗','song-poetry','','[]','山空寺古紫苔侵，更喜漁樵不見尋。',32,'全唐诗/poet.song.110000.json','["山空寺古紫苔侵，更喜漁樵不見尋。", "坐對秋陰晚蕭瑟，風吹敗葉入廊深。"]'),
('7911d181-c36b-43f4-b301-69a5b377c509','即事','王銍','宋','宋诗','song-poetry','','[]','住依溪口破殘村，身伴渡頭零落雲。',32,'全唐诗/poet.song.110000.json','["住依溪口破殘村，身伴渡頭零落雲。", "更向空山拾黄葉，姓名那有世人聞。"]'),
('28a2008b-b14a-4b58-9698-5d2e9dfdc0ba','南巖悟禪老見于山中同烹玉糝羹','王銍','宋','宋诗','song-poetry','','[]','我家峯頭最高層，落葉蒼苔不可登。',32,'全唐诗/poet.song.110000.json','["我家峯頭最高層，落葉蒼苔不可登。", "清坐與師烹玉糝，千岩風雨夜深燈。"]'),
('f8fb8a28-74bb-4915-a7a3-c498ddcf5aa9','明覺寺折梅','王銍','宋','宋诗','song-poetry','','[]','遥山天際斂眉峯，清淺溪邊淡粉容。',32,'全唐诗/poet.song.110000.json','["遥山天際斂眉峯，清淺溪邊淡粉容。", "薄暮寺橋人獨立，一燈明滅數聲鐘。"]'),
('e4d18c83-66af-4182-8f5d-a248cef05451','夜晴','王銍','宋','宋诗','song-poetry','','[]','雨脚初收天意晴，西風摇落夜寒清。',32,'全唐诗/poet.song.110000.json','["雨脚初收天意晴，西風摇落夜寒清。", "披衣自起開窗戶，落月一山高下明。"]'),
('fe5c52f9-bf42-46a1-b9cf-3e43db110da3','古漁父詞十二首  其一','王銍','宋','宋诗','song-poetry','','[]','漁父家風我所知，家風要與道相宜。',32,'全唐诗/poet.song.110000.json','["漁父家風我所知，家風要與道相宜。", "不懷貪餌吞鉤意，常似絲綸未下時。"]'),
('ea0fba07-59f6-403a-affc-570fd2cb2cc6','古漁父詞十二首  其二','王銍','宋','宋诗','song-poetry','','[]','雨中漁艇一聲歌，夾岸青林照碧波。',32,'全唐诗/poet.song.110000.json','["雨中漁艇一聲歌，夾岸青林照碧波。", "躍馬更誰思往事，紅塵千丈奈人何。"]'),
('5336f2ff-a313-437a-b8a4-c5d4c8ecef02','古漁父詞十二首  其三','王銍','宋','宋诗','song-poetry','','[]','萬里號風雪滿山，黄蘆晻靄水汪灣。',32,'全唐诗/poet.song.110000.json','["萬里號風雪滿山，黄蘆晻靄水汪灣。", "九衢朝馬愁泥滑，不識漁翁興未閒。"]'),
('763e0ebd-cba8-4e4a-a1fd-79336647952c','古漁父詞十二首  其四','王銍','宋','宋诗','song-poetry','','[]','風波穩處釣舟閒，雲去諸山暝不還。',32,'全唐诗/poet.song.110000.json','["風波穩處釣舟閒，雲去諸山暝不還。", "江面一峯何所似，青銅鏡裏綠雲鬟。"]'),
('801fabfe-960e-48bd-bd1b-1307c83a10ef','古漁父詞十二首  其五','王銍','宋','宋诗','song-poetry','','[]','千古高人張志和，浮家泛宅老煙波。',32,'全唐诗/poet.song.110000.json','["千古高人張志和，浮家泛宅老煙波。", "不應別有神仙界，祇此滄江一釣蓑。"]'),
('c46dde2c-6be5-4ba6-9b94-24336eae532a','古漁父詞十二首  其六','王銍','宋','宋诗','song-poetry','','[]','虞舜遺風遠可尋，煙波一棹古猶今。',32,'全唐诗/poet.song.110000.json','["虞舜遺風遠可尋，煙波一棹古猶今。", "九疑蒼莽三湘濶，盡是雲山韶濩音。"]'),
('a4bc2ade-4dc6-425f-acd2-dc3e370b9c6a','古漁父詞十二首  其七','王銍','宋','宋诗','song-poetry','','[]','曾見三閭屈大夫，强將清濁較賢愚。',32,'全唐诗/poet.song.110000.json','["曾見三閭屈大夫，强將清濁較賢愚。", "如今更覺前言拙，醒醉由來本不殊。"]'),
('b1ed94be-31c3-41b7-87ae-7affc590a0be','古漁父詞十二首  其八','王銍','宋','宋诗','song-poetry','','[]','風裊溪頭釣線多，戲魚無奈巧依荷。',32,'全唐诗/poet.song.110000.json','["風裊溪頭釣線多，戲魚無奈巧依荷。", "直須飄浄浮萍草，盡放青天照碧波。"]'),
('7be67377-d629-4c69-9a04-a011ea3bb9e8','古漁父詞十二首  其九','王銍','宋','宋诗','song-poetry','','[]','禹門三級浪千重，變化飛騰豈有蹤。',32,'全唐诗/poet.song.110000.json','["禹門三級浪千重，變化飛騰豈有蹤。", "寄語魚蝦休上釣，要看頭角是真龍。"]'),
('31410d3b-c209-4150-bee0-acfe2b31749e','古漁父詞十二首  其一○','王銍','宋','宋诗','song-poetry','','[]','得即歡欣失即憂，死生輪轉暗相讐。',64,'全唐诗/poet.song.111000.json','["得即歡欣失即憂，死生輪轉暗相讐。", "那知垂釣非真釣，只在絲綸不在鉤。", "船子禪師意未平，萬波要喻境中情。", "魚寒不食清池釣，何處歸舟有月明。"]'),
('3b29618a-4105-4726-8e7f-0d5306459b45','古漁父詞十二首  其一一','王銍','宋','宋诗','song-poetry','','[]','波清百尺見修鱗，水色天容自古新。',32,'全唐诗/poet.song.111000.json','["波清百尺見修鱗，水色天容自古新。", "昨夜西江浴明月，冰輪玉兔絕纖塵。"]'),
('398c649c-7ba5-4916-9097-254a184ba4f3','宿華岳觀','王銍','宋','宋诗','song-poetry','','[]','凌空老樹雪垂葉，壓屋梨花雪照人。',32,'全唐诗/poet.song.111000.json','["凌空老樹雪垂葉，壓屋梨花雪照人。", "深愧地仙教俗客，慇勤留看華山春。"]'),
('3e116a78-b637-4eb6-9999-c1ce78c4dce5','又二年經此再題','王銍','宋','宋诗','song-poetry','','[]','石壇流水共蒼苔，青竹林間一徑開。',32,'全唐诗/poet.song.111000.json','["石壇流水共蒼苔，青竹林間一徑開。", "可惜梨花飛已盡，前年游客始重來。"]'),
('3c873b5d-a5e9-4c2a-8259-eefd91fafea5','王子猷返棹處','王銍','宋','宋诗','song-poetry','','[]','我家住在剡溪曲，萬壑千山看不足。',32,'全唐诗/poet.song.111000.json','["我家住在剡溪曲，萬壑千山看不足。", "却笑當年訪戴人，雪夜扁舟去何速。"]'),
('80a91c30-9cf1-433e-abf7-c5096384c64b','倚吟閣','王銍','宋','宋诗','song-poetry','','[]','賀家湖東剡溪曲，白塔幽林聲斷續。',64,'全唐诗/poet.song.111000.json','["賀家湖東剡溪曲，白塔幽林聲斷續。", "雪中興盡酒船空，境高地勝何由俗。", "誰結禪居在上方，山房屈曲隨山麓。", "個中非動亦非靜，自有白雲簷下宿。"]'),
('db52a794-abf1-4555-b471-1e4590341ad8','剡坑探梅','王銍','宋','宋诗','song-poetry','','[]','嶺上寒梅自看栽，山斜一半似屏開。',32,'全唐诗/poet.song.111000.json','["嶺上寒梅自看栽，山斜一半似屏開。", "春寒點點枝頭雨，爲有東流水過來。"]'),
('814d0d58-ecdb-48b4-acbc-a8023b3d09e5','普惠寺','王銍','宋','宋诗','song-poetry','','[]','鏡裏形容水底天，定將何物喻真禪。',32,'全唐诗/poet.song.111000.json','["鏡裏形容水底天，定將何物喻真禪。", "心安便是毗盧界，盡日添香伴兀然。"]'),
('f1c10e57-b6c9-4276-8796-c278025214ac','歸鴻閣','王銍','宋','宋诗','song-poetry','','[]','初離江渚荻生芽，飛到龍荒雪滿沙。',32,'全唐诗/poet.song.111000.json','["初離江渚荻生芽，飛到龍荒雪滿沙。", "寄語不須傳信遠，將軍憂國不憂家。"]'),
('624df98c-c8d2-4172-9801-fb8c467d779c','妙庭觀用東坡韻  其一','王銍','宋','宋诗','song-poetry','','[]','侍宴瑶池更不歸，茂陵千古掛餘悲。',32,'全唐诗/poet.song.111000.json','["侍宴瑶池更不歸，茂陵千古掛餘悲。", "祇今山下傳遺姓，應守瓊田舊玉芝。"]'),
('35f88206-9392-4986-968d-fee6cee05dd4','妙庭觀用東坡韻  其二','王銍','宋','宋诗','song-poetry','','[]','山房書篆自磨丹，溪月還來照碧潭。',32,'全唐诗/poet.song.111000.json','["山房書篆自磨丹，溪月還來照碧潭。", "鼎懼神姦暗持去，道人聊保一枝安。"]'),
('10e8d905-493f-49e7-8400-e421fb0fc080','定光院','王銍','宋','宋诗','song-poetry','','[]','兵戈幾載劇波翻，去住優游僧自閒。',64,'全唐诗/poet.song.111000.json','["兵戈幾載劇波翻，去住優游僧自閒。", "已熟機緣到真際，久將生死斷人寰。", "沙明寒水月窺澗，露濕曉煙秋在山。", "一佛鏡中那是別，孤雲不離亂峰間。"]'),
('696b8fea-e3c4-44be-bdbc-d29a8e67963c','王文孺臞菴','王銍','宋','宋诗','song-poetry','','[]','全家高隠白雲關，事不縈懷夢亦閑。',32,'全唐诗/poet.song.111000.json','["全家高隠白雲關，事不縈懷夢亦閑。", "欵乃交撐漁市散，隔江城郭是人間。"]'),
('c40260e3-7cdf-4a99-b0e6-ff40286ad7f5','雲門寺','王銍','宋','宋诗','song-poetry','','[]','青山春又到，白髮策烏藤。',48,'全唐诗/poet.song.111000.json','["青山春又到，白髮策烏藤。", "已是他鄉客，還同寄住僧。", "瘦松黏凍雪，流水带寒冰。", "更覺蒼崖路，雲深不可登。"]'),
('ebbedea9-63f7-4cee-844b-2f911704f1e4','山村','王銍','宋','宋诗','song-poetry','','[]','家依溪口破殘村，身伴渡頭零落雲。',32,'全唐诗/poet.song.111000.json','["家依溪口破殘村，身伴渡頭零落雲。", "更向空山拾黄葉，姓名那有世人聞。"]'),
('70e02700-e545-4e5f-ad8f-e38392fbb517','僕在會稽泛舟至剡中是時雪遲梅子煙外萬枝夾岸幽香不斷蓋非人間世也友人廉宣仲在四明聞之作子猷訪戴圖見寄作長短句謝之仍書四絕句於圖後  其一','王銍','宋','宋诗','song-poetry','','[]','白玉花開碧玉彎，戴逵溪上謝公山。',32,'全唐诗/poet.song.111000.json','["白玉花開碧玉彎，戴逵溪上謝公山。", "若教當日逢斯景，肯道扁舟盡興還。"]'),
('d64fa4d5-d272-4b18-b948-faeb2bbbd6be','僕在會稽泛舟至剡中是時雪遲梅子煙外萬枝夾岸幽香不斷蓋非人間世也友人廉宣仲在四明聞之作子猷訪戴圖見寄作長短句謝之仍書四絕句於圖後  其二','王銍','宋','宋诗','song-poetry','','[]','越溪梅接剡溪濱，得意還成一景春。',32,'全唐诗/poet.song.111000.json','["越溪梅接剡溪濱，得意還成一景春。", "此日可憐高興盡，扁舟處處作東隣。"]'),
('15c8ffb2-b27c-4766-b057-9817400711c9','僕在會稽泛舟至剡中是時雪遲梅子煙外萬枝夾岸幽香不斷蓋非人間世也友人廉宣仲在四明聞之作子猷訪戴圖見寄作長短句謝之仍書四絕句於圖後  其三','王銍','宋','宋诗','song-poetry','','[]','山回水轉碧玲瓏，月在群山四合中。',32,'全唐诗/poet.song.111000.json','["山回水轉碧玲瓏，月在群山四合中。", "香滿一船梅勝雪，休誇訪戴畫屏風。"]'),
('e4c6e267-d2f8-43fa-863c-a5b704fccdca','僕在會稽泛舟至剡中是時雪遲梅子煙外萬枝夾岸幽香不斷蓋非人間世也友人廉宣仲在四明聞之作子猷訪戴圖見寄作長短句謝之仍書四絕句於圖後  其四','王銍','宋','宋诗','song-poetry','','[]','梅英與雪一般色，不得北風香不知。',32,'全唐诗/poet.song.111000.json','["梅英與雪一般色，不得北風香不知。", "懶咏尤思招隠句，先生今有畫中詩。"]'),
('cb050009-1b55-4ad3-9558-f142e2b97769','題惠安寺增勝堂','王銍','宋','宋诗','song-poetry','','[]','心是華嚴境，圓機更善根。',48,'全唐诗/poet.song.111000.json','["心是華嚴境，圓機更善根。", "一塵猶可見，十勝不爲繁。", "放鶴掃松逕，呼猿開竹門。", "妙高峯頂住，客到亦忘言。"]'),
('076aa232-d2ae-47e9-abc8-03fbc863b368','登挾溪亭','王銍','宋','宋诗','song-poetry','','[]','剡中何許隔林坰，無復明巒到眼明。',32,'全唐诗/poet.song.111000.json','["剡中何許隔林坰，無復明巒到眼明。", "頼有西南天一角，亂雲深處疊秋屏。"]'),
('e560c5a5-5bd6-488d-abf0-9d22c84f9ab9','送開公歸徑山','王銍','宋','宋诗','song-poetry','','[]','白頭住世我無日，破衲出家師妙年。',64,'全唐诗/poet.song.111000.json','["白頭住世我無日，破衲出家師妙年。", "衮繡門庭猶自妄，瓶盂蹤跡不離禪。", "鷄催曉月人奔渡，雁喚西風葉滿船。", "夢境相逢便相別，萬峰秋色正磨天。"]'),
('143470f8-b99d-4a6b-96ca-99e3234e63fa','句  其一','王銍','宋','宋诗','song-poetry','','[]','雲氣與山爲態度，月華借水作精神。',16,'全唐诗/poet.song.111000.json','["雲氣與山爲態度，月華借水作精神。"]'),
('7e870afe-18b9-422a-ae5c-82dffce7157e','句  其二','王銍','宋','宋诗','song-poetry','','[]','古驛路邊煙雨暮，孤莊籬畔水雲寒。',16,'全唐诗/poet.song.111000.json','["古驛路邊煙雨暮，孤莊籬畔水雲寒。"]'),
('2b3af2e2-1f22-428a-afff-2c5f70c58440','句  其三','王銍','宋','宋诗','song-poetry','','[]','杜宇啼時花正開。',8,'全唐诗/poet.song.111000.json','["杜宇啼時花正開。"]'),
('58763f8c-a83c-4e4b-b6c8-efd51b10af42','句  其四','王銍','宋','宋诗','song-poetry','','[]','慘慘風林叫竹雞，冥冥山路曉光微。',16,'全唐诗/poet.song.111000.json','["慘慘風林叫竹雞，冥冥山路曉光微。"]'),
('97c88033-0dca-49d8-a941-7a083975b22b','句  其五','王銍','宋','宋诗','song-poetry','','[]','盡在疎枝冷蘂中。',8,'全唐诗/poet.song.111000.json','["盡在疎枝冷蘂中。"]'),
('2ae20163-0c54-48bd-bdd6-7bb0dd9545c6','句  其六','王銍','宋','宋诗','song-poetry','','[]','一枝清峭臨荒岸。',8,'全唐诗/poet.song.111000.json','["一枝清峭臨荒岸。"]'),
('16abc40c-5890-45bf-b972-9771316dd156','句','范寅亮','宋','宋诗','song-poetry','','[]','寺藏螺髻頂，人在藕花心。',12,'全唐诗/poet.song.111000.json','["寺藏螺髻頂，人在藕花心。"]'),
('eecbfb7c-3c8d-4b8d-b186-5229070e7436','團練統制程公全哀輓  其一','程暘','宋','宋诗','song-poetry','','[]','江蹟留空壘，牙梟讖異徵。',48,'全唐诗/poet.song.111000.json','["江蹟留空壘，牙梟讖異徵。", "報君忠貫日，吞虜氣填膺。", "死戰悲楊業，生降唾李陵。", "哀榮褒典厚，主上已中興。"]'),
('cbd72918-47de-4fce-aef5-1fb5f06039f1','團練統制程公全哀輓  其二','程暘','宋','宋诗','song-poetry','','[]','舉宗南渡日，相恃得元戎。',48,'全唐诗/poet.song.111000.json','["舉宗南渡日，相恃得元戎。", "譜系通江左，家聲愧洛中。", "一抔埋寶劍，三錫負彤弓。", "誰念轅門士，哀歌徹昊穹。"]'),
('ea7a412d-9af6-4480-9fc4-c8ebd3d82657','謝自然','王儔','宋','宋诗','song-poetry','','[]','頗怪韓夫子，猶疑謝自然。',24,'全唐诗/poet.song.111000.json','["頗怪韓夫子，猶疑謝自然。", "至今成福地，自古有神仙。"]'),
('7e5243d4-5479-4a52-b9d7-baa34a87f6b4','桄榔庵賓燕亭','陳覺','宋','宋诗','song-poetry','','[]','秋來雨溢足池塘，華屋臨流四面凉。',64,'全唐诗/poet.song.111000.json','["秋來雨溢足池塘，華屋臨流四面凉。", "風颭圓荷翻翠蓋，水涵芳蘂艷紅粧。", "淡烟難掩天真色，薄月常供自在香。", "詩老未須譏瑣細，解陪梅菊到冰霜。"]'),
('7e7989af-dc84-4fce-a109-95a4253d75db','咸陽  其一','劉棐','宋','宋诗','song-poetry','','[]','父老壺漿迓義旗，亡秦誰復爲秦悲。',32,'全唐诗/poet.song.111000.json','["父老壺漿迓義旗，亡秦誰復爲秦悲。", "不曾被虐曾蒙德，十二金人各淚垂。"]'),
('2bbb5b0f-86c6-4644-a137-9f65e3264148','咸陽  其二','劉棐','宋','宋诗','song-poetry','','[]','玉殿珠樓二世中，楚人一炬逐煙空。',32,'全唐诗/poet.song.111000.json','["玉殿珠樓二世中，楚人一炬逐煙空。", "却緣火是秦人火，只與焚書一樣紅。"]'),
('2b66320f-0696-40dc-ab45-5641bbfe09cb','至石橋夜半風雨大作','劉棐','宋','宋诗','song-poetry','','[]','方廣即真華藏界，自他不隔一毫端。',32,'全唐诗/poet.song.111000.json','["方廣即真華藏界，自他不隔一毫端。", "龐眉大士常相見，猛雨豪風漫作難。"]'),
('b03c1a48-3f74-4864-8730-ef5fd480bcb7','題惠衆院','劉棐','宋','宋诗','song-poetry','','[]','雲迷鳥道嶺重重，松竹深藏釋子宮。',32,'全唐诗/poet.song.111000.json','["雲迷鳥道嶺重重，松竹深藏釋子宮。", "戎馬不曾來爾界，太平元在亂山中。"]'),
('a4ee3542-a4ce-4e5b-97ff-7036222d4721','遊南山','汪任','宋','宋诗','song-poetry','','[]','湞陽富佳致，無以過南山。',288,'全唐诗/poet.song.111000.json','["湞陽富佳致，無以過南山。", "山高雄地理，萬丈親雲端。", "攀援臨絕頂，氣象非塵寰。", "神存古廟貌，臺敞舊軒欄。", "青石生龍文，凜凜常風寒。", "縱目四無際，陡覺天地寬。", "直北二江合，水勢中分灘。", "灘橫水亦轉，曲折束成灣。", "羣峯自西來，險絕如函關。", "中虛左梵剎，地勝苾芻安。", "梵修祝聖壽，額自九重頒。", "旁有石一障，高下數畝間。", "或列如屏風，或方如僊壇。", "或立如駐馬，或走如奔帆。", "或側如虎卧，或曲如龍蟠。", "或嚴如衛吏，或羅如星官。", "或傴如老人，而枯其形顔。", "或儼如端士，而正其衣冠。", "或堆如雲霞，重疊而聚攢。", "或湧如波浪，攣屬而奔湍。", "或傾而復舉，如獵而獸跧。", "或騰而不下，如射而禽翻。", "或先後相續，如朝赴金鑾。", "或參差不齊，如兵方結圓。"]'),
('f336cd8a-efc4-4aac-9058-7ffe5ecb4b9e','定光室','汪任','宋','宋诗','song-poetry','','[]','古有如來號定光，百年真相爲重裝。',32,'全唐诗/poet.song.111000.json','["古有如來號定光，百年真相爲重裝。", "面前湧出香爐石，欲使人燒無盡香。"]'),
('f0630b43-595b-4abe-8bc4-00f03461c848','熙熙亭','汪任','宋','宋诗','song-poetry','','[]','中天未復舊山河，春日同民强一過。',32,'全唐诗/poet.song.111000.json','["中天未復舊山河，春日同民强一過。", "草草杯盤等閑置，愁多易覺醉顔酡。"]'),
('20efd16e-e61c-4c9e-8389-6a10abbece01','根輞巖','汪任','宋','宋诗','song-poetry','','[]','高巖古木根如輞，輞壞無根何處尋。',32,'全唐诗/poet.song.111000.json','["高巖古木根如輞，輞壞無根何處尋。", "下有唐人元傑記，讀之聊足慰登臨。"]'),
('40d0ef6f-0a33-4e16-979e-121a33f5ae44','臨清龕','汪任','宋','宋诗','song-poetry','','[]','地闢仙龕小亦奇，龕前長瀉碧琉璃。',32,'全唐诗/poet.song.111000.json','["地闢仙龕小亦奇，龕前長瀉碧琉璃。", "我來恰似陶彭澤，覽景濡毫便賦詩。"]'),
('1fc0d34a-5c95-4e83-983a-f871f21c81ba','煮茗臺','汪任','宋','宋诗','song-poetry','','[]','石梯千級杖藜行，行到山腰足暫停。',32,'全唐诗/poet.song.111000.json','["石梯千級杖藜行，行到山腰足暫停。", "旋汲靈泉煮佳茗，渴心滋潤困魔醒。"]'),
('9719499d-5349-4c0e-8e14-89399cf3ae55','寒翠亭','汪任','宋','宋诗','song-poetry','','[]','疊浪千堆霰雪寒，澄淵百尺瑠璃翠。',32,'全唐诗/poet.song.111000.json','["疊浪千堆霰雪寒，澄淵百尺瑠璃翠。", "江皋更展石屏風，特爲幽亭助嘉致。"]'),
('ff371247-96f2-4812-ac93-4412e7c07a19','雪山院','汪任','宋','宋诗','song-poetry','','[]','乘興挐舟到雪山，松篁門徑望中寬。',32,'全唐诗/poet.song.111000.json','["乘興挐舟到雪山，松篁門徑望中寬。", "翻思我佛修行處，景物雖殊道一般。"]'),
('9b7a5bd4-eea3-40ce-b5ae-45283868c293','伏闕辭歸','程康國','宋','宋诗','song-poetry','','[]','偶逢豺虎寢天關，事有當言恥口緘。',64,'全唐诗/poet.song.111000.json','["偶逢豺虎寢天關，事有當言恥口緘。", "不建侯藩控西北，別求何策保東南。", "幸投草野言無棄，退就山林老亦甘。", "束起舊書歸舊隠，遠依福曜炯台顔。"]'),
('82a2b642-249e-4851-a548-d91cfb9fa35c','題白雲巖','韓京','宋','宋诗','song-poetry','','[]','良辰尋勝到禪關，盡日澄懷水石間。',32,'全唐诗/poet.song.111000.json','["良辰尋勝到禪關，盡日澄懷水石間。", "白酒黄花聊自若，盛遊何必羨龍山。"]'),
('f70fb0e1-6637-461e-a630-f6eaff4f55f4','譏劉豫','建炎民謠','宋','宋诗','song-poetry','','[]','濃磨一錠兩錠墨，畫出千年萬年樹。',32,'全唐诗/poet.song.111000.json','["濃磨一錠兩錠墨，畫出千年萬年樹。", "誤得百鳥盡飛來，踏枝不著空飛去。"]'),
('53975e72-b94e-4603-b76a-fb06349cd2e3','題蘭亭帖','晁子綺','宋','宋诗','song-poetry','','[]','少游寫就蘭亭敘，逸少英姿殆昔人。',32,'全唐诗/poet.song.111000.json','["少游寫就蘭亭敘，逸少英姿殆昔人。", "我祖同爲長公客，每於翰墨契精神。"]'),
('bf532da3-9a93-4b39-a184-afea39eb4021','題常樂寺五雲堂','韋謙','宋','宋诗','song-poetry','','[]','吾匠慕先哲，至理皆融通。',48,'全唐诗/poet.song.111000.json','["吾匠慕先哲，至理皆融通。", "一法果有至，五雲凝在空。", "講香侵棐几，夜月鎖簾櫳。", "弋者何須預，冥冥出塞鴻。"]'),
('7d86c740-f133-4fa0-be80-eb7b6bd307a5','句','韓璜','宋','宋诗','song-poetry','','[]','願爲靖節妃。',6,'全唐诗/poet.song.111000.json','["願爲靖節妃。"]'),
('3269c7f7-75e2-4f51-ba94-995129a827a9','題東白山嘯猿亭','釋仲皎','宋','宋诗','song-poetry','','[]','放意在林表，飄然更自由。',48,'全唐诗/poet.song.111000.json','["放意在林表，飄然更自由。", "挂烟羣木冷，啼月一山秋。", "裊裊清風裏，凄凄碧澗頭。", "三聲融妙聽，行客若爲愁。"]'),
('8a7b69f9-c235-4dca-9c91-59a7d5060419','題東白山軒','釋仲皎','宋','宋诗','song-poetry','','[]','竹外泉聲急，松心月色寒。',24,'全唐诗/poet.song.111000.json','["竹外泉聲急，松心月色寒。", "人間推曠絕，只自倚闌干。"]'),
('96180fb0-9342-4674-8d7a-352b20961fba','遊西白山一禪師二禪師道場','釋仲皎','宋','宋诗','song-poetry','','[]','勝境東西白，高僧一二禪。',48,'全唐诗/poet.song.111000.json','["勝境東西白，高僧一二禪。", "只知行道處，不記住山年。", "澗月平分照，林花各自妍。", "披雲尋舊址，猶在絳峯邊。"]'),
('50570cae-f385-493a-8e44-dc09ee008644','題西白山齊雲閣','釋仲皎','宋','宋诗','song-poetry','','[]','山雲吹斷路頭開，此處疑穿月脅來。',32,'全唐诗/poet.song.111000.json','["山雲吹斷路頭開，此處疑穿月脅來。", "怪底行人看碧落，笑談容易作風雷。"]'),
('7e6a4e6e-53bf-4d41-a368-5c5627f54fe7','題西白山觀雪','釋仲皎','宋','宋诗','song-poetry','','[]','西白名山處，那堪踏雪觀。',48,'全唐诗/poet.song.111000.json','["西白名山處，那堪踏雪觀。", "四圍銀世界，一色玉峯巒。", "夜色和天冷，清輝放月寒。", "溪梅初一二，著意爲渠看。"]'),
('0b6c8c30-f898-499b-9671-d722de217653','菴居','釋仲皎','宋','宋诗','song-poetry','','[]','啼切孤猿曉更哀，柴門半掩白雲來。',96,'全唐诗/poet.song.111000.json','["啼切孤猿曉更哀，柴門半掩白雲來。", "山童問我歸何晚，昨夜梅花一半開。", "無地卓錐生計難，且空雙手到林間。", "猥隨碧水瞻明月，堅訂白雲賒好山。", "巖石空邊依草舍，藤蘿低處著松關。", "年來老去知何許，合向人間占斷閑。"]'),
('370ae42c-19b8-4ee1-b49f-9c0a89d2f83f','雪作望剡溪','釋仲皎','宋','宋诗','song-poetry','','[]','玉樓瓊樹曉煙披，擁衲開門四望迷。',32,'全唐诗/poet.song.111000.json','["玉樓瓊樹曉煙披，擁衲開門四望迷。", "清曠世人誰似我，雪中更對子猷溪。"]'),
('6e24b623-2ead-4dab-be43-8f4f0a042314','懷剡川故居  其一','釋仲皎','宋','宋诗','song-poetry','','[]','烟光流轉太駸駸，又見春山換綠陰。',64,'全唐诗/poet.song.111000.json','["烟光流轉太駸駸，又見春山換綠陰。", "蝴蝶夢中新歲病，杜鵑聲裏故鄉心。", "焦桐冷却風三尺，瘦竹拖來月一尋。", "早晚掉頭歸小隠，誅茅千嶂白雲深。"]'),
('a251f6f7-ef3b-45a0-b512-36eeabb88db8','懷剡川故居  其二','釋仲皎','宋','宋诗','song-poetry','','[]','斷雪流水古巖隈，憶得柴門半扇開。',64,'全唐诗/poet.song.111000.json','["斷雪流水古巖隈，憶得柴門半扇開。", "雪打子猷船上過，春從靈運屐邊來。", "逃禪野榻排芳草，覓句寒崖掃落苔。", "容易三年拋絕去，不勝啼月曉猿哀。"]'),
('dcca3221-2759-42b2-88da-9ec6c0fa51dd','懷剡川故居  其三','釋仲皎','宋','宋诗','song-poetry','','[]','病日飛蠅鬢雪乾，欲扶吾道愧衰殘。',64,'全唐诗/poet.song.111000.json','["病日飛蠅鬢雪乾，欲扶吾道愧衰殘。", "把他杓柄力何倦，還我钁頭心便安。", "待摘菜花添午供，便裁荷葉備春寒。", "不辭高卧烟霞裏，枕上青山最好看。"]'),
('411445bb-9c84-4f6c-ab9a-e40593c0c7ee','歸鴻閣','釋仲皎','宋','宋诗','song-poetry','','[]','精舍傍修嶺，道心隨眼明。',48,'全唐诗/poet.song.111000.json','["精舍傍修嶺，道心隨眼明。", "山遺僧偃跡，水作剡溪聲。", "無雨竹亦潤，有風松更清。", "上方真可住，不用觸歸情。"]'),
('890f2f49-d0ab-4a5e-ae0f-f7894bca54c3','歸雲亭','釋仲皎','宋','宋诗','song-poetry','','[]','一從飛出岫，舒卷意何長。',48,'全唐诗/poet.song.111000.json','["一從飛出岫，舒卷意何長。", "作雨徧天下，乘風歸帝鄉。", "無心憐灑落，到處自清凉。", "縹緲來空碧，吟邊带夕陽。"]'),
('0e5db7d8-5c31-44b4-8a1c-743946321435','送僧入三峰','釋仲皎','宋','宋诗','song-poetry','','[]','上人瞿曇裔，律身玉無瑕。',84,'全唐诗/poet.song.111000.json','["上人瞿曇裔，律身玉無瑕。", "力究毗尼論，汪汪海無涯。", "振錫復何許，三峯隠蒼霞。", "堂上大道師，靈芝發根芽。", "相見湧法施，鼕鼕鼓聲撾。", "上人從之游，勿憚歲月遐。", "坐待霜露熟，香風散天葩。"]'),
('baad7497-d1bd-450e-b795-e4a442fc0c91','牡丹','釋仲皎','宋','宋诗','song-poetry','','[]','玉棱金線曉妝寒，妙入天工不可干。',32,'全唐诗/poet.song.111000.json','["玉棱金線曉妝寒，妙入天工不可干。", "老去只知空境界，淺紅深紫夢中看。"]'),
('c21b4e7c-f33a-4074-9160-d209ce0fecb9','石巖花','釋仲皎','宋','宋诗','song-poetry','','[]','朱英歷歷爍晴空，過了花間幾信風。',32,'全唐诗/poet.song.111000.json','["朱英歷歷爍晴空，過了花間幾信風。", "明日畫欄供徙倚，却須有句到芳叢。"]'),
('3a214a06-9e65-4e6a-8c0d-57132aeef1ee','次韻王性之梅花  其一','釋仲皎','宋','宋诗','song-poetry','','[]','白玉叢邊碧玉流，見花無復爲花羞。',32,'全唐诗/poet.song.111000.json','["白玉叢邊碧玉流，見花無復爲花羞。", "春風細雨溪山路，洗盡去年今日愁。"]'),
('5a0db328-f8c3-47a8-a502-0c2fc65d3046','次韻王性之梅花  其二','釋仲皎','宋','宋诗','song-poetry','','[]','春到寒林雪得知，雪中誰解認芳姿。',32,'全唐诗/poet.song.111000.json','["春到寒林雪得知，雪中誰解認芳姿。", "溪山飛上一輪月，香滿風前獨立時。"]'),
('bf8c231e-38f8-4b25-b805-2e7c5621f56e','靜林寺古松','釋仲皎','宋','宋诗','song-poetry','','[]','古松古松生古道，枝不生葉皮生草。',32,'全唐诗/poet.song.111000.json','["古松古松生古道，枝不生葉皮生草。", "行人不見樹栽時，樹見行人幾回老。"]'),
('46460965-38af-499c-9eaf-3389a131e47a','句','釋仲皎','宋','宋诗','song-poetry','','[]','未飛三日雪，却報一枝春。',12,'全唐诗/poet.song.111000.json','["未飛三日雪，却報一枝春。"]'),
('791baca3-12cc-491e-94d5-e6ca25c86c48','山居','釋彥强','宋','宋诗','song-poetry','','[]','老矣毋能役，巖分草草綠。',48,'全唐诗/poet.song.111000.json','["老矣毋能役，巖分草草綠。", "放渠藜六尺，銷得屋三椽。", "雪盡收茶早，雲晴拾菌鮮。", "有時臨近澗，揎手弄潺湲。"]'),
('76a9d39f-30c2-4fa4-b602-50c28778187b','句','釋彥强','宋','宋诗','song-poetry','','[]','一間茅屋元無主，付與山頭野火燒。',16,'全唐诗/poet.song.111000.json','["一間茅屋元無主，付與山頭野火燒。"]'),
('3b0543cc-cb96-4fb8-bdba-97df5d63aa95','凉月','劉子翬','宋','宋诗','song-poetry','','[]','凉月未出山，浮雲半空白。',120,'全唐诗/poet.song.111000.json','["凉月未出山，浮雲半空白。", "徘徊步軒窗，宛若待佳客。", "經林漏飛輝，映溆生華澤。", "及茲秋景清，吾廬更幽寂。", "殊觀發祕藏，妙聽生寥閴。", "營營息初機，烱烱懷新得。", "豈無平生心，所樂已非昔。", "天旋河漢動，夜久鄰機息。", "淒淒感庭蘭，歲莫霜霰集。", "呼兒溫濁醪，獨酌醉永夕。"]'),
('5bd38893-1ba3-4681-8321-2430d9511c80','渡淮','劉子翬','宋','宋诗','song-poetry','','[]','鳴鼙渡長淮，霏烟散清晨。',120,'全唐诗/poet.song.111000.json','["鳴鼙渡長淮，霏烟散清晨。", "皎皎初日光，照耀草木新。", "橫林渡餘碧，疊嶂開嶙峋。", "移橈失向背，烟波浩無垠。", "兒童相櫂歌，余心亦欣欣。", "輕帆互相踰，畫鷁映流津。", "徘徊望洲渚，悠然獨懷人。", "樵漁有棲遯，寂寞誰問鄰。", "暮風翻洪濤，魚蝦亦有神。", "四顧天地黑，孤舟恐漂淪。"]'),
('f5308e5d-7420-4511-b8d7-085272cd3ad8','山陰作','劉子翬','宋','宋诗','song-poetry','','[]','地勢東南盡，清江吳越分。',120,'全唐诗/poet.song.111000.json','["地勢東南盡，清江吳越分。", "修塗雜川陸，游役念良勤。", "相從二三子，心期同所欣。", "逢幽不暫憇，何由解塵紛。", "抗跡蹈奇石，揚情矚流雲。", "崇林擁密翠，細草潛幽薰。", "蘭亭訪舊遊，昔嘗覽遺文。", "有生憐共盡，興懷豈惟君。", "逍遥千載上，逸興故不羣。", "風流詠觴樂，寂寂今無聞。"]'),
('44800e91-7b48-46c1-9010-dd8d581417d0','醉歌贈金元白','劉子翬','宋','宋诗','song-poetry','','[]','南游會稽今十年，重來風物皆依然。',256,'全唐诗/poet.song.111000.json','["南游會稽今十年，重來風物皆依然。", "一時冠蓋零落盡，故人獨老空江邊。", "西陵倉曹實冗散，出無車馬衆所憐。", "江亭曳履偶識面，凜凜瘦骨餘雙顴。", "談兵自是一敵國，屢薦不用寧非天。", "胸中跧伏萬貔虎，靜若女子容娟娟。", "我家光祿新出塞，羣彥入幕君宜先。", "自言衰髮已種種，豈復有意仍騰騫。", "强飯廉頗思故國，據鞍馬援忘華顛。", "只今左臂雖小病，尚想攬轡能周旋。", "興來且酌杯中酒，邊庭消息君知否。", "經天太一位臨坎，干戈喪亂已經久。", "南關兵敗上將戮，太原城破羣胡守。", "嗚呼國步危若此，每惜壯士時難偶。", "猝嗟未是真英雄，綸巾羽扇聊從容。", "何當矍鑠渡河去，一洗塞北烟塵空。"]'),
('edd0cdb1-ad26-4d51-81e6-7ef1fc1365ae','獨坐','劉子翬','宋','宋诗','song-poetry','','[]','獨坐高堂上，遊觀思無極。',120,'全唐诗/poet.song.111000.json','["獨坐高堂上，遊觀思無極。", "重門雖晝關，遠岫如不隔。", "長林葉布陰，淺澗流波激。", "欣欣物態榮，淑氣生原隰。", "幽禽感時鳴，繞樹飛還集。", "常恐逐驚飆，無階戀儔匹。", "興懷念良遊，歲月更相及。", "佳人獨棄余，何以慰岑寂。", "褰裳迷所向，望遠時佇立。", "心知徒百憂，沈思不能釋。"]'),
('8f518f88-9ef5-4048-9db1-33048127622a','次韵盧贊元再喜雪','劉子翬','宋','宋诗','song-poetry','','[]','史君新詩來不絕，燦燦珠星聯璧月。',128,'全唐诗/poet.song.111000.json','["史君新詩來不絕，燦燦珠星聯璧月。", "黄堂旌旆曉排衙，喜見賓僚重賀雪。", "寒儒茅屋補更穿，雪餘仍值江風顛。", "擬招鄰叟共一醉，斗酒十千愁費錢。", "南枝又見新梅萼，試熨春衫冷難著。", "飄零節物易驚心，常恐星星侵鬢脚。", "東閣何當呼侍兒，蟹螯不妨左手持。", "參陪後乘盡珠履，誰賦劉叉冰柱詩。"]'),
('e1a5d880-6863-4f5f-9886-78a01475bb79','霖雨','劉子翬','宋','宋诗','song-poetry','','[]','霖雨遂兼旬，瘴霧盈川谷。',108,'全唐诗/poet.song.111000.json','["霖雨遂兼旬，瘴霧盈川谷。", "霏陰入戶浮，潤氣滋帷褥。", "溟濛飛澤遠，散漫何時足。", "驟響决流渠，驚洪發平陸。", "翔禽困滯翼，穴獸思馮木。", "衡茅日萎壞，環堵無完築。", "曨匆晚色霽，草樹晞華沐。", "長雷夜復興，濯濯鳴高屋。", "撫枕不能寐，沈憂萃心曲。"]'),
('1da116ee-cd45-4bc2-8d42-1c9cc3f1ebbd','阻風','劉子翬','宋','宋诗','song-poetry','','[]','晚歲多悲風，江湖浪崢嶸。',96,'全唐诗/poet.song.111000.json','["晚歲多悲風，江湖浪崢嶸。", "扁舟渺無依，日暮猶孤征。", "重崗擁滯霧，迥隰飄浮霙。", "繫舟古岸邊，纜斷舟復橫。", "天寒鴻鴈稀，滯留知旅情。", "頹崖震林谷，客子心夜驚。", "披衣待清曉，缺月西南明。", "遠遊多所懷，益遣歸思盈。"]'),
('0eea63be-21c6-4df4-aae8-1f2e1ada5b68','聞箏作','劉子翬','宋','宋诗','song-poetry','','[]','月高夜鳴箏，聲從綺窗來。',144,'全唐诗/poet.song.111000.json','["月高夜鳴箏，聲從綺窗來。", "隨風更迢遞，縈雲暫徘徊。", "餘音若可玩，繁弦互相催。", "不見理箏人，遥知心所懷。", "寧悲舊寵棄，豈念新期乖。", "含情鬰不發，寄曲宣餘哀。", "一彈飛霜零，再撫流光頹。", "每恨聽者稀，銀甲生浮埃。", "幽幽孤鳳吟，衆鳥聲難諧。", "盛年嗟不偶，况乃容華衰。", "道同符片諾，志異勞百媒。", "栖栖牆東客，亦抱凌雲才。"]'),
('fd77dd19-d3c6-43fb-9cde-760691288296','建康六感 吳','劉子翬','宋','宋诗','song-poetry','','[]','龍翔大耳兒，虎視捉刀人。',120,'全唐诗/poet.song.111000.json','["龍翔大耳兒，虎視捉刀人。", "風雲競追逐，逸軌誰能遵。", "大皇負英材，沈潛欻求伸。", "一呼定南國，再戰威强鄰。", "抗魏既摇岳，攘劉亦披鱗。", "組練繞平隰，艨艟蔽通津。", "偉哉人物盛，成功豈無因。", "代祀已飄忽，風流久彌新。", "停橈眺迥陸，裂蔓登層闉。", "卧龍昔來遊，萬古懷清塵。"]'),
('032ceb3d-45e6-4320-b492-c948cb7fddf4','建康六感 晉','劉子翬','宋','宋诗','song-poetry','','[]','日昃無全照，南遷事倉忙。',120,'全唐诗/poet.song.111000.json','["日昃無全照，南遷事倉忙。", "龍謠方協瑞，星禍已告亡。", "凌遲百年運，凜凜危莫將。", "向來問鼎人，項背常相望。", "環宮白羽列，面闕鳴弦張。", "膺圖未躋泰，卜世豈在長。", "獨憐短轅公，推刃殺忠良。", "百身嗟莫贖，一慟鬢成蒼。", "時移事亦更，爲宋復爲梁。", "惟有采石潮，年年到前崗。"]'),
('0c9b8d97-b01c-4659-8eed-525d4d0fb735','建康六感 宋','劉子翬','宋','宋诗','song-poetry','','[]','寄奴真偉人，落拓龍潛地。',120,'全唐诗/poet.song.111000.json','["寄奴真偉人，落拓龍潛地。", "據筵呼五木，已有吞世氣。", "世期值陽九，天綱日淪替。", "偏邦或跨州，卑號猶稱帝。", "匪乘艱棘運，英姿疇能濟。", "南戡奠番禺，西狩澄涇渭。", "功雖與世隆，道亦因人廢。", "緬懷揖讓風，黄屋身如寄。", "頹波日奔迫，夜壑遷神器。", "巢由獨賢哉，高縱邈難繼。"]'),
('5fb06c56-5d30-44d7-8371-9b6e559a2573','建康六感 齊','劉子翬','宋','宋诗','song-poetry','','[]','堯宮不翦茨，禹室無崇壤。',120,'全唐诗/poet.song.111000.json','["堯宮不翦茨，禹室無崇壤。", "巍巍天步隆，萬代猶可仰。", "荒哉二三君，經營務華敞。", "落慥滿清江，飛斤殷遥響。", "疏淵引瀾澳，築圃遷林莽。", "筋力斃民軀，貲財傾國帑。", "雄心獨未倦，矯首生遐想。", "時徂陵谷變，無事猶悲曩。", "殷憂易興懷，逸樂難終享。", "過客問青棲，荒畦棘花長。"]'),
('093dee51-6290-46ee-95f8-bed88522b4e4','建康六感 梁','劉子翬','宋','宋诗','song-poetry','','[]','開圖屬英睿，失國由昏愞。',120,'全唐诗/poet.song.111000.json','["開圖屬英睿，失國由昏愞。", "斯人異前脩，撥亂旋致亂。", "輕刑下益肆，厚爵臣彌叛。", "聰明馳萬機，精苦徒宵旰。", "鳳冕敬方袍，鸞旗游彼岸。", "悠然棄從懷，臨機復難斷。", "那知千佛力，不紓一寇難。", "酒色覆商周，神仙蕩秦漢。", "趨亡固多軌，荒迷卒同貫。", "微聖常鮮終，撫冊三慨嘆。"]'),
('12c221e2-7983-40cf-a495-b4e74cf07c15','建康六感 陳','劉子翬','宋','宋诗','song-poetry','','[]','悲風嘯荒垣，歌斷庭花曲。',120,'全唐诗/poet.song.111000.json','["悲風嘯荒垣，歌斷庭花曲。", "璧月夜沈輝，瓊樹春銷馥。", "郊圻遊從盛，想像猶經目。", "麗景明新妝，清波映鮮服。", "承恩屬令姿，被選皆華族。", "朝從結綺遊，暮向臨春宿。", "意高時忽謝，步遠塗方促。", "榮華事不長，哀樂情難足。", "悠悠六朝事，轉眄風驚燭。", "永懷興亡端，斯文慚麗縟。"]'),
('de918851-e2c7-41df-b5f2-70aad32a08ce','夜飲','劉子翬','宋','宋诗','song-poetry','','[]','良宵樂未央，促席團欒坐。',84,'全唐诗/poet.song.111000.json','["良宵樂未央，促席團欒坐。", "佳人意慇懃，唱歌屬余和。", "幽期貴闊畧，醉語多叢脞。", "沈沈玉巵酒，量淺難負荷。", "豈不懷極懽，恐重賓友過。", "褰帷望明河，山月銜半破。", "回軒互追奔，傘拂簷瓦墮。"]'),
('7b04e8f4-f1df-4d27-b053-15f768b5d88b','遊朱勔家園','劉子翬','宋','宋诗','song-poetry','','[]','晨暉麗丹楹，翼翼侔帝居。',168,'全唐诗/poet.song.111000.json','["晨暉麗丹楹，翼翼侔帝居。", "向來堂上人，零落烟海隅。", "聯翩際時會，振跡皆刑餘。", "閨帷尚帝主，皁隸乘軒車。", "流威被東南，生殺在指呼。", "樓船載花石，里巷無袴襦。", "至今江左地，風雲亦嗟吁。", "叨榮已過量，受禍如償逋。", "荒凉戟門路，尚想冠蓋趨。", "客舸維岸柳，鄰人罾池魚。", "徘徊極幽觀，曲折迷歸途。", "夜月扃綺戶，春風散羅裾。", "繁華能幾時，喪亂實感予。", "曹鄶予何譏，此曹真人奴。"]'),
('114350d7-8ef9-4e01-8bd9-8719c185a1d3','孤翼吟','劉子翬','宋','宋诗','song-poetry','','[]','哀哀孤飛禽，聲鳴何悲酸。',144,'全唐诗/poet.song.111000.json','["哀哀孤飛禽，聲鳴何悲酸。", "含情若有訴，口訥無由宣。", "瞻雲憶舊侶，悠悠隔山川。", "勿言異類微，聚散同悲懽。", "零霜解疊翼，錯綵銷文翰。", "殞身未足辭，失意誠可憐。", "羣飛盡投林，凌空獨翩翩。", "豈無棲巢枝，託跡常不安。", "啄食朝競場，流飲暮爭源。", "鳴弦應機發，薄命當其先。", "長翮易奮飛，窮途少周旋。", "風雲肯借便，一舉誰能攀。"]'),
('e56339b5-d224-4ae0-9ab6-ae806cca00a7','早行','劉子翬','宋','宋诗','song-poetry','','[]','村雞已報晨，曉月漸無色。',24,'全唐诗/poet.song.111000.json','["村雞已報晨，曉月漸無色。", "行人馬上去，殘燈照空驛。"]'),
('6178484f-0e0b-4daf-a52f-e07ccc2b5866','寄懶菴','劉子翬','宋','宋诗','song-poetry','','[]','山暝雨連夕，今晨天氣清。',48,'全唐诗/poet.song.111000.json','["山暝雨連夕，今晨天氣清。", "遥懷懶菴人，高卧掩柴荆。", "幽寂性所嗜，蕭然寄平生。", "惟應田叟來，對床話躬耕。"]'),
('a5b7ff77-5341-4d18-b9ed-fa2f96385470','老農','劉子翬','宋','宋诗','song-poetry','','[]','山前有老農，給我薪水役。',48,'全唐诗/poet.song.111000.json','["山前有老農，給我薪水役。", "得錢徑沽酒，醉卧山日夕。", "忘形與之語，妙理時見益。", "志士多隠淪，欲言慚未識。"]'),
('551201d0-63ea-4254-9773-40b9543241d7','次四六叔韵','劉子翬','宋','宋诗','song-poetry','','[]','吾家小步兵，辭林獨輝映。',120,'全唐诗/poet.song.111000.json','["吾家小步兵，辭林獨輝映。", "携詩過山堂，句挾風雲潤。", "思嵇遠命駕，訪戴屢乘興。", "訂古釋羣疑，談玄發清聽。", "年均愧質滯，稟異驚才峻。", "頼茲時發揮，藥石攻余病。", "提携蘭畹曲，笑語柴門靜。", "歸軒騖急響，行炬飄遺燼。", "平生共飄流，晚歲同棲遁。", "語言聊寫懷，補綴酬斯詠。"]'),
('a9479b27-c16d-41a8-a510-e26727f8ca67','題懶菴  其一','劉子翬','宋','宋诗','song-poetry','','[]','幔亭隠淪翁，作菴更名懶。',48,'全唐诗/poet.song.111000.json','["幔亭隠淪翁，作菴更名懶。", "紛紜萬念繁，要以一理遣。", "我衰百無長，此興復不淺。", "他時儻卜鄰，心賞符二阮。"]'),
('c6268818-0b3b-451b-acc3-ad30a813a9c8','題懶菴  其二','劉子翬','宋','宋诗','song-poetry','','[]','地偏賓至稀，晝靜門常掩。',48,'全唐诗/poet.song.111000.json','["地偏賓至稀，晝靜門常掩。", "深房紙瓦明，宴坐蒲團穩。", "庭花落未掃，徑草繁不剪。", "林泉倦出遊，况乃市朝遠。"]'),
('d9064213-d080-4f07-b813-7be91b06e09d','種菜','劉子翬','宋','宋诗','song-poetry','','[]','傍舍植柔蔬，携鋤理荒穢。',48,'全唐诗/poet.song.111000.json','["傍舍植柔蔬，携鋤理荒穢。", "桔槔勤俯仰，一雨功百倍。", "朝來綠映土，新葉摇肺肺。", "牛羊勿踐畦，肉食屠爾輩。"]'),
('79b78df3-f7ea-486c-aea2-818d38a4c445','晨興','劉子翬','宋','宋诗','song-poetry','','[]','晨興訪蕭寺，爽氣清如沐。',48,'全唐诗/poet.song.111000.json','["晨興訪蕭寺，爽氣清如沐。", "坐看雨離山，飛陰斷平陸。", "歸途阻夕漲，竚立驚幽獨。", "曳杖聽殘鐘，却寄僧坊宿。"]'),
('2c7bdf69-6c1d-40ce-a3ff-69d6b586a757','袖刺','劉子翬','宋','宋诗','song-poetry','','[]','袖刺謁諸鄰，徘徊寄心賞。',48,'全唐诗/poet.song.111000.json','["袖刺謁諸鄰，徘徊寄心賞。", "潭潭廣厦深，咳唾生餘響。", "茲邦懷地寶，比屋誇雄敞。", "如何蓬廬士，貧賤安所養。"]'),
('72a3ad8b-e1c0-4c9b-8374-901b648505b4','同翁士特李似表謁巽伯少卿因作醉歌','劉子翬','宋','宋诗','song-poetry','','[]','翁劉異氏居同里，奕葉論交今久矣。',208,'全唐诗/poet.song.111000.json','["翁劉異氏居同里，奕葉論交今久矣。", "隴西京兆實姻連，我既識翁因識李。", "巽卿自洛始遷閩，寄食僧房仍密邇。", "盍簪雅好有新舊，傾蓋高情無彼此。", "酣歌擲劍悲羣公，胡爲局促荒山中。", "曲肱放浪雖所樂，樂此亦知吾道窮。", "自聞胡馬再南牧，九州何地無兵戎。", "世衰成敗不以正，姦宄得意爲英雄。", "儒生守經昧時變，憤切氣欲摩蒼穹。", "斯言撥棄勿復理，把酒論詩差可喜。", "圍爐夜語忘刻漏，吹燈曉色盈窗几。", "歸塗草棘縈風袍，主人謝客僕御勞。", "雲山悵望一回首，虎豹出穴哀猿號。"]'),
('1c842adf-1f26-4c35-995a-76f6bf370568','下灘作','劉子翬','宋','宋诗','song-poetry','','[]','青山鎖連環，白間走鳴瀨。',96,'全唐诗/poet.song.111000.json','["青山鎖連環，白間走鳴瀨。", "迷津毫髮間，舟與危石會。", "回淵聚浮沫，斷壁餘澎湃。", "玩奇心若驚，覽景目不逮。", "悠然一回首，孤驛已茫昧。", "停橈念經歷，履地猶旋憒。", "悲風嘯枯林，暮野雲相蓋。", "隔船聞和歌，沽酒慰疲怠。"]'),
('560376bb-2d77-412a-99bd-b061a9249342','偶步','劉子翬','宋','宋诗','song-poetry','','[]','鬰鬰思淫滯，振衣聊萍遊。',120,'全唐诗/poet.song.111000.json','["鬰鬰思淫滯，振衣聊萍遊。", "雲晴霄宇麗，綠暗川原幽。", "佇步時引顧，心期歎無儔。", "路逢荷犂翁，笑我獨何求。", "趨塵顧叩之，棄去不少留。", "心知所言非，齟齬自慚羞。", "歸來面空牖，默坐窮其由。", "達人隆廣度，曲士遵偏謀。", "臨歧每易惑，怨己識未周。", "行藏命也夫，吾非斯人流。"]'),
('d282183c-dd6b-40ed-9339-2fd81dff3d45','弔史','劉子翬','宋','宋诗','song-poetry','','[]','禽殫繁弱棄，兔盡韓盧烹。',120,'全唐诗/poet.song.111000.json','["禽殫繁弱棄，兔盡韓盧烹。", "英雄起乘時，時徂力難爭。", "精魂閉尺穴，壯骨颺飛塵。", "淒涼千載下，聞風凜如生。", "嬴秦失其鹿，圖王各崢嶸。", "斯人顧眄間，漢楚分重輕。", "臣雖替末路，君亦寒初盟。", "豈不念疇昔，百戰同艱辛。", "誰云漢網疏，豪俊屢拂縈。", "高蹈欣繫解，括囊聞飲醇。"]'),
('4d0dbe64-06b7-44e0-8362-c1400a3e77b7','雙樹','劉子翬','宋','宋诗','song-poetry','','[]','猗猗映門樹，團團若雙蓋。',48,'全唐诗/poet.song.111000.json','["猗猗映門樹，團團若雙蓋。", "微風薄層霄，彷彿鬭清籟。", "逍遥步其下，秀色吾所愛。", "秋來霜葉紅，飄落不相待。"]'),
('56a326ab-feb3-4997-960e-6b3dceb12bdd','懷致中','劉子翬','宋','宋诗','song-poetry','','[]','夢覺殘夜永，山寒氣逾清。',108,'全唐诗/poet.song.111000.json','["夢覺殘夜永，山寒氣逾清。", "林幽萬籟息，月出虛堂明。", "披衣坐復起，懷人思空盈。", "經時不對面，素榻浮埃生。", "遥知念盍簪，臨風亦關情。", "褰幃望歧路，慨然欲宵征。", "無人導我先，何因識門庭。", "仰憑鴻雁飛，書詞寫深誠。", "詞多意莫宣，益遣幽恨并。"]'),
('3f620f32-82cd-408f-99d3-209cb2c3c7e3','棄竹夫人','劉子翬','宋','宋诗','song-poetry','','[]','愛憎情易遷，感物思鬰紆。',96,'全唐诗/poet.song.111000.json','["愛憎情易遷，感物思鬰紆。", "念昔未棄捐，嘗侍君子居。", "煩襟一披豁，雅抱何清虛。", "蹉跎怨時暮，凉德竟見疏。", "飛霜皓中庭，枵然委牆隅。", "的皪珠幃深，熒煌錦茵鋪。", "豈不懷舊恩，君心已非初。", "當年紈扇謠，抱恨同區區。"]'),
('bd593f32-bf7a-4f66-b85c-4208ec88e45e','江山突星石士特欲易爲獨醒有詩因次其韵','劉子翬','宋','宋诗','song-poetry','','[]','羣石翠參錯，茲峰峙雲林。',144,'全唐诗/poet.song.111000.json','["羣石翠參錯，茲峰峙雲林。", "突星名固誇，流傳經古今。", "幽姿儼向背，異態生晴陰。", "怒若抽翠筍，端如立瑶簪。", "不有融結奇，寧知化工深。", "翁郎丘壑人，籃輿越秋岑。", "崎嶇喪亂間，逢幽亦登臨。", "把酒視雲漢，浩歌散愁襟。", "著鞭雖後余，歸蹤畧相尋。", "獨醒訂訛謬，懷人識君心。", "政恐五字詩，光芒射奎參。", "玩味不可忘，寫之朱絲琴。"]'),
('a5c6b5ef-60fe-4bd2-8fd0-62a7fa793e34','秋懷','劉子翬','宋','宋诗','song-poetry','','[]','哲人嘆逝川，志士悲廩秋。',216,'全唐诗/poet.song.111000.json','["哲人嘆逝川，志士悲廩秋。", "流光不暫停，忽忽歲欲周。", "凉飆襲迥野，飛霜皓盈疇。", "華林失鮮輝，奔谿殺湍流。", "萬化儻日徂，吾生難獨留。", "而我苦不樂，彷徨復何求。", "世途多軌轍，今行非昔謀。", "徒遵耿耿意，齟齬固莫投。", "時乎不再來，豈余敢懷尤。", "王道炳日星，歷聘疲軻丘。", "歸歟既改旆，浩然亦回輈。", "寂寞甯子歌，棲遲長卿遊。", "客嘲徒自解，天問終不酬。", "長揖未免烹，說難竟遭囚。", "行藏或大謬，聖賢共悠悠。", "含思疚憤積，念往川途脩。", "煌煌青春姿，蹉跎恐茲由。", "諒非宏達觀，那能齊百憂。"]'),
('5584d0d0-3609-46a0-a5d7-8ad2766c41d5','四不忍  其一','劉子翬','宋','宋诗','song-poetry','','[]','草邊飛騎如煙滅，拉獸摧斑食其血。',64,'全唐诗/poet.song.111000.json','["草邊飛騎如煙滅，拉獸摧斑食其血。", "此時疾首念鑾輿，玉體能勝饑渴無。", "危城屑麴驚雲擾，簠簋無光天座杳。", "奮戈儻未雪深讎，我食雖甘何忍飽。"]'),
('3366fd1e-dc85-497c-b7aa-3990a68692e4','四不忍  其二','劉子翬','宋','宋诗','song-poetry','','[]','黄河鑿鑿冰成路，人語寒空氣成霧。',64,'全唐诗/poet.song.111000.json','["黄河鑿鑿冰成路，人語寒空氣成霧。", "此時泣血念鑾輿，玉體能勝凜冽無。", "蒼黄天步蒙塵去，畫衮飄零傷歲暮。", "飛書儻未伐姦謀，我服雖華何忍御。"]'),
('9b05e385-8fab-491d-b8e5-9c7cdd7937c5','四不忍  其三','劉子翬','宋','宋诗','song-poetry','','[]','平沙月轉旌旗影，擐甲爲衾戈作枕。',64,'全唐诗/poet.song.111000.json','["平沙月轉旌旗影，擐甲爲衾戈作枕。", "此時飲恨念鑾輿，玉體能勝暴露無。", "問安使者空相繼，清蹕不回宮殿閉。", "請纓儻未縛酋渠，我榻雖安何忍寐。"]'),
('7e0bbefa-7d81-46ef-9fed-97f0eb8739f8','四不忍  其四','劉子翬','宋','宋诗','song-poetry','','[]','漁陽疊鼓風沙戰，潑水淋漓舞胡旋。',64,'全唐诗/poet.song.111000.json','["漁陽疊鼓風沙戰，潑水淋漓舞胡旋。", "此時太息念鑾輿，玉體能勝寂寞無。", "六宮遭亂多奔迸，不復梨園歌舞盛。", "著鞭儻未蹂龍庭，我瑟雖調何忍聽。"]'),
('2a5083c4-3dd1-4e73-a3cb-85bb6f31a17f','雲際贈施子','劉子翬','宋','宋诗','song-poetry','','[]','驚沙慘淡連雲起，曳杖悲歌行復止。',224,'全唐诗/poet.song.111000.json','["驚沙慘淡連雲起，曳杖悲歌行復止。", "春城是處聞鼓鼙，好風依舊開桃李。", "對花惆悵忽逢君，把酒無懽如啜水。", "六年喪亂兩相見，世路艱難嗟若此。", "江邊盜賊真遊魂，挾虜聲援圖并吞。", "金陵失守數騎入，會稽移蹕千官奔。", "只今州縣多阻絕，消息時聽行路說。", "百川背海欲西流，八柱搘天愁更折。", "苻堅陳亂丘山摧，夜聞鶴唳猶驚猜。", "莫輕赤壁一炬火，曹瞞氣焰隨飛灰。", "功名邂逅有快意，豈在今日無人哉。", "天方稔禍祕豪傑，故遣君輩多沈埋。", "亦知興衰運有極，天時一半因人力。", "男兒遇事不作難，看君赤手排荆棘。"]'),
('71318ae8-d524-46c2-b910-c8fe12d72200','望京謠','劉子翬','宋','宋诗','song-poetry','','[]','雙鑾北狩淹歸轂，寂寞梁園春草綠。',192,'全唐诗/poet.song.111000.json','["雙鑾北狩淹歸轂，寂寞梁園春草綠。", "猶傳故老守孤城，官軍不到黄河曲。", "連雲樓櫓已灰燼，更倚窗扉防箭鏃。", "招兵太半出羣盜，繡䘿蒙衣屢翻覆。", "前宗後社力誅鉏，白刃如霜挂人肉。", "州橋燈火夜無光，夾道狐狸晝相逐。", "往時汴泗絕行舟，市糶十千塵滿斛。", "衣冠避胡多在南，胡馬却食江南粟。", "謀臣武士力俱困，海角飄摇轉黄屋。", "盤庚五遷方擇利，昆陽一戰何當卜。", "寧聞犬豕亂中華，漢祚承天終必復。", "夕烽明處望千門，孤臣祇欲吞聲哭。"]'),
('1db153b1-5a9f-4a9a-bae4-1fa86e64ca27','詩寄懶翁兼簡士特溫其原仲致仲昆季','劉子翬','宋','宋诗','song-poetry','','[]','懶翁疏散無與儔，結菴名懶山之幽。',304,'全唐诗/poet.song.111000.json','["懶翁疏散無與儔，結菴名懶山之幽。", "蕭然杖屨巖壑裏，似是當年嵇阮流。", "云何出處戾初志，束書負劍俄西遊。", "悲猿攀車鶴卧轍，去意勇决誰能留。", "菴垂鐵鎖人跡斷，破窗鳴紙風颼颼。", "曳裾我昔翁門客，豈知繼踵居翁室。", "里閭應記往還頻，猿鶴乍驚賓主易。", "爾來庭戶已更創，尚榜翁名志陳迹。", "傍菴小樹昔親栽，鑿沼今遷在簷北。", "我山亭闞舊牆東，此景新成翁未識。", "遥知捧檄遵歸途，摘山官况今何如。", "書來頗厭作吏冗，俸祿僅可供妻孥。", "趨庭日一見官長，脚靴手板常睢盱。", "簿書有程那得懶，却視故隠真蘧廬。", "寄聲頻慰吾人望，往時交友皆無恙。", "鵝峰諸劉更互來，清湖居士時相訪。", "中郎司戶又繼歸，酒社文盟氣增壯。", "我慚淺拙難强陪，每憶翁才真輩行。", "拂衣早赴竹林期，莫遣移文重前謗。"]'),
('e81e1834-cc2b-42ad-a6b4-494ed6761e0a','遊龍潭','劉子翬','宋','宋诗','song-poetry','','[]','四客同笑言，一僧陪杖屨。',120,'全唐诗/poet.song.111000.json','["四客同笑言，一僧陪杖屨。", "徜徉山水窟，適意忘晨暮。", "疏鐘巖北寺，細竹溪南路。", "中流石參錯，不礙潺湲注。", "泓澄小龍潭，潤氣金碧聚。", "時驚木葉墜，俯見魚蝦度。", "斯遊非預期，偶爾造佳處。", "幼輿丘壑情，陶令琴觴趣。", "淹留慰所願，惟以賓友故。", "夕陽淡寒山，遲回不能去。"]'),
('31c02532-177f-4ac1-8a4a-8a1e68de332b','田家','劉子翬','宋','宋诗','song-poetry','','[]','長空淡淡如雲掃，暮過田家風物好。',32,'全唐诗/poet.song.111000.json','["長空淡淡如雲掃，暮過田家風物好。", "耕犂倚戶寂無人，饑牛卧齧牆根草。"]'),
('09ff89e3-a1dd-4097-aa94-d4f5fdca9632','沙頭','劉子翬','宋','宋诗','song-poetry','','[]','沙頭鸂鶒寒相傍，老樹槃跚枝拂浪。',32,'全唐诗/poet.song.111000.json','["沙頭鸂鶒寒相傍，老樹槃跚枝拂浪。", "前村急雨漲灘流，日暮漁舟撐不上。"]'),
('1bc58318-ade6-4ec5-9d21-5a541cef677b','臨池歌','劉子翬','宋','宋诗','song-poetry','','[]','君不見鍾繇學書夜不眠，以指畫字衣皆穿。',198,'全唐诗/poet.song.111000.json','["君不見鍾繇學書夜不眠，以指畫字衣皆穿。", "當時尺牘來鄴下，錦標玉軸爭流傳。", "又不見魯公得法屋漏雨，意象咄咄凌千古。", "斷碑零落翠苔封，直氣英風猶可覩。", "元常獨步黄初際，清臣後出今無繼。", "風神迥處本天資，巧力亦自精勤至。", "羨君好尚何高奇，寒窗弄筆手生胝。", "向來失計墮塵網，銳氣直欲摩雲飛。", "男兒舌在心何怍，却擬臨池尋舊學。", "要須筆外見鍾顔，會自蛟龍生掌握。", "銀鈎石刻余何愛，勸以短歌君勿怠。", "他時八體妙有餘，此歌儻可君紳書。"]'),
('4cb6365d-8ba9-4c6b-b327-6cce5f7f8bff','胡兒莫窺江','劉子翬','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','胡兒莫窺江，長江限絕吳楚間。',202,'全唐诗/poet.song.111000.json','["胡兒莫窺江，長江限絕吳楚間。", "驚濤駭浪如連山，鯨鯢出沒含戈鋋。", "汝不顧死爭相先，鳴髇不響突騎閑。", "浮屍隨潮去復還。", "胡兒莫窺江，樓船百尺高崔嵬。", "鼓枻叱咤生風雷，吳儂入水雙眸開。", "汝不素習胡爲來，生雖欲殺死可哀。", "南北孰非吾民哉。", "胡兒莫窺江，前年飛矢入未央。", "日月雙墜天無光，去年一炬燒維揚。", "丹鳳徙穴仍南翔，國勢如衡有低昂。", "犬戎豈得稱天王，暴興恃暴必亟亡。", "乘蛇古讖開其祥，中興將士材無雙。", "撫劍氣已馳龍荒，胡兒胡兒莫猖狂。"]'),
('44d49126-13e8-46fc-a21b-5c14508d262d','和李巽伯春懷','劉子翬','宋','宋诗','song-poetry','','[]','山寒古寺清，斷續春朝雨。',96,'全唐诗/poet.song.111000.json','["山寒古寺清，斷續春朝雨。", "遥憐遠客情，寂寞誰晤語。", "平生氣軒昂，失意今易與。", "有酒即佳晨，無兵皆樂土。", "微吟對節物，林靜幽花吐。", "悠悠念鄉邑，耿耿悲豺虎。", "知有濟時才，從橫在談麈。", "功名恐未遲，老翮期更舉。"]'),
('e03d3859-83ba-4c06-b00e-b6ad168b4f81','明皇九馬圖','劉子翬','宋','宋诗','song-poetry','','[]','書生兀兀園不窺，見馬豈辨騮與騅。',160,'全唐诗/poet.song.111000.json','["書生兀兀園不窺，見馬豈辨騮與騅。", "開圖九駿立突兀，摸索知是真龍兒。", "奔雷蹴踏原野動，曳練慘錯風沙隨。", "華纓金絡豈不好，矯首奮迅那容羈。", "吾聞取驥如擇士，競愛妥帖驚權奇。", "士懷倜儻衆論斥，馬有顦顇羣駑欺。", "六閑豢養固恩厚，橫氣摧折常鳴悲。", "丹青儻不逢妙手，萬世豈識真龍姿。", "因思中原政格鬭，鐵騎倏忽銀山移。", "著鞭安得致此物，掩畫四顧徒歔欷。"]'),
('b7966d96-7361-4e94-b8dc-59109fc224be','怨女曲','劉子翬','宋','宋诗','song-poetry','','[]','空原悲風吹苜蓿，胡兒飲馬桑乾曲。',160,'全唐诗/poet.song.111000.json','["空原悲風吹苜蓿，胡兒飲馬桑乾曲。", "誰家女子在氊城，嗚嗚夜看星河哭。", "黄金爲閨玉爲宇，平生不出人稀覩。", "父憐母惜呼小名，擇對華門未輕許。", "干戈漂蕩身如寄，綠鬢朱顔反爲累。", "朝從獵騎草邊遊，暮逐戎王沙上醉。", "西鄰小姑亦被虜，貧賤思家心更苦。", "隨身只有嫁時衣，生死同爲泉下土。", "出門有路歸無期，不歸長愁歸亦悲。", "女身軟弱難自主，壯士從姑不如女。"]'),
('0a527e82-6621-46c7-aabc-14665702820c','防江行  其一','劉子翬','宋','宋诗','song-poetry','','[]','朝來殺氣秋，千里無立草。',36,'全唐诗/poet.song.111000.json','["朝來殺氣秋，千里無立草。", "翩翩黑幟飛，結壘天長道。", "獵罷楚天寒，黄雲淡如掃。"]'),
('7c273841-6518-40df-90f5-40040b1ef48d','防江行  其二','劉子翬','宋','宋诗','song-poetry','','[]','漢家飛將雄，夜戰蕪城北。',36,'全唐诗/poet.song.111000.json','["漢家飛將雄，夜戰蕪城北。", "雙刀斫盡刓，月暗穿圍出。", "低頭拔胡箭，却向胡軍射。"]'),
('6032233f-b1d1-4bc4-a96b-ed174cccaad0','防江行  其三','劉子翬','宋','宋诗','song-poetry','','[]','寒烽隔水明，虜意猶叵測。',36,'全唐诗/poet.song.111000.json','["寒烽隔水明，虜意猶叵測。", "君王自臨戎，萬騎隨清蹕。", "士氣薄層霄，欃槍夜無色。"]'),
('ed76a832-a977-416d-86ba-ac1528365850','防江行  其四','劉子翬','宋','宋诗','song-poetry','','[]','江邊五色旗，分總期門士。',36,'全唐诗/poet.song.111000.json','["江邊五色旗，分總期門士。", "驚砂雜雪飛，日暮孤城閉。", "寂寥良將風，誰識投醪意。"]'),
('3a0548d1-7427-4797-9c2c-a158caddd46f','防江行  其五','劉子翬','宋','宋诗','song-poetry','','[]','樓船動滄江，江晴鼓聲發。',36,'全唐诗/poet.song.111000.json','["樓船動滄江，江晴鼓聲發。", "男兒取封侯，赴敵如饑渴。", "腰懸孛堇頭，長歌獻金闕。"]'),
('3709deac-f6f0-4e96-857c-1b3e85cd41ce','和安汝功採紫竹杖篇','劉子翬','宋','宋诗','song-poetry','','[]','赤籐表珍奇，桃竹寄吟玩。',156,'全唐诗/poet.song.111000.json','["赤籐表珍奇，桃竹寄吟玩。", "高情在丘壑，微物懷深睠。", "徵工匝遠林，彌山選一幹。", "雲根傍崖蹙，椹色涵霜變。", "匪憑精刃揮，根柢難立斷。", "慇懃爲摩撫，燁燁光浮爛。", "觸石聲含鍾，撢波影摇電。", "矧余疲曳姿，假力斯過半。", "皇皇駟馬威，秦趙昔臨按。", "胡爲步槃跚，猥逐漁樵伴。", "千金一顧重，朽質增華煥。", "不經提携手，棄擲亦何算。", "夙懷用捨情，感茲發長歎。"]'),
('27ad2a91-edf7-437e-8a58-a4bf2eeebedc','贈宗周賓','劉子翬','宋','宋诗','song-poetry','','[]','我車南，君車北，相逢總是天涯客。',32,'全唐诗/poet.song.111000.json','["我車南，君車北，相逢總是天涯客。", "擁爐談笑一燈殘，出門風雨千山隔。"]'),
('eab236f8-de92-46ac-8b7f-1f32f167415f','湆淡灘','劉子翬','宋','宋诗','song-poetry','','[]','南來甌粵無平陸，林巒起翠波騰綠。',160,'全唐诗/poet.song.111000.json','["南來甌粵無平陸，林巒起翠波騰綠。", "扶輿政恐犯霜露，買舟儻可休僮僕。", "清灘白晝雷霆作，亂石驚湍犬牙錯。", "平生珍重千金軀，舟子一篙那可託。", "飄摇葉漾勢轉急，釜竈傾頹不能立。", "眼看白浪散銀山，蛟螭百怪堂堂出。", "人皆乘險欲趨利，我不安行悔可及。", "吁嗟世路風波猛，巧穽危機暗馳騁。", "江湖溺舟猶自戒，勢利溺人終莫省。", "矯情鎮物未足言，書此聊爲後來警。"]'),
('9d8fea14-265e-4e12-a3d5-ce0e77d991b4','巡寨偶書','劉子翬','宋','宋诗','song-poetry','','[]','窮寇轉趨海，吾邦備宜先。',180,'全唐诗/poet.song.111000.json','["窮寇轉趨海，吾邦備宜先。", "連年戍役頻，徵兵及漁佃。", "扶戈或稚齒，嬰胄仍華顛。", "未知戎伍肅，朱旗亂長阡。", "林端晚燧發，石際飛梯懸。", "崎嶇樵牧地，萬竈生浮烟。", "我行視營柵，兒戲端可憐。", "倚茲形勢險，寇至常遷延。", "羣兇昔吾軍，赤指抨鳴弦。", "防胡屢瓦解，合寇俄星連。", "猶多燕趙兒，意氣非當年。", "駢車載珍寶，結騎馳嬋娟。", "時危天稔亂，事豈汝能專。", "怒風飛驚濤，河梁失歸船。", "四顧天地黑，攬衣思茫然。"]'),
('3ae9c869-a2a1-482c-8d11-e115b71f9967','次韵蔡學士梅詩','劉子翬','宋','宋诗','song-poetry','','[]','梅梢破白香清切，凊雨含春不成雪。',160,'全唐诗/poet.song.111000.json','["梅梢破白香清切，凊雨含春不成雪。", "瑶池彷彿萬妃遊，縞裙練帨何鮮潔。", "凌晨燦爛忽驚眼，客中又過嘉平月。", "年年見梅非昔地，海角尋芳更愁絕。", "多情欲伴曉雲飛，有恨只教啼鳥說。", "兵厨况是酒如澠，東閣喜聽談吐屑。", "飄零使我懽意盡，山誠暮角聲嗚咽。", "庭邊一樹春最晚，照影遥憐水方折。", "暫忙不到今幾時，南北枝頭開又歇。", "新辭婉媚發春妍，未害廣平心似鐵。"]'),
('8e7eb73b-aa93-474d-a01f-672bb2bc9217','禱雨蟹泉','劉子翬','宋','宋诗','song-poetry','','[]','厭旱訟風伯，苦雨誅雲師。',192,'全唐诗/poet.song.111000.json','["厭旱訟風伯，苦雨誅雲師。", "天公良獨難，爾民多怨咨。", "夏潦包原隰，苗端漲清漪。", "冬暄但流塵，土堅不銜犂。", "陰陽有乘除，此理固可推。", "惟神執天權，憫物思濟之。", "穴泉類蹄涔，幽靈隠其涯。", "彷彿小雙螯，控御蛟龍隨。", "名居列曜尊，箕畢可指撝。", "顧匪郭索倫，嘗辱左手持。", "滂沱爲一縱，豈惟潤東菑。", "灝灝燠氣清，浮浮瘴烟披。", "將聞鼓腹謠，寧求折肱醫。", "寸澤垂二惠，此功神所尸。", "遥知青青麥，春風滿陵陂。", "吾儕飽湯餠，敢後椒漿期。"]'),
('81d7e1f0-e60d-43d4-9982-36c8563de25a','負暄','劉子翬','宋','宋诗','song-poetry','','[]','宵寒卧增裯，晝寒起增衣。',132,'全唐诗/poet.song.111000.json','["宵寒卧增裯，晝寒起增衣。", "何如負暄樂，高堂日暉暉。", "引光扉盡闢，追影榻屢移。", "妙趣久乃酣，瞑目潛自知。", "初如擁紅爐，凍粟消頑肌。", "漸如飲醇醪，暖力中融怡。", "欠伸百骸舒，爬搔隨意爲。", "稍回驕佚氣，頓改酸寒姿。", "薰然沐慈仁，天恩豈余私。", "願披橫空雲，四海同熙熙。", "矯首望扶桑，傾心效園葵。"]'),
('040ca5fa-8403-4626-abb7-cbdb62a8f62b','子魚','劉子翬','宋','宋诗','song-poetry','','[]','舊聞通印名，海錯珍莫踰。',168,'全唐诗/poet.song.111000.json','["舊聞通印名，海錯珍莫踰。", "火氣爍鱗鬣，鹵香泛庖厨。", "泥泥子盈胞，鮮美禍所區。", "生如粒芥微，多若囊粟儲。", "他年想吞舟，勿輕此錙銖。", "一咀命千百，雖甘汝安無。", "窮冬孚乳時，罩䍡海爲虛。", "含凍體猶僵，得潟味已渝。", "虐戲等刳孕，淫刑幾戮孥。", "人深襁褓恩，在物愛豈殊。", "閩風易殺子，盥水沈其軀。", "詎有惻怛心，旁推及豚魚。", "相殘人獸均，自殘獸不如。", "哦詩化蠻獠，因警饕餮徒。"]'),
('7b22bbcb-0605-4b0a-92a4-f621e1e73bc0','郡圃觀酴醿','劉子翬','宋','宋诗','song-poetry','','[]','憶昔尋春西洛橋，酴醿結洞橫朱架。',208,'全唐诗/poet.song.111000.json','["憶昔尋春西洛橋，酴醿結洞橫朱架。", "翠帷銀網一番新，百萬花頭相枕籍。", "飄摇羽客靜疑仙，窈窕素娥嬌欲嫁。", "細蕤摘貯絳紗囊，撲鼻清香奪蘭麝。", "論花每恨流品雜，韵絕江梅此其亞。", "紛紛紅紫已空條，耿耿冰霜猶照夜。", "只今漂泊一身存，海角逢春足悲咤。", "銀苞翠蔓宛如昨，瘦骨蒼顔忽驚乍。", "當時我最推少年，想見同遊更衰謝。", "洛陽園苑狐兔生，虜騎時來北邙下。", "浮生榮悴均有老，萬古興衰那足訝。", "南鄰地主好襟懷，官事稍閑須命駕。", "急須喚酒賞餘妍，惡雨狂風不相借。"]'),
('062debc1-6c20-46cb-aba9-dc175ba8de4a','木犀古風','劉子翬','宋','宋诗','song-poetry','','[]','化工吝幽香，斑斑被花木。',144,'全唐诗/poet.song.111000.json','["化工吝幽香，斑斑被花木。", "氤氳寒巖桂，高韵蓋羣馥。", "無人盡日芳，守志何幽獨。", "士介恥求知，女貞慚自鬻。", "淒涼楚山秋，樛枝吐金粟。", "淺水映輕明，微飆發含蓄。", "樓端靜忽聞，馬上遥相逐。", "踟躕爲延竚，但見林巒綠。", "瓶罌誰折贈，清芬閟廬屋。", "久處不自知，乍至彌鬰郁。", "客悲芳歲暮，夢繞寒溪曲。", "長吟小山詞，古意恐難復。"]'),
('81c15981-77d6-44d2-853f-e8ccf06ca428','食蠣房','劉子翬','宋','宋诗','song-poetry','','[]','蠣房生海壖，堅頑宛如石。',288,'全唐诗/poet.song.111000.json','["蠣房生海壖，堅頑宛如石。", "其中儲可欲，雖固必生隙。", "嵌喦各包藏，碨䃁相附積。", "終逢霹靂手，妙若啟扃鐍。", "鑽灼諒難堪，曷不吐餘瀝。", "南庖富腥盤，豈惟此稱特。", "吞航大絕倫，梯臠萬夫食。", "針鱗九牛毛，小嚼逾千百。", "光螺暈紫斑，䗻膏湛金色。", "水母脆鳴牙，章舉懸疣密。", "烏黏力排奡，貼石不可索。", "妾魚戲浮波，媚鮜雌雄匹。", "蟹躁輒橫騖，鼈縮常畏出。", "車螯不服箱，馬鮫非駿跡。", "江瑶貴一柱，嗟豈棟梁質。", "骨柔競愛䱠，多鯁鯯乃斥。", "蚶虹鮭赤文，肉黑魚之賊。", "鰷鱨鰋鯉鰻，鱣鮪鰍魴鯽。", "鱅庸而𩵖小，瑣冗難盡述。", "包涵知海量，長養荷天德。", "貪生族類繁，失地波濤窄。", "網罼人創禍，甘鮮已爲厄。", "紛然均可口，流品當別白。", "微物倘見知，捐軀不足惜。"]'),
('a73fd5ac-f67c-4645-a260-09b318461c4e','春寒偶書','劉子翬','宋','宋诗','song-poetry','','[]','浮雲匿晨暉，雨雹驚春晝。',120,'全唐诗/poet.song.111000.json','["浮雲匿晨暉，雨雹驚春晝。", "天公號令乖，陰晴變何驟。", "小徑踐芳泥，通渠走寒溜。", "風顛萬木偃，氣凜重幃透。", "鵷鸞護巢翔，奈此羣雛幼。", "擁爐烏薪然，雙手慵出袖。", "褰幃望空明，屋角見遥岫。", "良朋不可招，塊處慚孤陋。", "青青桃葉長，奕奕蘭花秀。", "長吟曷咨嗟，佳辰去難又。"]'),
('64e764d8-52eb-4c81-bc7e-a5bee9a52535','荔子歌','劉子翬','宋','宋诗','song-poetry','','[]','炎精孕秀多靈植，荔子佳名聞自昔。',224,'全唐诗/poet.song.111000.json','["炎精孕秀多靈植，荔子佳名聞自昔。", "絳囊剖雪出琱盤，尋常百果無顔色。", "閩天六月雨初晴，星火熒煌曜川澤。", "欻如彩鳳戲翱翔，爛若彤雲堆翕爀。", "中郎裁品三十二，陳紫方紅冠流匹。", "鹽蒸蜜漬尚絕倫，啄鮮空羨南飛翼。", "我聞二和全盛時，貢輸不減開元日。", "涪州距雍已云遠，况此奔馳來海側。", "繡衣中使動輶車，黄紙封林遍阡陌。", "浮航走轍空四郡，妙品人間無復得。", "似聞供御只纖毫，往往盡入公侯宅。", "驪山廢苑狐兔靜，艮嶽新宮鼙鼓急。", "繁華今古共淒涼，繞樹行吟悲野客。", "西風刮地戰塵昏，一聽胡笳雙淚滴。"]'),
('3e418833-78b7-4970-a052-72267adb5fed','法石見李漢老參政','劉子翬','宋','宋诗','song-poetry','','[]','我識今朝李翰林，十年隔絕飛寸心。',208,'全唐诗/poet.song.111000.json','["我識今朝李翰林，十年隔絕飛寸心。", "素書每逢雙鯉得，雲路欲倚長梯尋。", "翰林昔參建炎政，想見中興人物盛。", "方圓齟齬不足論，角巾雅有江湖興。", "玉堂草詔褫凶魄，丹陛陳謨發天聽。", "介圭便合趣公還，只今密勿才稀並。", "自憐隨牒東南奔，假道因得登龍門。", "怪余髯面益老矣，一笑問勞情彌敦。", "僧坊蕭蕭遠闤闠，豈料飄零獲清對。", "牛行尚憶王相宅，曩日交遊幾人在。", "濁酒青燈夢寐間，九州四海煙塵內。", "區區王事今有程，暫見復別難爲情。", "長亭喚馬一悽斷，璧月曉墮桐花城。"]'),
('665dde17-0307-4e43-a78a-8a24141d6d18','歸田','劉子翬','宋','宋诗','song-poetry','','[]','聲色家有穽，軒裳仕之囚。',108,'全唐诗/poet.song.111000.json','["聲色家有穽，軒裳仕之囚。", "冥行不知迷，今將返吾輈。", "愛慕洗餘習，清虛樂孤遊。", "亭亭隠仙巖，迎人入雙眸。", "稻色黄莽莽，溪光碧油油。", "佳樹殘照滿，高穹亂雲流。", "乍參樵牧羣，辭氣不婉柔。", "性有書史癖，時逢甲兵休。", "斯懷儻遂全，曩志不必酬。"]'),
('8f2aee42-3089-4452-86d5-3ea7fa9355ab','省拱辰山','劉子翬','宋','宋诗','song-poetry','','[]','豺狼已煙銷，言歸省先塋。',120,'全唐诗/poet.song.111000.json','["豺狼已煙銷，言歸省先塋。", "豈無消息至，怵惕意自驚。", "兵戈道孔由，不折寸草徑。", "神物陰有護，兇威肅其獰。", "敬瞻壠闕雲，墮淚眶睫盈。", "如承慈穆顔，如聞謦咳聲。", "道餘孤風存，澤本遺愛成。", "昔我罹禍苦，結廬傍佳城。", "哀慕寧有極，忽忽時序更。", "慚愧舊巢鳥，常繞松柏鳴。"]'),
('251de703-d560-49c7-aeb5-8ca1ca13e5d7','士特贈筆','劉子翬','宋','宋诗','song-poetry','','[]','書成癡，傳成癖，平生識字真無益。',127,'全唐诗/poet.song.111000.json','["書成癡，傳成癖，平生識字真無益。", "筆扛鼎，思涌泉，何如蹶張强弩絃。", "管城雅貺情雖重，感此囏難拙於用。", "君不見翠華南渡江，江路八百里。", "胡兒飲馬鏡湖邊，不逢漢兵胡自止。", "只今城闕多旌旗，報國擬將雕面兒。", "長星吐彗南掃北，轉禍爲福須乘時。", "虎頭心事不能已，勸君勿弄毛錐子。"]'),
('d3009d4c-7a0a-4907-a240-5d54295bf00d','諭俗  其一','劉子翬','宋','宋诗','song-poetry','','[]','故園喪亂餘，歸來復何有。',156,'全唐诗/poet.song.111000.json','["故園喪亂餘，歸來復何有。", "鄰人雖喜在，憂悴成老叟。", "爲言寇來時，白刃穿田畝。", "驚忙不知路，夜踏人屍走。", "屋廬成飛烟，囊橐無暇取。", "匹夫快恩讎，王法誰爲守。", "艱難歷冬夏，遷徙遍林藪。", "深虞邏寇知，兒啼扼其口。", "樹皮爲衣裳，樹根作糧糗。", "還家生理盡，黑瘦面如狗。", "語翁翁勿悲，禍福較長久。", "東家紅巾郎，長大好身手。", "荒荒戰場中，頭白骨先朽。"]'),
('8aec03c9-8ac2-4e9f-b2bc-05c40a8470d4','諭俗  其二','劉子翬','宋','宋诗','song-poetry','','[]','西村人漸歸，撐柱燒殘屋。',120,'全唐诗/poet.song.111000.json','["西村人漸歸，撐柱燒殘屋。", "東村但蒿萊，死者無人哭。", "昔茲號富穰，被禍尤殘酷。", "二三里中豪，喪亂身爲僇。", "遺骸悵莫掩，饑鳶啄其腹。", "豈無平生時，意氣凌鄉曲。", "錐刀剝微利，舞智欺惸獨。", "錦囊收地券，奕葉相傳續。", "只今鄰叟耕，歲歲輸官穀。", "爾曹何顓愚，人生固多欲。"]'),
('61d92a32-8248-4407-9167-f8d0515a58a2','諭俗  其三','劉子翬','宋','宋诗','song-poetry','','[]','何州無戰爭，閩粵禍未銷。',120,'全唐诗/poet.song.111000.json','["何州無戰爭，閩粵禍未銷。", "或言殺子因，厲氣由此招。", "蠻陬地瘠狹，世業患不饒。", "生女奩分貲，生男野分苗。", "往往衣冠門，繼嗣無雙髫。", "前知飲啄定，妄以人力僥。", "三綱既自絕，餘澤豈更遥。", "王化久淘漉，刑章亦昭昭。", "那無舐犢慈，恩勤愧鴟鴞。", "寃報且勿論，茲義古所標。"]'),
('2f7ec30a-6286-47ce-aee5-7eaf96782b09','諭俗  其四','劉子翬','宋','宋诗','song-poetry','','[]','愚氓擾潢池，囏難亦常態。',120,'全唐诗/poet.song.111000.json','["愚氓擾潢池，囏難亦常態。", "簪紳有包藏，事異吁可怪。", "豺聲久伺亂，鯨戮終何悔。", "游言張兇焰，巧諜移機會。", "初如卵殻微，跐踐悉糜碎。", "養成羽翮雄，飛掣韝繩外。", "翦鉏淹歲月，螫毒彌疆界。", "向來詰端由，罪白不容蓋。", "南冠囚載路，東市誅其最。", "隆寬俗與新，僥倖汝勿再。"]'),
('452cc833-c0b5-4d12-9a4f-e95674504df5','諭俗  其五','劉子翬','宋','宋诗','song-poetry','','[]','野人厭羹藜，家有庖丁刀。',84,'全唐诗/poet.song.111000.json','["野人厭羹藜，家有庖丁刀。", "徒誇批導手，肯念耕稼勞。", "隠然肉山雄，畏彼尺箠操。", "春泥卧寒野，夜月犂東皋。", "辛勤力已盡，觳觫禍豈逃。", "誰無惻隠心，鮮能勝貪饕。", "蓋帷猶示恩，况異犬馬曹。"]'),
('53a2f4e5-2465-48a9-9b13-567ce2f55f1a','諭俗  其六','劉子翬','宋','宋诗','song-poetry','','[]','扇馬嚴內仗，貂璫侍宸閽。',84,'全唐诗/poet.song.111000.json','["扇馬嚴內仗，貂璫侍宸閽。", "哀哉里閭間，刀閹逮雞豚。", "放麑識忠藎，毋卵著格言。", "矧利肥甘軀，絕其孳息源。", "難銷愛欲心，物物天性存。", "逆情氣必戾，順化生乃蕃。", "誰開口腹謀，無乃傷仁恩。"]'),
('6c83f3d5-5412-451e-b08f-da7b40bb1a48','諭俗  其七','劉子翬','宋','宋诗','song-poetry','','[]','粵人多悍驕，風聲亦惟舊。',96,'全唐诗/poet.song.111000.json','["粵人多悍驕，風聲亦惟舊。", "兒童僅勝衣，挾箠相格鬭。", "藝精氣益橫，質化心忘陋。", "家饒喜稱俠，世亂甘爲寇。", "豈伊天性然，習俗所成就。", "吾聞互鄉童，翺翔聖賢囿。", "隠豹弄斕斑，攻駒發馳驟。", "佩觿爾何知，義方得無謬。"]'),
('4fd7e900-b53c-466f-8500-35fe7d5bb2a7','諭俗  其八','劉子翬','宋','宋诗','song-poetry','','[]','村南井欲乾，曉汲盈瓢濁。',96,'全唐诗/poet.song.111000.json','["村南井欲乾，曉汲盈瓢濁。", "飲濁不足言，奈此田畝涸。", "咿啞龍骨響，煥爛陽烏虐。", "良農無他營，辛苦事東作。", "春苗何葱芊，秋刈何稀薄。", "我雖食有餘，念彼心不樂。", "乞靈走羣祀，晚電明霍霍。", "屯膏竟未施，天意自難度。"]'),
('170f982d-ae00-4b69-84be-e8af66dc3813','諭俗  其九','劉子翬','宋','宋诗','song-poetry','','[]','震雷霹枯松，頑龍失其據。',96,'全唐诗/poet.song.111000.json','["震雷霹枯松，頑龍失其據。", "浮雲三日雨，盈畝復他注。", "商羊舞未休，旱魃消何遽。", "稍寬人心切，仰荷天恩布。", "稻畦褭連顛，挼穗給朝飫。", "菜畦擢新萌，蕩滌死羣蠹。", "歲儉民怨咨，時豐家悅豫。", "青青寒莠色，亦復貪雨露。"]'),
('d09257b8-5308-492f-a23d-b25f509b922a','諭俗  其一○','劉子翬','宋','宋诗','song-poetry','','[]','茲鄉山水佳，昔乃爲盜窟。',108,'全唐诗/poet.song.111000.json','["茲鄉山水佳，昔乃爲盜窟。", "吾盧已煨燼，荒草牆兀兀。", "牆東大梨樹，惟此爲舊物。", "火燒枝葉盡，老本更奇崛。", "衆鳥罷高栖，空庭失清樾。", "鄰兒利薪爨，往往肆戕伐。", "豈知昂霄勢，長養自毫末。", "寒堤孤碓在，廢圃鳴泉出。", "衡茅且經營，霜霰莫倉猝。"]'),
('b74d6f19-e5fc-408b-a5c2-2e6ff9c108a2','諭俗  其一一','劉子翬','宋','宋诗','song-poetry','','[]','未須葺吾廬，且復修吾倉。',120,'全唐诗/poet.song.111000.json','["未須葺吾廬，且復修吾倉。", "求安當卜居，求飽當聚糧。", "營生力有限，先此計頗長。", "去年稻盈畦，避寇不得將。", "新芽雨後白，卧穗霜中黄。", "鰥惸有饑色，寇釁餘稻糧。", "解衣易升斗，糠粃隨風揚。", "休嗟昔艱難，喜茲歲豐穰。", "鄰翁爲人耕，貯粟不盈箱。", "溪頭廩與囷，纍纍已相望。"]'),
('43ca0450-f953-4163-a44b-88f2bc24dd10','諭俗  其一二','劉子翬','宋','宋诗','song-poetry','','[]','懸牆挂德音，盡弛今年租。',144,'全唐诗/poet.song.111000.json','["懸牆挂德音，盡弛今年租。", "旄倪發懽謠，助達和氣舒。", "皇恩施甚厚，疲瘵望少蘇。", "吁嗟吏舞文，詔紙墨未渝。", "借貸盡白著，勾稽窮宿逋。", "掊克儻歸公，民貧猶樂輸。", "量權徵倍耗，夤緣竊其餘。", "寧逢盜剽攘，厭聞吏追呼。", "盜姦久必戢，吏姦無由鉏。", "雷霆不言威，肉食忍自誣。", "故態勿狃習，窮閻勿侵漁。", "勿謂天聽高，勿謂黔首愚。"]'),
('2501cd16-55eb-4413-9c1c-ac374d4e6815','清江行','劉子翬','宋','宋诗','song-poetry','','[]','漁翁一棹老清波，稚子學語能漁歌。',64,'全唐诗/poet.song.111000.json','["漁翁一棹老清波，稚子學語能漁歌。", "日暮沙頭寒爇竹，雨餘船角亂堆蓑。", "鬻殘小鮮仍自鱠，湖海茫茫醉鄉內。", "夜闌酒渴潄寒流，月照蘆花上蓬背。"]'),
('4354bc97-ab63-4523-b555-2d6103cb6759','聽詹溫之彈琴歌','劉子翬','宋','宋诗','song-poetry','','[]','鳴琴藝精非小道，可惜溫之今已老。',210,'全唐诗/poet.song.111000.json','["鳴琴藝精非小道，可惜溫之今已老。", "玲琅一鼓萬象春，鐵面霜髯不枯槁。", "自言寡知音，求我爲作歌。", "號宮韵角可聽不可狀，錦腸繡舌空吟哦。", "吾意其一氣之濁清，兩曜之晦明。", "山河之結融，雷霆風雨之震驚。", "包羅具七弦，開闔造化由人心。", "又疑夫堯禹之躬行，丘軻之立言。", "瞿聃之同歸，百家諸子之紛然。", "更歷千萬古，此意不滅絲桐間。", "滌除浮慮清，蕩摩愁襟開。", "琴之氣象廣莫有如此，欲媚俗耳知難哉。", "寒缸燒涸夜向闌，罷琴歸矣我欲眠。", "夢跨冰輪出瑶海，一笑碌碌瀛洲仙。"]'),
('ba9bc85c-1f1a-4d4c-85dc-056e8365069d','鵝峰居士以地黄遺病翁因爲作引','劉子翬','宋','宋诗','song-poetry','','[]','君不見咸陽之原，涇渭之間。',173,'全唐诗/poet.song.111000.json','["君不見咸陽之原，涇渭之間。", "靈苗叢生綠芊綿，春風莽莽膠晴煙。", "天馬嚼齕黄金涎，渴噴清浪香浮川。", "年深駿足宵騰邁，目有神光破昏昧。", "方經誇異儻不誣，伊人服之功必倍。", "君家種藥南山隅，紫花褐實連庭除。", "長鑱斸掘動雲壤，婉婉盡拔生龍鬚。", "飲之清醥觀其德，宛如君子彌溫克。", "浮沈詎卹世論量，蒸曝益見中腴澤。", "我年三十號病翁，空齋藥杵聲瓏冬。", "未能醫國慚君賜，舊書且讀蠅頭字。"]'),
('4674be9b-7280-4a45-818c-ee856a1bfd62','萊孫歌','劉子翬','宋','宋诗','song-poetry','','[]','屯田詞，考功詩，白水之白鍾此奇。',152,'全唐诗/poet.song.111000.json','["屯田詞，考功詩，白水之白鍾此奇。", "鈎章棘句凌萬象，逸興高情俱一時。", "耆卿骨朽士特死，澗谷錯莫無晶輝。", "後生俊秀何其寡，吾宗喜有萊孫者。", "雙瞳點漆面如水，一見使我心神寫。", "讀書已通經，學賦已知律。", "只今年十三，吐氣成五色。", "驪珠出海夜生光，突笴流弦追莫及。", "人材有價誰能私，不妨乃翁聊譽兒。", "囊中彩筆今付汝，往繼二妙聲名馳。"]'),
('d8c8ccc2-8b81-4728-995a-05895888d1b1','夢仙謠','劉子翬','宋','宋诗','song-poetry','','[]','鵝子峰前波色清，劉郎看山無俗情。',236,'全唐诗/poet.song.111000.json','["鵝子峰前波色清，劉郎看山無俗情。", "癯儒自昔有仙骨，夜夢體飛如葉輕。", "雲中不識朝天路，雙童導我凌空去。", "側身度巖隈，盤盤復回回。", "翛然意往形不礙，石窟蘚竇俄天開。", "乘槎夜泛牛女渡，鞭鸞曉入金銀臺。", "花深不逢人，時聞佩環聲。", "仙翁睡起方結襪，見客坦易無崖垠。", "擊蒙冀垂矜，叩妙獲一言。", "七情汩心心憒昏，窒慾如水澄其源。", "臼中㕮咀藥，手撮仍見分。", "旁有泠泠泉，三潄乃盡吞。", "駐紅却白非難事，貪生慮死真愚計。", "當時同遊七姓俱，但記古月成胡字。", "塵緣未斷不得留，海風吹過蓬瀛洲。", "覺來窗戶冥曚曉，玉鏡晶晶墮松杪。"]'),
('94dfd91a-d508-49d7-9a7a-07573a1c698c','雲際會劉致中','劉子翬','宋','宋诗','song-poetry','','[]','紅綃千樹桃，雪縠萬株李，柘葉青青如鼠耳。',116,'全唐诗/poet.song.111000.json','["紅綃千樹桃，雪縠萬株李，柘葉青青如鼠耳。", "橫山渡口浪成堆，認得劉郎船子來。", "物情時事不須說，且喜新歲同銜杯。", "少年鼻哂輕流俗，歛銳收豪今碌碌。", "敝裘常带客塵緇，雙鬢不如春草綠。", "東風吹愁入我心，使我嘯歎成悲吟。", "問君底事久留此，曷不聯鑣歸故林。"]'),
('ca0fc4a2-3c4c-4562-97af-07cc44261560','懷舊歌','劉子翬','宋','宋诗','song-poetry','','[]','黄茅生煙暗村落，浩歌無復當時樂。',192,'全唐诗/poet.song.111000.json','["黄茅生煙暗村落，浩歌無復當時樂。", "鄰家酒熟逆鼻香，一醉乾坤墮冥漠。", "尋芳屢過垂玉軒，叉魚夜上浮清閣。", "鬭牌擊鼓多伎倆，我獨旁觀惟大噱。", "驚烽入座懽難保，幸得身存他勿道。", "吾宗潛武卧空棺，衮臣兄弟埋荒草。", "當時醉舞向花下，綠鬢朱顔各鮮好。", "隙駒風燭尚須臾，數子凋零不待老。", "死生細事從渠天，莫學兒女相哀憐。", "一窗容膝可終隠，寇盜擾擾今連年。", "王師誅鉏有漏網，死灰焰焰猶思然。", "憂煎過計祇自惱，且但努力耕吾田。"]'),
('d2c06690-e528-40ab-b210-8588deb642e0','夜過王勉仲家宿酒數行爲作此歌','劉子翬','宋','宋诗','song-poetry','','[]','遥林带雪迷村疃，伶俜一馬行無伴。',176,'全唐诗/poet.song.111000.json','["遥林带雪迷村疃，伶俜一馬行無伴。", "故人家住丁坂頭，停驂邂逅成清款。", "犯寒知我猶空腹，地爐然薪架紅玉。", "花瓷湯酒欲生香，竹外庖厨聞剁肉。", "夫君不有中饋賢，咄嗟辦此何神速。", "酒酣意氣悲荆棘，尚憶朱甍舊時宅。", "豺狼得志竟何成，至今人骨如霜白。", "亂離少有闔門在，漂蕩俄驚五年隔。", "數畝荒田已失耕，一間茅屋仍留客。", "客情主意懽難盡，短臘窮冬春欲近。", "明朝分手更愁人，且覆清觴莫留剩。"]'),
('c5be05dd-4394-4019-8b33-c5d3a298ee81','夏日吟','劉子翬','宋','宋诗','song-poetry','','[]','君不見長安公侯家，六月不知暑。',118,'全唐诗/poet.song.111000.json','["君不見長安公侯家，六月不知暑。", "扇車起長風，冰檻瀝寒雨。", "重櫩邃屋晝生陰，反易天時在談吐。", "又不見五陵富豪兒，炎天多快意。", "雪縠曳輕明，珍槃嚼甘脆。", "蛾眉皓齒發清歌，灑酒筠枝集蠅蚋。", "何如野客歌滄浪，萬事不理心清凉。", "流金鑠石未爲苦，勢利如火焚中腸。"]'),
('fc117d36-b1be-48ec-b315-062bad7fed0c','萊孫求墨并以詩與之','劉子翬','宋','宋诗','song-poetry','','[]','何年老烏龍，排山折其角。',120,'全唐诗/poet.song.111000.json','["何年老烏龍，排山折其角。", "漁人網得之，澄淵起雷雹。", "異物世常猜，神光夜潛覺。", "流傳歲月深，質槁紋斑剝。", "漆簡射晶熒，玄圭靡雕琢。", "孰謂喬松煙，能成此堅確。", "晴窗試墨池，雲霧生掌握。", "只恐化蜿蜒，飛騰入冥邈。", "萊孫真可兒，句法有家學。", "贈汝囊中珍，慚余鼻端斲。"]'),
('9ff6b72a-deaf-4dc7-9de5-072a6645f158','劉致中惠瓜','劉子翬','宋','宋诗','song-poetry','','[]','炎熇氣如焚，塊坐惟兀兀。',132,'全唐诗/poet.song.111000.json','["炎熇氣如焚，塊坐惟兀兀。", "劉侯惠甘瓜，胸次瀉溟渤。", "豐膚素浪浮，翠理霜刀刜。", "因思少年時，窺園步清樾。", "百金酬地主，熟蒂香可揭。", "鄙懷須一快，聊效野人齕。", "種瓜雖賤工，愛護渠敢忽。", "薅芸治其煩，灌溉滋其竭。", "自然子母繁，翠蔓相連結。", "種瓜誠有道，養民豈無術。", "噫余夙昔知，此意未及物。"]'),
('b3150448-d253-474b-801b-683147644605','白水見梅憶士特','劉子翬','宋','宋诗','song-poetry','','[]','去年看梅時，中郎共開樽。',40,'全唐诗/poet.song.111000.json','["去年看梅時，中郎共開樽。", "今年看梅時，獨招中郎魂。", "悲歡聚散誰作惱，擬欲問春春不言。"]'),
('2d0358f3-0e8c-4150-b85c-7e3c1d8bb878','送謝中瑩','劉子翬','宋','宋诗','song-poetry','','[]','相別夢悠悠，相逢懽草草。',36,'全唐诗/poet.song.111000.json','["相別夢悠悠，相逢懽草草。", "送君躍馬臨長道。", "十年憔悴向塵埃，一段精神摧不老。"]'),
('ad81bb81-d58b-4364-9b93-98b8e291b539','與純臣原仲溫其煮魚羹','劉子翬','宋','宋诗','song-poetry','','[]','衆賓會高堂，嘉魚脫重淵。',120,'全唐诗/poet.song.111000.json','["衆賓會高堂，嘉魚脫重淵。", "霜鰓尚呀呷，綠藻仍牽連。", "厨人起揎袖，刀机鳴鏗然。", "斷尾頳縠碎，批鱗玉花翩。", "雲雷蓊深釜，清香已遥傳。", "投葱裂素絲，裁薑落金錢。", "陶甌舉筠箸，更覺真味全。", "細紋松江鱸，縮頸槎頭鯿。", "吾儕但知飽，美惡無棄捐。", "何論調羹手，聊復試小鮮。"]'),
('eaec73c1-141c-4032-b1fa-4ba5bed76921','餘柑','劉子翬','宋','宋诗','song-poetry','','[]','炎方橄欖佳，餘柑豈苗裔。',108,'全唐诗/poet.song.111000.json','["炎方橄欖佳，餘柑豈苗裔。", "風姿雖小殊，氣韵乃酷似。", "騂顔澀吻餘，彷彿清甘至。", "侯門收寸長，粉骨成珍劑。", "猶聞雜蜜草，少轉森嚴味。", "奇才用不專，雖用何殊棄。", "端如效苦言，逆耳多嫌忌。", "棄果事何傷，違言德之累。", "悅口易逢知，感茲發長喟。"]'),
('5c477415-52ba-401a-912c-d6a8e72ab232','打魚歌','劉子翬','宋','宋诗','song-poetry','','[]','西溪觀魚仍開樽，鳴榔隠隠沈煙村。',160,'全唐诗/poet.song.111000.json','["西溪觀魚仍開樽，鳴榔隠隠沈煙村。", "吾人豈有竭澤意，澒洞四際魚龍奔。", "驚潛初見穿亂藻，亟遁轉覺迷深源。", "向非驅迫羣黨聚，罩䍡徒使波濤渾。", "巨鱗足供數客飽，銀刀瑣碎不足論。", "吁嗟神物未變化，暴骨砧机寧非寃。", "江湖萬里厭游泳，失地斗水能爲恩。", "臨流解網意亦厚，誘以芳餌仍爭吞。", "因悲摇尾向數罟，豈異俯首縻華軒。", "慨然投箸起太息，歸思已逐冥鴻鶱。"]'),
('bd7fa5da-e22e-42b6-8025-b2867b579886','潭溪十詠 悠然堂','劉子翬','宋','宋诗','song-poetry','','[]','吾廬猶未完，作意創此堂。',36,'全唐诗/poet.song.111000.json','["吾廬猶未完，作意創此堂。", "悠然見南山，高風邈相望。", "賓至聊共娛，無賓自徜徉。"]'),
('e2e3b294-d3a3-4575-9ba6-e488bde194b1','潭溪十詠 海棠洲','劉子翬','宋','宋诗','song-poetry','','[]','煌煌海棠洲，錦樹臨清灣。',36,'全唐诗/poet.song.111000.json','["煌煌海棠洲，錦樹臨清灣。", "常恨灣頭風，吹花走潺湲。", "潺湲去不息，花亦無由還。"]'),
('1de719a2-d8ae-452b-be3d-bb0e112e8978','潭溪十詠 醒心泉','劉子翬','宋','宋诗','song-poetry','','[]','藤蘿撥不開，石竇一鏡明。',36,'全唐诗/poet.song.111000.json','["藤蘿撥不開，石竇一鏡明。", "携瓢酌清甘，漻然瑩心神。", "我病不能酌，時來聽泠泠。"]'),
('6bf720ab-edc0-4e57-a44e-93fe3eed5296','潭溪十詠 懷新亭','劉子翬','宋','宋诗','song-poetry','','[]','茅簷入竹低，曠野時寓目。',36,'全唐诗/poet.song.111000.json','["茅簷入竹低，曠野時寓目。", "寂寂農家春，新秧滿田綠。", "何時稻登場，秋山響蓬樸。"]'),
('753f0855-aea5-47a4-a53e-b2d9b395a687','潭溪十詠 宴坐巖','劉子翬','宋','宋诗','song-poetry','','[]','青青榹樹林，下蔭蒼蘚石。',36,'全唐诗/poet.song.111000.json','["青青榹樹林，下蔭蒼蘚石。", "幽人宴坐時，懷抱忘其適。", "不見暮樵歸，寒山雨中碧。"]'),
('bcaca8a5-21e8-41e2-b4d6-027892a8e917','潭溪十詠 山館','劉子翬','宋','宋诗','song-poetry','','[]','春林繞舍青，門館終日靜。',36,'全唐诗/poet.song.111000.json','["春林繞舍青，門館終日靜。", "吾心樂有餘，所寓皆勝境。", "更鑿庭下池，溶溶浸山影。"]'),
('d9ae0fdc-e091-4273-b9c2-a74ef2fdc4f6','潭溪十詠 凉陰軒','劉子翬','宋','宋诗','song-poetry','','[]','北窗何所見，疏竹雜遥岑。',36,'全唐诗/poet.song.111000.json','["北窗何所見，疏竹雜遥岑。", "凉飆思有無，虛簷動蕭森。", "此興何由盡，移床入翠陰。"]'),
('b3ffafca-b015-4428-83e7-62f89964d9a9','潭溪十詠 橘林','劉子翬','宋','宋诗','song-poetry','','[]','木奴困新移，憔悴雪霜侵。',36,'全唐诗/poet.song.111000.json','["木奴困新移，憔悴雪霜侵。", "呼童翦其顛，割愛慮已深。", "會待春氣回，青枝補故林。"]'),
('cef1dac5-7df7-4f97-93f0-a88e2108708f','潭溪十詠 蓮池','劉子翬','宋','宋诗','song-poetry','','[]','蓮池一畝餘，瀰瀰吞衆流。',36,'全唐诗/poet.song.111000.json','["蓮池一畝餘，瀰瀰吞衆流。", "花繁不近堤，欲往無方舟。", "不及池中魚，隨波自沈浮。"]'),
('bc0113c1-1f79-4b66-9b88-e47252a0fbe8','潭溪十詠 南溪','劉子翬','宋','宋诗','song-poetry','','[]','聊爲溪上遊，一步一回顧。',36,'全唐诗/poet.song.111000.json','["聊爲溪上遊，一步一回顧。", "悠悠出山水，浩浩無停注。", "惟有舊溪聲，萬古流不去。"]'),
('273f93ee-eecd-4b58-82e3-612d45f52cdd','兼道携古墨來墨面龍紋墨背識云保大九年奉敕造長春殿供御龍印香煤旁又識云墨務官臣庭邽監官臣夷中臣子和臣卞等進蓋江南李氏物也感之爲作此詩','劉子翬','宋','宋诗','song-poetry','','[]','長春殿古生荆薈，猶有前朝遺物在。',192,'全唐诗/poet.song.111000.json','["長春殿古生荆薈，猶有前朝遺物在。", "錦囊珍重出玄圭，雙虬刻作蜿蜒態。", "枯皮剝製弄幾刓，斷玦精堅磨不殺。", "吾聞李氏據江左，文采風流高一代。", "當時好玩不獨此，器用往往窮奢汰。", "徵工選技填御府，不惜千金爲賞賚。", "治兵唐推英衛精，治民漢許龔黄最。", "惜哉取士不知術，妙手獨得庭邽輩。", "真主驅馳八極中，荒王逸樂孤城內。", "汗青得失更誰論，尤物競爲人寶愛。", "嗟余視此真糞土，事有至微猶足戒。", "投文欲往弔江流，幽魂未泯應慚悔。"]'),
('b0317258-e3b6-49a8-a412-c1adc20f6945','入開善','劉子翬','宋','宋诗','song-poetry','','[]','雙童肩竹輿，兀兀如乘舟。',132,'全唐诗/poet.song.111000.json','["雙童肩竹輿，兀兀如乘舟。", "及茲朝暑微，遠訪招提幽。", "蒼山望中橫，清泉脚底流。", "所歷已殊勝，况乃窮林丘。", "僧房在在凉，逢迎足茶甌。", "岸幘幽鳥鳴，橫琴素煙浮。", "倦借一榻眠，吾生復何求。", "薰風溪上來，虛簷散颼颼。", "開懷若傾倒，忽去不可留。", "人間苦炎熱，物外常清秋。", "功名非所期，聊尋赤松遊。"]'),
('95ddbe88-8572-41f2-b73a-578bd49782d0','寄茶與二劉','劉子翬','宋','宋诗','song-poetry','','[]','然松煮鼎山泉冽，槍旗一水分優劣。',72,'全唐诗/poet.song.111000.json','["然松煮鼎山泉冽，槍旗一水分優劣。", "鳳餠推開雪照人，花瓷啜罷甘潮舌。", "大劉談天紫髯張，小劉逃禪清興長。", "會須酌此同翱翔，或凌剛風九天上，或泛弱水三山傍。"]'),
('9e517360-3748-4619-b469-29e7928a2120','劉兼道獵','劉子翬','宋','宋诗','song-poetry','','[]','劉侯好獵親馳逐，指呼雙犬如奴僕。',64,'全唐诗/poet.song.111000.json','["劉侯好獵親馳逐，指呼雙犬如奴僕。", "朝衝唐石亂雲來，暮聽潭溪流水宿。", "何如著鞭走大梁，我亦與子同翱翔。", "今年獵叛醢彭越，明年獵胡羓德光。"]'),
('99658eaf-5961-418e-9348-6f13559df6d1','觀二劉題壁','劉子翬','宋','宋诗','song-poetry','','[]','溫其題詩新歷寺，落筆風雨驚長林。',128,'全唐诗/poet.song.111000.json','["溫其題詩新歷寺，落筆風雨驚長林。", "眼高一世常欲駡，想見掀髯坐巖陰。", "致中題詩新興寺，壞壁歲久莓苔侵。", "山僧好事亦可喜，解誦鳥啼春意深。", "我來經覽渾如昨，玉友金昆念離索。", "投林倦翼不同栖，况復分飛在寥廓。", "故山終勝他山好，新交不如舊交樂。", "何况把酒問鷗盟，卧聽松風同一壑。"]'),
('2ae25f88-1bc1-44c0-931f-c55407b27d51','入白水訪劉致中昆仲','劉子翬','宋','宋诗','song-poetry','','[]','夜雨歇清曉，山椒雲氣昏。',168,'全唐诗/poet.song.111000.json','["夜雨歇清曉，山椒雲氣昏。", "駕言聊出遊，窈窕窮川原。", "側帽避橫篠，揚袪障晴暾。", "春泉散石壁，細草羅丘園。", "陟峻已逾嶺，窺深更緣源。", "喬松傍澗折，垂柯激潺湲。", "過籟寒慘慘，驚林白翻翻。", "造幽景寥閴，勝絕難具論。", "僕夫知余樂，踟躕爲停軒。", "惜無徙倚地，時來此開樽。", "暮投鵝峯宿，青燈耿柴門。", "相從二三子，交情久彌敦。", "談玄測彖象，攬佩紉蘭蓀。", "願言固所懷，丘壑吾道尊。"]'),
('b8d4bffd-a07e-4810-8337-f93ef9d14793','携筇','劉子翬','宋','宋诗','song-poetry','','[]','晨起偶無事，携筇出潭川。',132,'全唐诗/poet.song.111000.json','["晨起偶無事，携筇出潭川。", "翩翩雙鳬飛，宛若導我前。", "林靜滴殘雨，村深澹寒烟。", "當春足膏澤，俯夏餘清妍。", "野溜綠交貫，山花紅接連。", "雄觀發新奇，勝地窮攀緣。", "據石弄驚急，班荆蔭連卷。", "幽懷脫塵拘，如超混芒先。", "向令作興來，未必勝偶然。", "榮觀事多乖，內取樂乃全。", "他時誰繼遊，此意遥相傳。"]'),
('4d434e27-a9e8-4a71-a887-5a464d014561','續賦家園七詠 早賦堂','劉子翬','宋','宋诗','song-poetry','','[]','南溪抱山流，潤氣滋林麓。',36,'全唐诗/poet.song.111000.json','["南溪抱山流，潤氣滋林麓。", "平生歸歟心，寄老一堂足。", "夢破午窗陰，清風在寒竹。"]'),
('5f611b64-6996-4ac1-b1ca-ed2e7c6d0056','續賦家園七詠 橫秋閣','劉子翬','宋','宋诗','song-poetry','','[]','秋山萬尺青，影落杯酒中。',36,'全唐诗/poet.song.111000.json','["秋山萬尺青，影落杯酒中。", "登臨豈不佳，寒色見遠空。", "未忘天下憂，胡塵起西風。"]'),
('dcda369b-d6f3-462f-af3b-1df521e5868f','續賦家園七詠 萬石亭','劉子翬','宋','宋诗','song-poetry','','[]','嵐光近却無，一徑緣崖斷。',36,'全唐诗/poet.song.111000.json','["嵐光近却無，一徑緣崖斷。", "危亭勢欲飛，翠石雲中亂。", "小山閟清遊，懷人發長歎。"]'),
('224aba20-b3f1-40bc-b80e-69ffcef38188','續賦家園七詠 桂巖','劉子翬','宋','宋诗','song-poetry','','[]','山中多桂樹，亭亭傍幽巖。',36,'全唐诗/poet.song.111000.json','["山中多桂樹，亭亭傍幽巖。", "微風發秋香，十里穿松杉。", "誰歌招隠詞，吾生付長鑱。"]'),
('144c0036-e86f-4fbe-9a27-c4fad1c8ad1e','續賦家園七詠 百花臺','劉子翬','宋','宋诗','song-poetry','','[]','森沈徑易迷，搘筇爲徘徊。',36,'全唐诗/poet.song.111000.json','["森沈徑易迷，搘筇爲徘徊。", "何處春光多，時登百花臺。", "主人澹無情，林花爲誰開。"]'),
('d1542330-d6a1-4c51-8aec-e693c9fcf5b9','續賦家園七詠 酴醿洞','劉子翬','宋','宋诗','song-poetry','','[]','不愛酴醿花，愛此酴醿樹。',36,'全唐诗/poet.song.111000.json','["不愛酴醿花，愛此酴醿樹。", "青條含露滋，輕陰覆行路。", "晝永倦尋書，時來散幽步。"]'),
('53c076ca-4ebb-44a6-8a3b-014105060d0b','續賦家園七詠 意遠亭','劉子翬','宋','宋诗','song-poetry','','[]','雨餘陂水平，徙倚聊一望。',36,'全唐诗/poet.song.111000.json','["雨餘陂水平，徙倚聊一望。", "歸雲淡欲無，宇宙何清曠。", "吾心游太虛，聊寄此亭上。"]'),
('46842729-740d-4a4b-98c4-b3422620ef82','題靈鷲窗','劉子翬','宋','宋诗','song-poetry','','[]','翠合初疑無路往，停鞭邂逅成清賞。',32,'全唐诗/poet.song.111000.json','["翠合初疑無路往，停鞭邂逅成清賞。", "僧爐坐穩紙窗明，細雨忽來山竹響。"]');
